import{_ as e,c as a,o as m,b as t}from"./app.6039188d.js";const u='{"title":"\u041F\u0430\u0440\u0430\u043C\u0430\u0440\u0442\u0445\u0430\u0441\u0430\u0440\u0430","description":"","frontmatter":{"title":"\u041F\u0430\u0440\u0430\u043C\u0430\u0440\u0442\u0445\u0430\u0441\u0430\u0440\u0430","subtitle":"\u0421\u0443\u0442\u044C \u0412\u044B\u0441\u0448\u0435\u0439 \u0418\u0441\u0442\u0438\u043D\u044B","sans":"\u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0938\u093E\u0930","trans":"Param\u0101rthas\u0101ra","tags":"text","eng":"Paramarthasara","date":"2021-05-05T00:00:00.000Z"},"headers":[{"level":2,"title":"\u0410\u0431\u0445\u0438\u043D\u0430\u0432\u0430\u0433\u0443\u043F\u0442\u0430","slug":"\u0430\u0431\u0445\u0438\u043D\u0430\u0432\u0430\u0433\u0443\u043F\u0442\u0430"}],"relativePath":"texts/paramarthasara/index.md"}',s={},i=t('<h2 id="\u0430\u0431\u0445\u0438\u043D\u0430\u0432\u0430\u0433\u0443\u043F\u0442\u0430" tabindex="-1">\u0410\u0431\u0445\u0438\u043D\u0430\u0432\u0430\u0433\u0443\u043F\u0442\u0430 <a class="header-anchor" href="#\u0430\u0431\u0445\u0438\u043D\u0430\u0432\u0430\u0433\u0443\u043F\u0442\u0430" aria-hidden="true">#</a></h2><p>\u041F\u0435\u0440\u0435\u0432\u043E\u0434 \u043D\u0430 \u0440\u0443\u0441\u0441\u043A\u0438\u0439 \u044F\u0437\u044B\u043A \u043D\u0430 \u043E\u0441\u043D\u043E\u0432\u0435 <a href="http://www.sanskrit-sanscrito.com/en/abhinavagupta-s-paramarthasara-trika-scriptures-non-dual-shaivism-of-kashmir/616" class="external-link" target="_blank" rel="noopener noreferrer">\u043F\u043E\u0441\u043B\u043E\u0432\u043D\u043E\u0433\u043E \u0430\u043D\u0433\u043B\u0438\u0439\u0441\u043A\u043E\u0433\u043E \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0430 \u0441 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0430 \u0413\u0443\u0440\u0443 \u0413\u0430\u0431\u0440\u0438\u0435\u043B\u044F \u041F\u0440\u0430\u0434\u0438\u0438\u043F\u0430\u043A\u0438</a></p><div class="stanza"><a href="#s1" id="s1" class="num">1</a><p class="sans">\u092A\u0930\u0902 \u092A\u0930\u0938\u094D\u0925\u0902 \u0917\u0939\u0928\u093E\u0926\u0928\u093E\u0926\u093F\u092E\u0947\u0915\u0902 \u0928\u093F\u0935\u093F\u0937\u094D\u091F\u0902 \u092C\u0939\u0941\u0927\u093E \u0917\u0941\u0939\u093E\u0938\u0941 \u0964<br> \u0938\u0930\u094D\u0935\u093E\u0932\u092F\u0902 \u0938\u0930\u094D\u0935\u091A\u0930\u093E\u091A\u0930\u0938\u094D\u0925\u0902 \u0924\u094D\u0935\u093E\u092E\u0947\u0935 \u0936\u092E\u094D\u092D\u0941\u0902 \u0936\u0930\u0923\u0902 \u092A\u094D\u0930\u092A\u0926\u094D\u092F\u0947 \u0965\u0967\u0965</p><p class="trans">Para\u1E41 parastha\u1E41 gahan\u0101dan\u0101dimeka\u1E41 nivi\u1E63\u1E6Da\u1E41 bahudh\u0101 guh\u0101su \u0964<br> Sarv\u0101laya\u1E41 sarvacar\u0101carastha\u1E41 tv\u0101meva \u015Bambhu\u1E41 \u015Bara\u1E47a\u1E41 prapadye \u09651\u0965</p><p>\u0418\u0449\u0443 \u043F\u0440\u0438\u0431\u0435\u0436\u0438\u0449\u0430 <em>(\u015Bara\u1E47am prapadye)</em> \u0432 \u0428\u0430\u043C\u0431\u0445\u0443 <em>(\u015Bambhum)</em>, \u0432 \u0442\u0435\u0431\u0435 <em>(tv\u0101m)</em> \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C <em>(eva)</em> \u0412\u044B\u0441\u0448\u0435\u043C <em>(param)</em>, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u043C <em>(stham)</em> \u043F\u043E \u0442\u0443 \u0441\u0442\u043E\u0440\u043E\u043D\u0443 <em>(para)</em> \u043D\u0435\u043F\u0440\u043E\u043D\u0438\u0446\u0430\u0435\u043C\u043E\u0439 \u0442\u044C\u043C\u044B <em>(gahan\u0101t)</em>, \u0411\u0435\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u043C <em>(an\u0101dim)</em> \u0415\u0434\u0438\u043D\u0441\u0442\u0432\u0435 <em>(ekam)</em>, \u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u044E\u0449\u0435\u043C <em>(nivi\u1E63\u1E6Dam)</em> \u0441\u0435\u0440\u0434\u0446\u0430 <em>(guh\u0101su)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(bahudh\u0101)</em>, \u043A\u0442\u043E \u0435\u0441\u0442\u044C \u043C\u0435\u0441\u0442\u043E\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 <em>(\u0101laya)</em> \u0432\u0441\u0435\u0433\u043E <em>(sarva)</em> \u0438 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(stham)</em> \u0432\u043E \u0432\u0441\u0435\u0439 \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u0438 \u0441\u0443\u0449\u0435\u0433\u043E, \u043A\u0430\u043A \u043E\u0434\u0443\u0448\u0435\u0432\u043B\u0451\u043D\u043D\u043E\u0433\u043E, \u0442\u0430\u043A \u0438 \u043D\u0435\u043E\u0434\u0443\u0448\u0435\u0432\u043B\u0451\u043D\u043D\u043E\u0433\u043E <em>(sarva-cara-acara)</em>!</p><p class="eng">I take refuge <em>(\u015Bara\u1E47am prapadye)</em> in \u015Aambhu <em>(\u015Bambhum)</em>, in You <em>(tv\u0101m)</em> alone <em>(eva)</em> who are Supreme <em>(param)</em>, who reside <em>(stham)</em> beyond <em>(para)</em> the impenetrable darkness [known as M\u0101y\u0101] <em>(gahan\u0101t)</em>, who are One <em>(ekam)</em> with no beginning <em>(an\u0101dim)</em>, who stay <em>(nivi\u1E63\u1E6Dam)</em> in the hearts <em>(guh\u0101su)</em> in many ways <em>(bahudh\u0101)</em>, who are the Abode <em>(\u0101laya)</em> of all <em>(sarva)</em> [and] who exist <em>(stham)</em> in the whole aggregate of created things whether animate or inanimate <em>(sarva-cara-acara)</em>!</p></div><div class="stanza"><a href="#s2" id="s2" class="num">2</a><p class="sans">\u0917\u0930\u094D\u092D\u093E\u0927\u093F\u0935\u093E\u0938\u092A\u0942\u0930\u094D\u0935\u0915\u092E\u0930\u0923\u093E\u0928\u094D\u0924\u0915\u0926\u0941\u0903\u0916\u091A\u0915\u094D\u0930\u0935\u093F\u092D\u094D\u0930\u093E\u0928\u094D\u0924\u0903 \u0964<br> \u0906\u0927\u093E\u0930\u0902 \u092D\u0917\u0935\u0928\u094D\u0924\u0902 \u0936\u093F\u0937\u094D\u092F\u0903 \u092A\u092A\u094D\u0930\u091A\u094D\u091B \u092A\u0930\u092E\u093E\u0930\u094D\u0925\u092E\u094D \u0965\u0968\u0965</p><p class="trans">Garbh\u0101dhiv\u0101sap\u016Brvakamara\u1E47\u0101ntakadu\u1E25khacakravibhr\u0101nta\u1E25 \u0964<br> \u0100dh\u0101ra\u1E41 bhagavanta\u1E41 \u015Bi\u1E63ya\u1E25 papraccha param\u0101rtham \u09652\u0965</p><p>\u041E\u0437\u0430\u0434\u0430\u0447\u0435\u043D\u043D\u044B\u0439 <em>(vibhr\u0101nta\u1E25)</em> \u0446\u0438\u043A\u043B\u043E\u043C <em>(cakra)</em> \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0439 <em>(du\u1E25kha)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0449\u0438\u043C\u0441\u044F c <em>(p\u016Brvaka)</em> \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u044F <em>(adhiv\u0101sa)</em> \u0432 \u0443\u0442\u0440\u043E\u0431\u0435 <em>(garbha)</em> [\u0438] \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044E\u0449\u0438\u043C\u0441\u044F <em>(antaka)</em> \u0441\u043C\u0435\u0440\u0442\u044C\u044E [\u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0442\u0435\u043B\u0430] <em>(mara\u1E47a)</em>, \u0443\u0447\u0435\u043D\u0438\u043A <em>(\u015Bi\u1E63ya\u1E25)</em> \u0441\u043F\u0440\u043E\u0441\u0438\u043B <em>(papraccha)</em> \u0437\u043D\u0430\u043C\u0435\u043D\u0438\u0442\u043E\u0433\u043E <em>(bhagavantam)</em> \u0410\u0434\u0445\u0430\u0440\u0443 <em>(\u0101dh\u0101ram)</em> \u043E \u0412\u0435\u0440\u0445\u043E\u0432\u043D\u043E\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(parama-artham)</em>.</p><p class="eng">Bewildered <em>(vibhr\u0101nta\u1E25)</em> by the wheel <em>(cakra)</em> of pain <em>(du\u1E25kha)</em> beginning with <em>(p\u016Brvaka)</em> his dwelling <em>(adhiv\u0101sa)</em> in the womb <em>(garbha)</em> [and] ending in <em>(antaka)</em> death [of the physical body] <em>(mara\u1E47a)</em>, a disciple <em>(\u015Bi\u1E63ya\u1E25)</em> asked _(papraccha)_illustrious <em>(bhagavantam)</em> \u0100dh\u0101ra \u2013also known as \u0100di\u015Be\u1E63a\u2013 <em>(\u0101dh\u0101ram)</em>about the Highest Reality \u2013or Supreme Goal\u2013 _(parama-artham)_</p></div><div class="stanza"><a href="#s3" id="s3" class="num">3</a><p class="sans">\u0906\u0927\u093E\u0930\u0915\u093E\u0930\u093F\u0915\u093E\u092D\u093F\u0938\u094D\u0924\u0902 \u0917\u0941\u0930\u0941\u0930\u092D\u093F\u092D\u093E\u0937\u0924\u0947 \u0938\u094D\u092E \u0924\u0924\u094D\u0938\u093E\u0930\u092E\u094D \u0964<br> \u0915\u0925\u092F\u0924\u094D\u092F\u092D\u093F\u0928\u0935\u0917\u0941\u092A\u094D\u0924\u0903 \u0936\u093F\u0935\u0936\u093E\u0938\u0928\u0926\u0943\u0937\u094D\u091F\u093F\u092F\u094B\u0917\u0947\u0928 \u0965\u0969\u0965</p><p class="trans">\u0100dh\u0101rak\u0101rik\u0101bhista\u1E41 gururabhibh\u0101\u1E63ate sma tats\u0101ram \u0964<br> Kathayatyabhinavagupta\u1E25 \u015Biva\u015B\u0101sanad\u1E5B\u1E63\u1E6Diyogena \u09653\u0965</p><p>\u0413\u0443\u0440\u0443 <em>(guru\u1E25)</em> \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u043B <em>(abhibh\u0101\u1E63ate sma)</em> \u0435\u043C\u0443 <em>(tam)</em> \u0441\u0443\u0442\u044C <em>(s\u0101ram)</em> \u044D\u0442\u043E\u0433\u043E <em>(tad)</em> \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u0100dh\u0101rak\u0101rik\u0101-s \u2013\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u0432 \u0410\u0434\u0445\u0430\u0440\u044B, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u0442\u0430\u043B\u0438 \u0432 \u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0438 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B \u043A\u0430\u043A Param\u0101rthas\u0101ra, \u0421\u0443\u0442\u044C \u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438\u2013 <em>(\u0101dh\u0101ra-k\u0101rik\u0101bhi\u1E25)</em>. \u0410\u0431\u0445\u0438\u043D\u0430\u0432\u0430\u0433\u0443\u043F\u0442\u0430 <em>(abhinavagupta\u1E25)</em> \u043F\u0435\u0440\u0435\u0434\u0430\u0451\u0442 <em>(kathayati)</em> [\u044D\u0442\u0438 \u0436\u0435 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u044B \u0432 \u0441\u043B\u0435\u0433\u043A\u0430 \u0438\u0437\u043C\u0435\u043D\u0451\u043D\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435] \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 <em>(yogena)</em> \u0442\u043E\u0447\u043A\u043E\u0439 \u0437\u0440\u0435\u043D\u0438\u044F <em>(d\u1E5B\u1E63\u1E6Di)</em> \u0434\u043E\u043A\u0442\u0440\u0438\u043D\u044B <em>(\u015B\u0101sana)</em> \u0428\u0438\u0432\u044B <em>(\u015Biva)</em>.</p><p class="eng">The Guru \u2013\u0100dh\u0101ra\u2013 <em>(guru\u1E25)</em> spoke <em>(abhibh\u0101\u1E63ate sma)</em> to him \u2013to that disciple\u2013 <em>(tam)</em> about the essence <em>(s\u0101ram)</em> of that [Highest Reality] \u2013or \u201Cof that teaching dealing with the Highest Reality\u201D\u2013 <em>(tad)</em> by means of \u0100dh\u0101rak\u0101rik\u0101-s \u2013The aphorisms of \u0100dh\u0101ra, which were finally known as Param\u0101rthas\u0101ra, Essence of the Highest Reality\u2013 <em>(\u0101dh\u0101ra-k\u0101rik\u0101bhi\u1E25)</em>. Abhinavagupta <em>(abhinavagupta\u1E25)</em> speaks <em>(kathayati)</em> [the same aphorisms but duly reformed] according to <em>(yogena)</em> the viewpoint <em>(d\u1E5B\u1E63\u1E6Di)</em> of \u015Aiva\u2019s <em>(\u015Biva)</em> doctrine <em>(\u015B\u0101sana)</em></p><blockquote><p>\u0410\u0434\u0445\u0430\u0440\u0430 \u2013 \u0438\u043C\u044F \u043C\u0443\u0434\u0440\u0435\u0446\u0430, \u0430\u0432\u0442\u043E\u0440\u0430 \u0410\u0434\u0445\u0430\u0440\u0430\u043A\u0430\u0440\u0438\u043A\u0438.</p></blockquote></div><div class="stanza"><a href="#s4" id="s4" class="num">4</a><p class="sans">\u0928\u093F\u091C\u0936\u0915\u094D\u0924\u093F\u0935\u0948\u092D\u0935\u092D\u0930\u093E\u0926\u0923\u094D\u0921\u091A\u0924\u0941\u0937\u094D\u091F\u092F\u092E\u093F\u0926\u0902 \u0935\u093F\u092D\u093E\u0917\u0947\u0928 \u0964<br> \u0936\u0915\u094D\u0924\u093F\u0930\u094D\u092E\u093E\u092F\u093E \u092A\u094D\u0930\u0915\u0943\u0924\u093F\u0903 \u092A\u0943\u0925\u094D\u0935\u0940 \u091A\u0947\u0924\u093F \u092A\u094D\u0930\u092D\u093E\u0935\u093F\u0924\u0902 \u092A\u094D\u0930\u092D\u0941\u0923\u093E \u0965\u096A\u0965</p><p class="trans">Nija\u015Baktivaibhavabhar\u0101da\u1E47\u1E0Dacatu\u1E63\u1E6Dayamida\u1E41 vibh\u0101gena \u0964<br> \u015Aaktirm\u0101y\u0101 prak\u1E5Bti\u1E25 p\u1E5Bthv\u012B ceti prabh\u0101vita\u1E41 prabhu\u1E47\u0101 \u09654\u0965</p><p>\u041F\u0435\u0440\u0435\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0439 <em>(bhar\u0101t)</em> \u0412\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u0438\u0435\u043C <em>(vaibhava)</em> \u0415\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(nija)</em> \u0421\u0438\u043B\u044B <em>(\u015Bakti)</em>, \u0413\u043E\u0441\u043F\u043E\u0434\u044C <em>(prabhu\u1E47\u0101)</em> \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u0435\u0442 <em>(prabh\u0101vitam)</em> \u044D\u0442\u0443 <em>(idam)</em> \u0447\u0435\u0442\u0432\u0451\u0440\u043A\u0443 <em>(catu\u1E63\u1E6Dayam)</em> \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u0445 <em>(vibh\u0101gena)</em> \u0441\u0444\u0435\u0440 <em>(a\u1E47\u1E0Da)</em>: \u0428\u0430\u043A\u0442\u0438 <em>(\u015Bakti\u1E25)</em>, \u041C\u0430\u0439\u044F <em>(m\u0101y\u0101)</em>, \u041F\u0440\u0430\u043A\u0440\u0438\u0442\u0438 <em>(prak\u1E5Bti\u1E25)</em> \u0438 <em>(ca)</em> \u041F\u0440\u0438\u0442\u0445\u0432\u0438 <em>(p\u1E5Bthv\u012B\u2026 iti).</em></p><p class="eng">Because of the abundance <em>(bhar\u0101t)</em> of Glory and Magnificence <em>(vaibhava)</em> [present] in His own <em>(nija)</em> Power <em>(\u015Bakti)</em>, this <em>(idam)</em> group offour <em>(catu\u1E63\u1E6Dayam)</em> eggs <em>(a\u1E47\u1E0Da)</em> [is] separately <em>(vibh\u0101gena)</em> manifested <em>(prabh\u0101vitam)</em> by the Lord <em>(prabhu\u1E47\u0101)</em>: \u201C\u015Aakti <em>(\u015Bakti\u1E25)</em>, M\u0101y\u0101 <em>(m\u0101y\u0101)</em>, Prak\u1E5Bti <em>(prak\u1E5Bti\u1E25)</em> and <em>(ca)</em> P\u1E5Bthv\u012B <em>(p\u1E5Bthv\u012B\u2026 iti)</em>.</p></div><div class="stanza"><a href="#s5" id="s5" class="num">5</a><p class="sans">\u0924\u0924\u094D\u0930\u093E\u0928\u094D\u0924\u0930\u094D\u0935\u093F\u0936\u094D\u0935\u092E\u093F\u0926\u0902 \u0935\u093F\u091A\u093F\u0924\u094D\u0930\u0924\u0928\u0941\u0915\u0930\u0923\u092D\u0941\u0935\u0928\u0938\u0928\u094D\u0924\u093E\u0928\u092E\u094D \u0964<br> \u092D\u094B\u0915\u094D\u0924\u093E \u091A \u0924\u0924\u094D\u0930 \u0926\u0947\u0939\u0940 \u0936\u093F\u0935 \u090F\u0935 \u0917\u0943\u0939\u0940\u0924\u092A\u0936\u0941\u092D\u093E\u0935\u0903 \u0965\u096B\u0965</p><p class="trans">Tatr\u0101ntarvi\u015Bvamida\u1E41 vicitratanukara\u1E47abhuvanasant\u0101nam \u0964<br> Bhokt\u0101 ca tatra deh\u012B \u015Biva eva g\u1E5Bh\u012Btapa\u015Bubh\u0101va\u1E25 \u09655\u0965</p><p>\u0422\u0430\u043C <em>(tatra)</em> \u0432\u043D\u0443\u0442\u0440\u0438 <em>(antar)</em> \u044D\u0442\u0430 <em>(idam)</em> \u0412\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(vi\u015Bvam)</em> \u2013 \u043C\u043D\u043E\u0433\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u044B\u0439 <em>(vicitra)</em> \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u044B\u0439 \u043F\u043E\u0442\u043E\u043A <em>(sant\u0101nam)</em> \u043C\u0438\u0440\u043E\u0432 <em>(bhuvana)</em>, \u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432 <em>(kara\u1E47a)</em> [\u0438] \u0442\u0435\u043B <em>(tanu)</em>. \u0418 <em>(ca)</em> \u0442\u0430\u043C <em>(tatra)</em> \u0432\u043E\u043F\u043B\u043E\u0449\u0451\u043D\u043D\u044B\u0439 \u0432 \u0442\u0435\u043B\u0435 <em>(deh\u012B)</em> \u0412\u043A\u0443\u0448\u0430\u044E\u0449\u0438\u0439 <em>(bhokt\u0101)</em> \u2014 \u0441\u0430\u043C <em>(eva)</em> \u0428\u0438\u0432\u0430 <em>(\u015Biva\u1E25)</em>, \u043F\u0440\u0438\u043D\u044F\u0432\u0448\u0438\u0439 <em>(g\u1E5Bh\u012Bta)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(bh\u0101va\u1E25)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 <em>(pa\u015Bu)</em>.</p><p class="eng">In <em>(antar)</em> there <em>(tatra)</em> \u2013in the group of four eggs\u2013, this <em>(idam)</em> universe <em>(vi\u015Bvam)</em>, which is a manifold _(vicitra)_continuous flow <em>(sant\u0101nam)</em> of worlds <em>(bhuvana)</em>, sense organs <em>(kara\u1E47a)</em> [and] bodies <em>(tanu)</em>, [exists]. And <em>(ca)</em> in that \u2013in the universe\u2013 <em>(tatra)</em>, \u015Aiva <em>(\u015Biva\u1E25)</em> alone <em>(eva)</em>, having assumed <em>(g\u1E5Bh\u012Bta)</em> the state <em>(bh\u0101va\u1E25)</em> of a limited individual \u2013lit. animal, beast\u2013 <em>(pa\u015Bu)</em> [in the form of] an embodied being <em>(deh\u012B)</em>, [is] the Enjoyer _(bhokt\u0101)_</p></div><div class="stanza"><a href="#s6" id="s6" class="num">6</a><p class="sans">\u0924\u0924\u094D\u0928\u093E\u0928\u093E\u0935\u093F\u0927\u0935\u0930\u094D\u0923\u093E\u0928\u093E\u0902 \u0930\u0942\u092A\u0902 \u0927\u0924\u094D\u0924\u0947 \u092F\u0925\u093E\u092E\u0932\u0903 \u0938\u094D\u092B\u091F\u093F\u0915\u0903 \u0964<br> \u0938\u0941\u0930\u092E\u093E\u0928\u0941\u0937\u092A\u0936\u0941\u092A\u093E\u0926\u092A\u0930\u0942\u092A\u0924\u094D\u0935\u0902 \u0924\u0926\u094D\u0935\u0926\u0940\u0936\u094B\u093D\u092A\u093F \u0965\u096C\u0965</p><p class="trans">N\u0101n\u0101vidhavar\u1E47\u0101n\u0101\u1E41 r\u016Bpa\u1E41 dhatte yath\u0101mala\u1E25 spha\u1E6Dika\u1E25 \u0964<br> Suram\u0101nu\u1E63apa\u015Bup\u0101dapar\u016Bpatva\u1E41 tadvad\u012B\u015Bo\u2019pi \u09656\u0965</p><p>\u041A\u0430\u043A <em>(yath\u0101)</em> \u0447\u0438\u0441\u0442\u044B\u0439 <em>(amala\u1E25)</em> \u043A\u0440\u0438\u0441\u0442\u0430\u043B <em>(spha\u1E6Dika\u1E25)</em> \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 <em>(dhatte)</em> \u0440\u0430\u0437\u043D\u043E\u0446\u0432\u0435\u0442\u043D\u044B\u0435 <em>(n\u0101n\u0101vidha-var\u1E47\u0101n\u0101m)</em> \u0444\u043E\u0440\u043C\u044B <em>(r\u016Bpam)</em>, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443 <em>(tad-vat)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u044C <em>(\u012B\u015Ba\u1E25)</em> \u0442\u0430\u043A\u0436\u0435 <em>(api)</em> [\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442] \u0444\u043E\u0440\u043C\u044B <em>(r\u016Bpatvam)</em> \u0431\u043E\u0433\u043E\u0432 <em>(sura)</em>, \u043B\u044E\u0434\u0435\u0439 <em>(m\u0101nu\u1E63a)</em>, \u0436\u0438\u0432\u043E\u0442\u043D\u044B\u0445 <em>(pa\u015Bu)</em> [\u0438] \u0440\u0430\u0441\u0442\u0435\u043D\u0438\u0439 <em>(p\u0101dapa)</em>.</p><p class="eng">Just as <em>(yath\u0101)</em> a pure <em>(amala\u1E25)</em> crystal <em>(spha\u1E6Dika\u1E25)</em> assumes <em>(dhatte)</em> a form or aspect <em>(r\u016Bpam)</em> containing various colors <em>(n\u0101n\u0101vidha-var\u1E47\u0101n\u0101m)</em>, even so <em>(tad-vat)</em> the Lord <em>(\u012B\u015Ba\u1E25)</em> also <em>(api)</em> [assumes] the form or aspect <em>(r\u016Bpatvam)</em> of gods <em>(sura)</em>, human beings <em>(m\u0101nu\u1E63a)</em>, animals <em>(pa\u015Bu)</em> [and] trees <em>(p\u0101dapa)</em></p></div><div class="stanza"><a href="#s7" id="s7" class="num">7</a><p class="sans">\u0917\u091A\u094D\u091B\u0924\u093F \u0917\u091A\u094D\u091B\u0924\u093F \u091C\u0932 \u0907\u0935 \u0939\u093F\u092E\u0915\u0930\u092C\u093F\u092E\u094D\u092C\u0902 \u0938\u094D\u0925\u093F\u0924\u0947 \u0938\u094D\u0925\u093F\u0924\u093F\u0902 \u092F\u093E\u0924\u093F \u0964<br> \u0924\u0928\u0941\u0915\u0930\u0923\u092D\u0941\u0935\u0928\u0935\u0930\u094D\u0917\u0947 \u0924\u0925\u093E\u093D\u092F\u092E\u093E\u0924\u094D\u092E\u093E \u092E\u0939\u0947\u0936\u093E\u0928\u0903 \u0965\u096D\u0965</p><p class="trans">Gacchati gacchati jala iva himakarabimba\u1E41 sthite sthiti\u1E41 y\u0101ti \u0964<br> Tanukara\u1E47abhuvanavarge tath\u0101\u2019yam\u0101tm\u0101 mahe\u015B\u0101na\u1E25 \u09657\u0965</p><p>\u041A\u0430\u043A <em>(iva)</em> \u043E\u0442\u0440\u0430\u0436\u0435\u043D\u0438\u0435 <em>(bimbam)</em> \u041B\u0443\u043D\u044B <em>(himakara)</em> \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044F <em>(gacchati)</em> \u0432 \u0441\u0442\u0440\u0443\u044F\u0449\u0435\u0439\u0441\u044F \u0432\u043E\u0434\u0435 <em>(gacchati jale)</em> [\u0438] \u043F\u043E\u043A\u043E\u0438\u0442\u0441\u044F <em>(sthitim y\u0101ti)</em> \u0432 \u0441\u0442\u043E\u044F\u0447\u0435\u0439 <em>(sthite)</em>, \u0442\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em> \u044D\u0442\u043E <em>(ayam)</em> \xAB\u042F\xBB <em>(\u0101tm\u0101)</em>, \u0412\u0435\u043B\u0438\u043A\u0438\u0439 <em>(mah\u0101)</em> \u0412\u043B\u0430\u0434\u044B\u043A\u0430 <em>(\u012B\u015B\u0101na\u1E25)</em>, [\u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0432\u043E \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435 <em>(varge)</em> \u0442\u0435\u043B <em>(tanu)</em>, \u043E\u0440\u0433\u0430\u043D\u043E\u0432 <em>(kara\u1E47a)</em> [\u0438] \u043C\u0438\u0440\u043E\u0432 <em>(bhuvana)</em>.</p><p class="eng">Just as <em>(iva)</em> the image <em>(bimbam)</em> of the moon <em>(himakara)</em> moves <em>(gacchati)</em> in flowing water <em>(gacchati jale)</em> [and] does not move <em>(sthitim y\u0101ti)</em> in still [water] <em>(sthite)</em>, even so <em>(tath\u0101)</em> this <em>(ayam)</em> Self <em>(\u0101tm\u0101)</em>, the Great <em>(mah\u0101)</em> Master <em>(\u012B\u015B\u0101na\u1E25)</em>, [behaves] as regards the group <em>(varge)</em> [composed] of body <em>(tanu)</em>, senses <em>(kara\u1E47a)</em> [and] worlds <em>(bhuvana)</em></p></div><div class="stanza"><a href="#s8" id="s8" class="num">8</a><p class="sans">\u0930\u093E\u0939\u0941\u0930\u0926\u0943\u0936\u094D\u092F\u094B\u093D\u092A\u093F \u092F\u0925\u093E \u0936\u0936\u093F\u092C\u093F\u092E\u094D\u092C\u0938\u094D\u0925\u0903 \u092A\u094D\u0930\u0915\u093E\u0936\u0924\u0947 \u0924\u0926\u094D\u0935\u0924\u094D \u0964<br> \u0938\u0930\u094D\u0935\u0917\u0924\u094B\u093D\u092A\u094D\u092F\u092F\u092E\u093E\u0924\u094D\u092E\u093E \u0935\u093F\u0937\u092F\u093E\u0936\u094D\u0930\u092F\u0923\u0947\u0928 \u0927\u0940\u092E\u0941\u0915\u0941\u0930\u0947 \u0965\u096E\u0965</p><p class="trans">R\u0101hurad\u1E5B\u015Byo\u2019pi yath\u0101 \u015Ba\u015Bibimbastha\u1E25 prak\u0101\u015Bate tadvat \u0964<br> Sarvagato\u2019pyayam\u0101tm\u0101 vi\u1E63ay\u0101\u015Braya\u1E47ena dh\u012Bmukure \u09658\u0965</p><p>\u0418 <em>(api)</em> \u043A\u0430\u043A <em>(yath\u0101)</em> \u043D\u0435\u0432\u0438\u0434\u0438\u043C\u0430\u044F <em>(ad\u1E5B\u015Bya\u1E25)</em> \u0442\u0435\u043D\u044C \u0417\u0435\u043C\u043B\u0438 <em>(\u0420\u0430\u0445\u0443)</em> <em>(r\u0101hu\u1E25)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0432\u0438\u0434\u0438\u043C\u043E\u0439 <em>(prak\u0101\u015Bate)</em> \u043A\u043E\u0433\u0434\u0430 \u043F\u0430\u0434\u0430\u0435\u0442 <em>(stha\u1E25)</em> \u043D\u0430 \u0434\u0438\u0441\u043A <em>(bimba)</em> \u043B\u0443\u043D\u044B <em>(\u015Ba\u015Bi)</em>, \u0442\u0430\u043A\u0436\u0435 <em>(tad-vat\u2026 api)</em> \u044D\u0442\u043E <em>(ayam)</em> \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0435 <em>(sarva-gata\u1E25)</em> \xAB\u042F\xBB <em>(\u0101tm\u0101)</em>, \u043E\u0431\u0440\u0430\u0449\u0430\u044F\u0441\u044C <em>(\u0101\u015Braya\u1E47ena)</em> \u043A \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C \u0447\u0443\u0432\u0441\u0442\u0432 <em>(vi\u1E63aya)</em>, [\u0432\u0438\u0434\u0438\u0442\u0441\u044F] \u0432 \u0437\u0435\u0440\u043A\u0430\u043B\u0435 <em>(mukure)</em> \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430 <em>(dh\u012B)</em>.</p><p class="eng">Just as <em>(yath\u0101)</em> even <em>(api)</em> the invisible <em>(ad\u1E5B\u015Bya\u1E25)</em> shadow of the earth <em>(r\u0101hu\u1E25)</em> becomes visible <em>(prak\u0101\u015Bate)</em> when remains <em>(stha\u1E25)</em> on the disc <em>(bimba)</em> of the moon <em>(\u015Ba\u015Bi)</em>, even so <em>(tad-vat\u2026 api)</em> this <em>(ayam)</em> omnipresent <em>(sarva-gata\u1E25)</em> Self <em>(\u0101tm\u0101)</em> [becomes perceptible] when [reflected] in the mirror <em>(mukure)</em> of the intellect <em>(dh\u012B)</em> by resorting to <em>(\u0101\u015Braya\u1E47ena)</em> the sense objects <em>(vi\u1E63aya)</em></p></div><div class="stanza"><a href="#s9" id="s9" class="num">9</a><p class="sans">\u0906\u0926\u0930\u094D\u0936\u0947 \u092E\u0932\u0930\u0939\u093F\u0924\u0947 \u092F\u0926\u094D\u0935\u0926\u094D\u0935\u0926\u0928\u0902 \u0935\u093F\u092D\u093E\u0924\u093F \u0924\u0926\u094D\u0935\u0926\u092F\u092E\u094D \u0964<br> \u0936\u093F\u0935\u0936\u0915\u094D\u0924\u093F\u092A\u093E\u0924\u0935\u093F\u092E\u0932\u0947 \u0927\u0940\u0924\u0924\u094D\u0924\u094D\u0935\u0947 \u092D\u093E\u0924\u093F \u092D\u093E\u0930\u0942\u092A\u0903 \u0965\u096F\u0965</p><p class="trans">\u0100dar\u015Be malarahite yadvadvadana\u1E41 vibh\u0101ti tadvadayam \u0964<br> \u015Aiva\u015Baktip\u0101tavimale dh\u012Btattve bh\u0101ti bh\u0101r\u016Bpa\u1E25 \u09659\u0965</p><p>\u041A\u0430\u043A <em>(yadvat)</em> \u043B\u0438\u0446\u043E <em>(vadanam)</em> \u044F\u0441\u043D\u043E \u0432\u0438\u0434\u043D\u043E <em>(vibh\u0101ti)</em> \u0432 \u0437\u0435\u0440\u043A\u0430\u043B\u0435 <em>(\u0101dar\u015Be)</em>, \u043B\u0438\u0448\u0451\u043D\u043D\u043E\u043C <em>(rahite)</em> \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0439 <em>(mala)</em>, \u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435 <em>(tadvat)</em> \u044D\u0442\u043E\u0442 <em>(ayam)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0432 \u0444\u043E\u0440\u043C\u0435 \u0441\u0438\u044F\u043D\u0438\u044F <em>(bh\u0101r\u016Bpa\u1E25)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(bh\u0101ti)</em> \u0432 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 <em>(tattve)</em> \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430 <em>(dh\u012B)</em>, \u043E\u0447\u0438\u0449\u0435\u043D\u043D\u043E\u043C <em>(vimale)</em> \u043D\u0438\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0435\u043C <em>(p\u0101ta)</em> \u0428\u0430\u043A\u0442\u0438 <em>(\u015Bakti)</em> \u0428\u0438\u0432\u044B <em>(\u015Biva)</em></p><p class="eng">Just as <em>(yadvat)</em> a face <em>(vadanam)</em> shines forth <em>(vibh\u0101ti)</em> in a mirror <em>(\u0101dar\u015Be)</em> devoid of <em>(rahite)</em> dirt <em>(mala)</em>, in the same way <em>(tadvat)</em> this <em>(ayam)</em> brilliant Lord <em>(bh\u0101r\u016Bpa\u1E25)</em> shines forth <em>(bh\u0101ti)</em> in the tattva or principle <em>(tattve)</em> of an intellect <em>(dh\u012B)</em> which is spotless <em>(vimale)</em> due to the descent <em>(p\u0101ta)</em> of Power <em>(\u015Bakti)</em> carried out by \u015Aiva <em>(\u015Biva)</em></p></div><div class="stanza"><a href="#s10-11" id="s10-11" class="num">10-11</a><p class="sans">\u092D\u093E\u0930\u0942\u092A\u0902 \u092A\u0930\u093F\u092A\u0942\u0930\u094D\u0923\u0902 \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0928\u093F \u0935\u093F\u0936\u094D\u0930\u093E\u0928\u094D\u0924\u093F\u0924\u094B \u092E\u0939\u093E\u0928\u0928\u094D\u0926\u092E\u094D \u0964<br> \u0907\u091A\u094D\u091B\u093E\u0938\u0902\u0935\u093F\u0924\u094D\u0915\u0930\u0923\u0948\u0930\u094D\u0928\u093F\u0930\u094D\u092D\u0930\u093F\u0924\u092E\u0928\u0928\u094D\u0924\u0936\u0915\u094D\u0924\u093F\u092A\u0930\u093F\u092A\u0942\u0930\u094D\u0923\u092E\u094D \u0965\u0967\u0966\u0965</p><p class="trans">Bh\u0101r\u016Bpa\u1E41 parip\u016Br\u1E47a\u1E41 sv\u0101tmani vi\u015Br\u0101ntito mah\u0101nandam \u0964<br> Icch\u0101sa\u1E41vitkara\u1E47airnirbharitamananta\u015Baktiparip\u016Br\u1E47am \u096510\u0965</p><p class="sans">\u0938\u0930\u094D\u0935\u0935\u093F\u0915\u0932\u094D\u092A\u0935\u093F\u0939\u0940\u0928\u0902 \u0936\u0941\u0926\u094D\u0927\u0902 \u0936\u093E\u0928\u094D\u0924\u0902 \u0932\u092F\u094B\u0926\u092F\u0935\u093F\u0939\u0940\u0928\u092E\u094D \u0964<br> \u092F\u0924\u094D \u092A\u0930\u0924\u0924\u094D\u0924\u094D\u0935\u0902 \u0924\u0938\u094D\u092E\u093F\u0928\u094D \u0935\u093F\u092D\u093E\u0924\u093F \u0937\u091F\u094D\u0924\u094D\u0930\u093F\u0902\u0936\u0926\u093E\u0924\u094D\u092E \u091C\u0917\u0924\u094D \u0965\u0967\u0967\u0965</p><p class="trans">Sarvavikalpavih\u012Bna\u1E41 \u015Buddha\u1E41 \u015B\u0101nta\u1E41 layodayavih\u012Bnam \u0964<br> Yat paratattva\u1E41 tasmin vibh\u0101ti \u1E63a\u1E6Dtri\u1E41\u015Bad\u0101tma jagat \u096511\u0965</p><p>\u041E\u0431\u043B\u0430\u0434\u0430\u044E\u0449\u0438\u0439 \u043B\u0443\u0447\u0435\u0437\u0430\u0440\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(bh\u0101-r\u016Bpam)</em>, \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u044B\u0439 <em>(parip\u016Br\u1E47am)</em>, [\u0447\u044C\u0451] \u0411\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0435 <em>(mah\u0101)</em> \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E <em>(\u0101nanda)</em> [\u043F\u043E\u0440\u043E\u0436\u0434\u0430\u0435\u0442\u0441\u044F] \u043E\u043F\u043E\u0440\u043E\u0439 \u0442\u043E\u043B\u044C\u043A\u043E <em>(vi\u015Br\u0101ntitas)</em> \u043D\u0430 \u0441\u0430\u043C\u043E\u0433\u043E \u0421\u0435\u0431\u044F <em>(sva-\u0101tmani)</em>, \u0438\u0437\u043E\u0431\u0438\u043B\u0443\u044E\u0449\u0438\u0439 *(nirbharitam) *\u0432\u043E\u043B\u0435\u0439 <em>(icch\u0101)</em> \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(sa\u1E41vid)</em> [\u0438] \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E\u0441\u0442\u044F\u043C\u0438 <em>(kara\u1E47ai\u1E25)</em> \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0439 <em>(parip\u016Br\u1E47am)</em> \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u044B\u043C\u0438 <em>(ananta)</em> \u0441\u0438\u043B\u0430\u043C\u0438 <em>(\u015Bakti)</em>, \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439 <em>(vih\u012Bnam)</em> \u043E\u0442\u043E \u0432\u0441\u0435\u0445 <em>(sarva)</em> \u0443\u043C\u043E\u043F\u043E\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u0439 <em>(vikalpa)</em>, \u0447\u0438\u0441\u0442\u044B\u0439 <em>(\u015Buddham)</em>, \u0431\u0435\u0437\u043C\u044F\u0442\u0435\u0436\u043D\u044B\u0439 <em>(\u015B\u0101ntam)</em> [\u0438] \u043D\u0435 \u043F\u043E\u0434\u0432\u0435\u0440\u0436\u0435\u043D\u043D\u044B\u0439 <em>(vih\u012Bnam)</em> \u0441\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044E <em>(udaya)</em> [\u0438] \u0440\u0430\u0441\u043F\u0430\u0434\u0443 <em>(laya)</em> \u2014 \u0442\u0430\u043A\u043E\u0432 <em>(yad)</em> \u0412\u044B\u0441\u0448\u0438\u0439 <em>(param)</em> \u041F\u0440\u0438\u043D\u0446\u0438\u043F <em>(tattvam)</em>, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C <em>(tasmin)</em> \u0441\u0438\u044F\u0435\u0442 <em>(vibh\u0101ti)</em> \u0432\u0441\u044F \u0412\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(jagat)</em>, \u043E\u0431\u043B\u0430\u0434\u0430\u044E\u0449\u0430\u044F \u0442\u0440\u0438\u0434\u0446\u0430\u0442\u0438\u0448\u0435\u0441\u0442\u0438\u0447\u0430\u0441\u0442\u043D\u043E\u0439 <em>(\u1E63a\u1E6Dtri\u1E41\u015Bat)</em> \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(\u0101tma)</em>.</p><p class="eng">The universe <em>(jagat)</em>, whose nature <em>(\u0101tma)</em> is thirty-six-fold \u2013consists of 36 tattva-s or categories\u2013 <em>(\u1E63a\u1E6Dtri\u1E41\u015Bat)</em> shines <em>(vibh\u0101ti)</em> in that <em>(tasmin)</em> Highest <em>(param)</em> Principle <em>(tattvam)</em> who <em>(yad)</em> is One whose nature is Effulgence <em>(bh\u0101-r\u016Bpam)</em>, who is totally Full <em>(parip\u016Br\u1E47am)</em>, [whose] Great <em>(mah\u0101)</em> Bliss <em>(\u0101nanda)</em> [comes] from a rest <em>(vi\u015Br\u0101ntitas)</em> on His own Self <em>(sva-\u0101tmani)</em>, who is replete <em>(nirbharitam)</em> with the instruments <em>(kara\u1E47ai\u1E25)</em> of the volitive <em>(icch\u0101)</em> Consciousness <em>(sa\u1E41vid)</em>, completely full of <em>(parip\u016Br\u1E47am)</em> infinite <em>(ananta)</em> powers <em>(\u015Bakti)</em>, who is free <em>(vih\u012Bnam)</em> from all <em>(sarva)</em> the thoughts <em>(vikalpa)</em>, Pure <em>(\u015Buddham)</em>, Peaceful <em>(\u015B\u0101ntam)</em> [and] without any <em>(vih\u012Bnam)</em> emergence <em>(udaya)</em> [and] dissolution <em>(laya)</em></p></div><div class="stanza"><a href="#s12-13" id="s12-13" class="num">12-13</a><p class="sans">\u0926\u0930\u094D\u092A\u0923\u092C\u093F\u092E\u094D\u092C\u0947 \u092F\u0926\u094D\u0935\u0928\u094D\u0928\u0917\u0930\u0917\u094D\u0930\u093E\u092E\u093E\u0926\u093F \u091A\u093F\u0924\u094D\u0930\u092E\u0935\u093F\u092D\u093E\u0917\u093F \u0964<br> \u092D\u093E\u0924\u093F \u0935\u093F\u092D\u093E\u0917\u0947\u0928\u0948\u0935 \u091A \u092A\u0930\u0938\u094D\u092A\u0930\u0902 \u0926\u0930\u094D\u092A\u0923\u093E\u0926\u092A\u093F \u091A \u0965\u0967\u0968\u0965</p><p class="trans">Darpa\u1E47abimbe yadvannagaragr\u0101m\u0101di citramavibh\u0101gi \u0964<br> Bh\u0101ti vibh\u0101genaiva ca paraspara\u1E41 darpa\u1E47\u0101dapi ca \u096512\u0965</p><p class="sans">\u0935\u093F\u092E\u0932\u0924\u092E\u092A\u0930\u092E\u092D\u0948\u0930\u0935\u092C\u094B\u0927\u093E\u0924\u094D\u0924\u0926\u094D\u0935\u0926\u094D\u0935\u093F\u092D\u093E\u0917\u0936\u0942\u0928\u094D\u092F\u092E\u092A\u093F \u0964<br> \u0905\u0928\u094D\u092F\u094B\u0928\u094D\u092F\u0902 \u091A \u0924\u0924\u094B\u093D\u092A\u093F \u091A \u0935\u093F\u092D\u0915\u094D\u0924\u092E\u093E\u092D\u093E\u0924\u093F \u091C\u0917\u0926\u0947\u0924\u0924\u094D\u0965\u0967\u0969\u0965</p><p class="trans">Vimalatamaparamabhairavabodh\u0101ttadvadvibh\u0101ga\u015B\u016Bnyamapi \u0964<br> Anyonya\u1E41 ca tato\u2019pi ca vibhaktam\u0101bh\u0101ti jagadetat \u096513\u0965</p><p>\u041A\u0430\u043A <em>(yadvat)</em> \u0433\u043E\u0440\u043E\u0434\u0430 <em>(nagara)</em>, \u0434\u0435\u0440\u0435\u0432\u043D\u0438 <em>(gr\u0101ma)</em> \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u043E\u0442\u0440\u0430\u0436\u0430\u044F\u0441\u044C <em>(bimbe)</em> \u0432 \u0437\u0435\u0440\u043A\u0430\u043B\u0435 <em>(darpa\u1E47a)</em> \u043D\u0435\u0434\u0435\u043B\u0438\u043C\u044B\u043C <em>(avibh\u0101gi)</em> \u0438\u0437\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0435\u043C <em>(citram)</em>, \u0432\u0438\u0434\u044F\u0442\u0441\u044F <em>(bh\u0101ti)</em> \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(eva)</em> \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u043C\u0438 <em>(vibh\u0101gena)</em> \u043A\u0430\u043A <em>(ca)</em> \u0434\u0440\u0443\u0433 \u043E\u0442 \u0434\u0440\u0443\u0433\u0430 <em>(parasparam)</em>, \u0442\u0430\u043A <em>(api)</em> \u0438 <em>(ca)</em> \u043E\u0442 <em>(\u0441\u0430\u043C\u043E\u0433\u043E)</em> \u0437\u0435\u0440\u043A\u0430\u043B\u0430 <em>(darpa\u1E47\u0101t)</em>, \u0442\u0430\u043A \u0436\u0435 <em>(tadvat)</em> \u044D\u0442\u0430 <em>(etad)</em> \u043D\u0435\u043E\u0442\u043B\u0438\u0447\u043D\u0430\u044F <em>(vibh\u0101ga-\u015B\u016Bnyam)</em> \u043E\u0442 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(bodh\u0101t)</em> \u0447\u0438\u0441\u0442\u0435\u0439\u0448\u0435\u0433\u043E <em>(vimalatama)</em> \u041F\u0430\u0440\u0430\u043C\u0430\u0431\u0445\u0430\u0439\u0440\u0430\u0432\u044B <em>(parama-bhairava)</em> \u0412\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(jagat)</em> \u0442\u043E\u0436\u0435 <em>(api)</em> \u0432\u0438\u0434\u0438\u0442\u0441\u044F <em>(\u0101bh\u0101ti)</em> \u0440\u0430\u0437\u0434\u0435\u043B\u0451\u043D\u043D\u043E\u0439 <em>(vibhaktam)</em> \u043A\u0430\u043A <em>(ca)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435 <em>(anyonyam)</em>, \u0442\u0430\u043A <em>(api)</em> \u0438 <em>(ca)</em> \u0441 \u041D\u0438\u043C [\u0441\u0430\u043C\u0438\u043C] <em>(tatas)</em>.</p><p class="eng">Just as <em>(yadvat)</em> the variety <em>(citram)</em> [composed of] a city <em>(nagara)</em>, a village <em>(gr\u0101ma)</em>, etc. <em>(\u0101di)</em> when reflected _(bimbe)_in a mirror <em>(darpa\u1E47a)</em>, [though] it is not different [from the mirror] <em>(avibh\u0101gi)</em>, shines forth <em>(bh\u0101ti)</em> as mutually <em>(parasparam)</em> differentiated \u2013i.e. as a city, a village, etc.\u2013 <em>(vibh\u0101gena eva)</em> and also <em>(ca\u2026 ca)</em> [as different] even _(api)_from the mirror [itself] <em>(darpa\u1E47\u0101t)</em>, even so <em>(tadvat)</em> this <em>(etad)</em> universe <em>(jagat)</em>, though <em>(api)</em> it is not different <em>(vibh\u0101ga-\u015B\u016Bnyam)</em> from the Consciousness <em>(bodh\u0101t)</em> of the extremely Pure <em>(vimalatama)</em> Paramabhairava \u2013the Supreme Bhairava or \u015Aiva\u2013 <em>(parama-bhairava)</em>, shines forth <em>(\u0101bh\u0101ti)</em> as mutually <em>(anyonyam)</em> differentiated <em>(vibhaktam)</em> and also <em>(ca\u2026 ca)</em> [as different] even <em>(api)</em>from Himself _(tatas)_.</p></div><div class="stanza"><a href="#s14" id="s14" class="num">14</a><p class="sans">\u0936\u093F\u0935\u0936\u0915\u094D\u0924\u093F\u0938\u0926\u093E\u0936\u093F\u0935\u0924\u093E\u092E\u0940\u0936\u094D\u0935\u0930\u0935\u093F\u0926\u094D\u092F\u093E\u092E\u092F\u0940\u0902 \u091A \u0924\u0924\u094D\u0924\u094D\u0935\u0926\u0936\u093E\u092E\u094D \u0964<br> \u0936\u0915\u094D\u0924\u0940\u0928\u093E\u0902 \u092A\u091E\u094D\u091A\u093E\u0928\u093E\u0902 \u0935\u093F\u092D\u0915\u094D\u0924\u092D\u093E\u0935\u0947\u0928 \u092D\u093E\u0938\u092F\u0924\u093F \u0965\u0967\u096A\u0965</p><p class="trans">\u015Aiva\u015Baktisad\u0101\u015Bivat\u0101m\u012B\u015Bvaravidy\u0101may\u012B\u1E41 ca tattvada\u015B\u0101m \u0964<br> \u015Aakt\u012Bn\u0101\u1E41 pa\xF1c\u0101n\u0101\u1E41 vibhaktabh\u0101vena bh\u0101sayati \u096514\u0965</p><p>\u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044F \u0434\u0438\u0444\u0444\u0435\u0440\u0435\u043D\u0446\u0438\u0440\u0443\u044E\u0449\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(vibhakta-bh\u0101vena)</em> \u043F\u044F\u0442\u0438 \u0441\u0438\u043B <em>(\u015Bakt\u012Bn\u0101m pa\xF1c\u0101n\u0101m)</em>, <em>(\u041F\u0430\u0440\u0430\u043C\u0430\u0431\u0445\u0430\u0439\u0440\u0430\u0432\u0430)</em> \u043F\u0440\u043E\u0435\u0446\u0438\u0440\u0443\u0435\u0442 <em>(bh\u0101sayati)</em> [\u0447\u0438\u0441\u0442\u044B\u0435] \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 <em>(tattva-da\u015B\u0101m)</em> \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u0435 \u043A\u0430\u043A <em>(t\u0101m\u2026 may\u012Bm)</em> \u0428\u0438\u0432\u0430 <em>(\u015Biva)</em>, \u0428\u0430\u043A\u0442\u0438 <em>(\u015Bakti)</em>, \u0421\u0430\u0434\u0430\u0448\u0438\u0432\u0430 <em>(sad\u0101\u015Biva)</em>, \u0430 \u0442\u0430\u043A\u0436\u0435 <em>(ca)</em> \u0418\u0448\u0432\u0430\u0440\u0430 <em>(\u012B\u015Bvara)</em> [\u0438] \u0412\u0438\u0434\u044C\u044F <em>(vidy\u0101)</em>.</p><p class="eng">Through a division <em>(vibhakta-bh\u0101vena)</em> of [His] five Powers <em>(\u015Bakt\u012Bn\u0101m pa\xF1c\u0101n\u0101m)</em>, [Parama\u015Biva] manifests _(bh\u0101sayati)_the tattvic state <em>(tattva-da\u015B\u0101m)</em> composed of <em>(t\u0101m\u2026 may\u012Bm)</em> [the tattva-s or categories known as] \u015Aiva <em>(\u015Biva)</em>, \u015Aakti <em>(\u015Bakti)</em> [and] Sad\u0101\u015Biva <em>(sad\u0101\u015Biva)</em> together with <em>(ca)</em> \u012A\u015Bvara <em>(\u012B\u015Bvara)</em>[and] Sadvidy\u0101 _(vidy\u0101)_</p></div><div class="stanza"><a href="#s15" id="s15" class="num">15</a><p class="sans">\u092A\u0930\u092E\u0902 \u092F\u0924\u094D \u0938\u094D\u0935\u093E\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u0902 \u0926\u0941\u0930\u094D\u0918\u091F\u0938\u092E\u094D\u092A\u093E\u0926\u0928\u0902 \u092E\u0939\u0947\u0936\u0938\u094D\u092F \u0964<br> \u0926\u0947\u0935\u0940 \u092E\u093E\u092F\u093E\u0936\u0915\u094D\u0924\u093F\u0903 \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u093E\u0935\u0930\u0923\u0902 \u0936\u093F\u0935\u0938\u094D\u092F\u0948\u0924\u0924\u094D \u0965\u0967\u096B\u0965</p><p class="trans">Parama\u1E41 yat sv\u0101tantrya\u1E41 durgha\u1E6Dasamp\u0101dana\u1E41 mahe\u015Basya \u0964<br> Dev\u012B m\u0101y\u0101\u015Bakti\u1E25 sv\u0101tm\u0101vara\u1E47a\u1E41 \u015Bivasyaitat \u096515\u0965</p><p>\u0422\u0430 <em>(yad)</em> \u0432\u044B\u0441\u0448\u0430\u044F <em>(paramam)</em> \u0438 \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u044E\u0449\u0430\u044F <em>(samp\u0101danam)</em> \u0442\u0440\u0443\u0434\u043D\u0435\u0439\u0448\u0435\u0435 <em>(durgha\u1E6Da)</em> \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u0430\u044F \u0441\u0432\u043E\u0431\u043E\u0434\u0430 \u0432\u043E\u043B\u0438 <em>(sv\u0101tantryam)</em> \u0412\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(mah\u0101-\u012B\u015Basya)</em>, [\u0435\u0441\u0442\u044C] \u0411\u043E\u0433\u0438\u043D\u044F <em>(dev\u012B)</em> \u041C\u0430\u0439\u044F-\u0448\u0430\u043A\u0442\u0438 <em>(m\u0101y\u0101-\u015Bakti\u1E25)</em> \u2014 [c\u0438\u043B\u0430] \u0441\u0430\u043C\u043E\u0441\u043E\u043A\u0440\u044B\u0442\u0438\u044F <em>(sva-\u0101tma-\u0101vara\u1E47am)</em> \u0441\u0430\u043C\u043E\u0433\u043E <em>(etad)</em> \u0428\u0438\u0432\u044B <em>(\u015Bivasya).</em></p><p class="eng">This <em>(etad)</em> Freedom <em>(sv\u0101tantryam)</em> of the Great Lord <em>(mah\u0101-\u012B\u015Basya)</em>, which <em>(yad)</em> [is] Supreme <em>(paramam)</em> [and] able to carry out <em>(samp\u0101danam)</em> what is hard to be accomplished <em>(durgha\u1E6Da)</em>, [is] the Goddess <em>(dev\u012B)</em> M\u0101y\u0101\u015Bakti <em>(m\u0101y\u0101-\u015Bakti\u1E25)</em> [or] the Self-concealing [Power] <em>(sva-\u0101tma-\u0101vara\u1E47am)</em> of \u015Aiva <em>(\u015Bivasya)</em></p></div><div class="stanza"><a href="#s16" id="s16" class="num">16</a><p class="sans">\u092E\u093E\u092F\u093E\u092A\u0930\u093F\u0917\u094D\u0930\u0939\u0935\u0936\u093E\u0926\u094D\u092C\u094B\u0927\u094B \u092E\u0932\u093F\u0928\u0903 \u092A\u0941\u092E\u093E\u0928\u094D \u092A\u0936\u0941\u0930\u094D\u092D\u0935\u0924\u093F \u0964<br> \u0915\u093E\u0932\u0915\u0932\u093E\u0928\u093F\u092F\u0924\u093F\u0935\u0936\u093E\u0926\u094D\u0930\u093E\u0917\u093E\u0935\u093F\u0926\u094D\u092F\u093E\u0935\u0936\u0947\u0928 \u0938\u092E\u094D\u092C\u0926\u094D\u0927\u0903 \u0965\u0967\u096C\u0965</p><p class="trans">M\u0101y\u0101parigrahava\u015B\u0101dbodho malina\u1E25 pum\u0101n pa\u015Burbhavati \u0964<br> K\u0101lakal\u0101niyativa\u015B\u0101dr\u0101g\u0101vidy\u0101va\u015Bena sambaddha\u1E25 \u096516\u0965</p><p>\u041F\u043E\u0434\u0447\u0438\u043D\u0435\u043D\u043D\u043E\u0435 <em>(va\u015B\u0101t)</em> \u0432\u043B\u0430\u0441\u0442\u0438 <em>(parigraha)</em> \u041C\u0430\u0439\u0438 <em>(m\u0101y\u0101)</em>, \u0447\u0438\u0441\u0442\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(bodha\u1E25)</em> \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u044F\u0435\u0442\u0441\u044F <em>(malina\u1E25)</em> <em>(\u0438)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(bhavati)</em> \u041F\u0443\u0440\u0443\u0448\u0435\u0439 <em>(pum\u0101n)</em>, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u043C <em>(pa\u015Bu\u1E25)</em>, \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u043C <em>(sambaddha\u1E25)</em> \u043F\u0440\u0438 \u043F\u043E\u043C\u043E\u0449\u0438 <em>(va\u015B\u0101t\u2026 va\u015Bena)</em> <em>[\u043F\u044F\u0442\u0438 \u043A\u0430\u043D\u0447\u0443\u043A \u0438\u043B\u0438 \u043F\u043E\u043A\u0440\u043E\u0432\u043E\u0432:]</em> \u043A\u0410\u043B\u0430 <em>(k\u0101la)</em>, \u043A\u0430\u043B\u0410 <em>(kal\u0101)</em>, \u043D\u0438\u044F\u0442\u0438 <em>(niyati)</em>, \u0440\u0430\u0433\u0438 <em>(r\u0101ga)</em> [\u0438] \u0430\u0432\u0438\u0434\u044C\u0438 <em>(avidy\u0101)</em>.</p><p class="eng">Due to <em>(va\u015B\u0101t)</em> the control and dominion <em>(parigraha)</em> of M\u0101y\u0101 <em>(m\u0101y\u0101)</em>, Bodha or Pure Consciousness \u2013Lord \u015Aiva\u2013 <em>(bodha\u1E25)</em> becomes <em>(bhavati)</em> Puru\u1E63a \u2013category 12\u2013 <em>(pum\u0101n)</em>, i.e. a limited individual \u2013lit. an animal\u2013 <em>(pa\u015Bu\u1E25)</em> furnished with Mala or Impurity <em>(malina\u1E25)</em>, [and as a result] gets completely bound <em>(sambaddha\u1E25)</em> by means of <em>(va\u015B\u0101t\u2026 va\u015Bena)</em> [the five Ka\xF1cuka-s or Sheaths known as] K\u0101la <em>(k\u0101la)</em>, Kal\u0101 <em>(kal\u0101)</em>, Niyati <em>(niyati)</em>, R\u0101ga <em>(r\u0101ga)</em> [and] Avidy\u0101 \u2013usually called Vidy\u0101\u2013 <em>(avidy\u0101)</em></p></div><div class="stanza"><a href="#s17" id="s17" class="num">17</a><p class="sans">\u0905\u0927\u0941\u0928\u0948\u0935 \u0915\u093F\u091E\u094D\u091A\u093F\u0926\u0947\u0935\u0947\u0926\u092E\u0947\u0935 \u0938\u0930\u094D\u0935\u093E\u0924\u094D\u092E\u0928\u0948\u0935 \u091C\u093E\u0928\u093E\u092E\u093F \u0964<br> \u092E\u093E\u092F\u093E\u0938\u0939\u093F\u0924\u0902 \u0915\u091E\u094D\u091A\u0941\u0915\u0937\u091F\u094D\u0915\u092E\u0923\u094B\u0930\u0928\u094D\u0924\u0930\u0919\u094D\u0917\u092E\u093F\u0926\u092E\u0941\u0915\u094D\u0924\u092E\u094D \u0965\u0967\u096D\u0965</p><p class="trans">Adhunaiva ki\xF1cidevedameva sarv\u0101tmanaiva j\u0101n\u0101mi \u0964<br> M\u0101y\u0101sahita\u1E41 ka\xF1cuka\u1E63a\u1E6Dkama\u1E47orantara\u1E45gamidamuktam \u096517\u0965</p><p>\u042D\u0442\u0438 <em>(idam)</em> [\u043F\u044F\u0442\u044C \u043F\u043E\u043D\u044F\u0442\u0438\u0439:] \u201C\u042F \u0437\u043D\u0430\u044E\u201D <em>(j\u0101n\u0101mi)</em>, \u201C\u0442\u043E\u043B\u044C\u043A\u043E \u0441\u0435\u0439\u0447\u0430\u0441 <em>(adhun\u0101 eva)</em>\u201C, \u201C\u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u043D\u0435\u043C\u043D\u043E\u0433\u043E <em>(ki\xF1cid)</em>\u201C, \u201C\u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u044D\u0442\u043E <em>(idam)</em>\u201C, \u201C\u0432\u0441\u0451 \u0434\u043B\u044F \u043C\u0435\u043D\u044F\u201D <em>(sarva-\u0101tman\u0101 eva)</em> \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 <em>(sahitam)</em> \u043C\u0430\u0439\u0435\u0439 <em>(m\u0101y\u0101)</em> \u043D\u0430\u0437\u044B\u0432\u0430\u044E\u0442 <em>(uktam)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 <em>(antar-a\u1E45gam)</em> \u0448\u0435\u0441\u0442\u0451\u0440\u043A\u043E\u0439 <em>(\u1E63a\u1E6Dkam)</em> \u043F\u043E\u043A\u0440\u043E\u0432\u043E\u0432 <em>(ka\xF1cuka)</em> \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0430 <em>(a\u1E47o\u1E25)</em>.</p><p class="eng">This <em>(idam)</em> is said to be <em>(uktam)</em> the internal <em>(antar-a\u1E45gam)</em> group of six <em>(\u1E63a\u1E6Dkam)</em> Sheaths <em>(ka\xF1cuka)</em> of an a\u1E47u or limited being \u2013Puru\u1E63a\u2013 <em>(a\u1E47o\u1E25)</em>: [The five notions] \u201Cnow <em>(adhun\u0101 eva)</em>!\u201D, \u201Conly <em>(eva)</em> something <em>(ki\xF1cid)</em>\u201C, \u201Conly <em>(eva)</em> this <em>(idam)</em>\u201C, \u201Ccompletely!\u201D <em>(sarva-\u0101tman\u0101 eva)</em>, \u201CI know\u201D <em>(j\u0101n\u0101mi)</em>, together with <em>(sahitam)</em> M\u0101y\u0101 <em>(m\u0101y\u0101)</em></p></div><div class="stanza"><a href="#s18" id="s18" class="num">18</a><p class="sans">\u0915\u092E\u094D\u092C\u0941\u0915\u092E\u093F\u0935 \u0924\u0923\u094D\u0921\u0941\u0932\u0915\u0923\u0935\u093F\u0928\u093F\u0935\u093F\u0937\u094D\u091F\u0902 \u092D\u093F\u0928\u094D\u0928\u092E\u092A\u094D\u092F\u092D\u093F\u0926\u093E \u0964<br> \u092D\u091C\u0924\u0947 \u0924\u0924\u094D\u0924\u0941 \u0935\u093F\u0936\u0941\u0926\u094D\u0927\u093F\u0902 \u0936\u093F\u0935\u092E\u093E\u0930\u094D\u0917\u094C\u0928\u094D\u092E\u0941\u0916\u094D\u092F\u092F\u094B\u0917\u0947\u0928 \u0965\u0967\u096E\u0965</p><p class="trans">Kambukamiva ta\u1E47\u1E0Dulaka\u1E47avinivi\u1E63\u1E6Da\u1E41 bhinnamapyabhid\u0101 \u0964<br> Bhajate tattu vi\u015Buddhi\u1E41 \u015Bivam\u0101rgaunmukhyayogena \u096518\u0965</p><p>\u041A\u0430\u043A <em>(iva)</em> \u043E\u0442\u0440\u0443\u0431\u0435\u0432\u0430\u044F \u043E\u0431\u043E\u043B\u043E\u0447\u043A\u0430 <em>(kambukam)</em>, \u043F\u043E\u043A\u0440\u044B\u0432\u0430\u044E\u0449\u0430\u044F <em>(vinivi\u1E63\u1E6Dam)</em> \u0440\u0438\u0441\u043E\u0432\u043E\u0435 \u0437\u0435\u0440\u043D\u043E <em>(ta\u1E47\u1E0Dula-ka\u1E47a)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0431\u0443\u0434\u0443\u0447\u0438 <em>(api)</em> \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0439 <em>(bhinnam)</em>, \u043A\u0430\u0436\u0435\u0442\u0441\u044F \u0435\u0434\u0438\u043D\u043E\u0439 <em>[\u0441 \u043D\u0438\u043C]</em> <em>(abhid\u0101)</em>. \u041D\u043E <em>(tu)</em> \u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u0435\u043C <em>(aunmukhya)</em> \u043A \u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044E <em>(yogena)</em> \u043D\u0430 \u043F\u0443\u0442\u0438 \u0428\u0438\u0432\u044B <em>(\u015Biva-m\u0101rga)</em> \u0434\u043E\u0441\u0442\u0438\u0436\u0438\u043C\u043E <em>(bhajate)</em> \u0438\u0445 <em>(t\xE1d)</em> \u043F\u043E\u043B\u043D\u043E\u0435 \u043E\u0447\u0438\u0449\u0435\u043D\u0438\u0435 <em>(vi\u015Buddhim)</em>.</p><p class="eng">[That group of six Sheaths is] as <em>(iva)</em> the bran <em>(kambukam)</em> residing <em>(vinivi\u1E63\u1E6Dam)</em> on a rice-grain <em>(ta\u1E47\u1E0Dula-ka\u1E47a)</em>, that though <em>(api)</em> separate [from the grain itself] <em>(bhinnam)</em>, it seems to be not separated [from it] \u2013lit. with absence of separation\u2013 <em>(abhid\u0101)</em>. But <em>(tu)</em> it \u2013the group of six Sheaths\u2013 <em>(t\xE1d)</em> attains <em>(bhajate)</em> extreme purity <em>(vi\u015Buddhim)</em> through the Yoga or Union <em>(yogena)</em> oriented <em>(aunmukhya)</em> toward the \u015Aiva\u2019s path <em>(\u015Biva-m\u0101rga)</em></p></div><div class="stanza"><a href="#s19" id="s19" class="num">19</a><p class="sans">\u0938\u0941\u0916\u0926\u0941\u0903\u0916\u092E\u094B\u0939\u092E\u093E\u0924\u094D\u0930\u0902 \u0928\u093F\u0936\u094D\u091A\u092F\u0938\u0919\u094D\u0915\u0932\u094D\u092A\u0928\u093E\u092D\u093F\u092E\u093E\u0928\u093E\u091A\u094D\u091A \u0964<br> \u092A\u094D\u0930\u0915\u0943\u0924\u093F\u0930\u0925\u093E\u0928\u094D\u0924\u0903\u0915\u0930\u0923\u0902 \u092C\u0941\u0926\u094D\u0927\u093F\u092E\u0928\u094B\u093D\u0939\u0919\u094D\u0915\u0943\u0924\u093F \u0915\u094D\u0930\u092E\u0936\u0903 \u0965\u0967\u096F\u0965</p><p class="trans">Sukhadu\u1E25khamoham\u0101tra\u1E41 ni\u015Bcayasa\u1E45kalpan\u0101bhim\u0101n\u0101cca \u0964<br> Prak\u1E5Btirath\u0101nta\u1E25kara\u1E47a\u1E41 buddhimano\u2019ha\u1E45k\u1E5Bti krama\u015Ba\u1E25 \u096519\u0965</p><p>\u0421\u043E\u0441\u0442\u043E\u044F\u0449\u0430\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u0438\u0437 <em>(m\u0101tram)</em> \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F <em>(sukha)</em>, \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u044F <em>(du\u1E25kha)</em> [\u0438] \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(moha)</em>, [\u0432\u044B\u0440\u0430\u0436\u0430\u044E\u0449\u0438\u0445\u0441\u044F \u0432] \u0443\u0432\u0435\u0440\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0440\u0435\u0448\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0438 \u0441\u0430\u043C\u043E\u043C\u043D\u0435\u043D\u0438\u0438 <em>(ni\u015Bcaya-sa\u1E45kalpana-abhim\u0101n\u0101t)</em>, \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(prak\u1E5Bti\u1E25)</em> \u0437\u0430\u0442\u0435\u043C <em>(atha)</em>, <em>[\u043F\u043E\u0440\u043E\u0436\u0434\u0430\u0435\u0442]</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0439 \u043E\u0440\u0433\u0430\u043D <em>(anta\u1E25kara\u1E47am)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0438\u0439 \u0438\u0437 \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430, \u0443\u043C\u0430 \u0438 \u044D\u0433\u043E <em>(buddhi-manas-aha\u1E45k\u1E5Bti)</em> \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E <em>(krama\u015Ba\u1E25)</em>.</p><p class="eng">Prak\u1E5Bti <em>(prak\u1E5Bti\u1E25)</em> consists of only <em>(m\u0101tram)</em> pleasure <em>(sukha)</em>, pain <em>(du\u1E25kha)</em> [and] delusion <em>(moha)</em>. And <em>(ca)</em> then <em>(atha)</em>, [from this Prak\u1E5Bti herself,] the inner [psychic] organ <em>(anta\u1E25kara\u1E47am)</em> comprising Buddhi \u2013intellect\u2013, Manas \u2013mind\u2013 and Aha\u1E45k\u0101ra \u2013ego\u2013 <em>(buddhi-manas-aha\u1E45k\u1E5Bti)</em> [emerges] from definite cognition \u2013lit. fixed opinion\u2013, the act of thinking \u2013lit. volition\u2013 and the state of \u201Cmine\u201D \u2013lit. an erroneous conception regarding one\u2019s own Self\u2013 <em>(ni\u015Bcaya-sa\u1E45kalpana-abhim\u0101n\u0101t)</em>, in succession \u2013i.e. respectively\u2013 <em>(krama\u015Ba\u1E25)</em></p></div><div class="stanza"><a href="#s20" id="s20" class="num">20</a><p class="sans">\u0936\u094D\u0930\u094B\u0924\u094D\u0930\u0902 \u0924\u094D\u0935\u0917\u0915\u094D\u0937\u093F \u0930\u0938\u0928\u093E \u0918\u094D\u0930\u093E\u0923\u0902 \u092C\u0941\u0926\u094D\u0927\u0940\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u093E\u0923\u093F \u0936\u092C\u094D\u0926\u093E\u0926\u094C \u0964<br> \u0935\u093E\u0915\u094D\u092A\u093E\u0923\u093F\u092A\u093E\u0926\u092A\u093E\u092F\u0942\u092A\u0938\u094D\u0925\u0902 \u0915\u0930\u094D\u092E\u0947\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u093E\u0923\u093F \u092A\u0941\u0928\u0903 \u0965\u0968\u0966\u0965</p><p class="trans">\u015Arotra\u1E41 tvagak\u1E63i rasan\u0101 ghr\u0101\u1E47a\u1E41 buddh\u012Bndriy\u0101\u1E47i \u015Babd\u0101dau \u0964<br> V\u0101kp\u0101\u1E47ip\u0101dap\u0101y\u016Bpastha\u1E41 karmendriy\u0101\u1E47i puna\u1E25 \u096520\u0965</p><p>\u0421\u0438\u043B\u044B \u0441\u043B\u0443\u0445\u0430 <em>(\u015Brotram)</em>, \u043E\u0441\u044F\u0437\u0430\u043D\u0438\u044F <em>(tvak)</em>, \u0432\u0438\u0434\u0435\u043D\u0438\u044F <em>(ak\u1E63i)</em>, \u0432\u043A\u0443\u0441\u0430 <em>(rasan\u0101)</em> [\u0438] \u043E\u0431\u043E\u043D\u044F\u043D\u0438\u044F <em>(ghr\u0101\u1E47am)</em> <em>[\u0435\u0441\u0442\u044C \u043F\u044F\u0442\u044C]</em> \u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F <em>(buddhi-indriy\u0101\u1E47i)</em> \u0437\u0432\u0443\u043A\u0430 \u0438 \u0442.\u0434. <em>(\u015Babda-\u0101dau)</em>. \u041D\u0430\u0440\u044F\u0434\u0443 \u0441 \u044D\u0442\u0438\u043C <em>(punar)</em> \u0441\u0438\u043B\u044B \u0440\u0435\u0447\u0438 <em>(v\u0101k)</em>, \u043C\u0430\u043D\u0438\u043F\u0443\u043B\u044F\u0446\u0438\u0438 <em>(p\u0101\u1E47i)</em>, \u043F\u0435\u0440\u0435\u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F <em>(p\u0101da)</em>, \u0432\u044B\u0434\u0435\u043B\u0435\u043D\u0438\u044F <em>(p\u0101yu)</em> [\u0438] \u0432\u043E\u0441\u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u0438\u044F <em>(upastham)</em> [\u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0442 \u043F\u044F\u0442\u044C] \u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(karma-indriy\u0101\u1E47i)</em>.</p><p class="eng">The power of hearing <em>(\u015Brotram)</em>, the power of feeling by touch <em>(tvak)</em>, the power of seeing <em>(ak\u1E63i)</em>, the power of tasting <em>(rasan\u0101)</em> [and] the power of smelling <em>(ghr\u0101\u1E47am)</em> [are the five] Powers of Perception <em>(buddhi-indriy\u0101\u1E47i)</em> with respect to Sound[-as-such], etc. <em>(\u015Babda-\u0101dau)</em>. Besides <em>(punar)</em>, the power of speaking <em>(v\u0101k)</em>, the power of handling <em>(p\u0101\u1E47i)</em>, the power of locomotion <em>(p\u0101da)</em>, the power of excreting <em>(p\u0101yu)</em> [and] the power of sexual activity and restfulness <em>(upastham)</em> [constitute the five] Powers of Action <em>(karma-indriy\u0101\u1E47i)</em></p></div><div class="stanza"><a href="#s21" id="s21" class="num">21</a><p class="sans">\u090F\u0937\u093E\u0902 \u0917\u094D\u0930\u093E\u0939\u094D\u092F\u094B \u0935\u093F\u0937\u092F\u0903 \u0938\u0942\u0915\u094D\u0937\u094D\u092E\u0903 \u092A\u094D\u0930\u0935\u093F\u092D\u093E\u0917\u0935\u0930\u094D\u091C\u093F\u0924\u094B \u092F\u0903 \u0938\u094D\u092F\u093E\u0924\u094D \u0964<br> \u0924\u0928\u094D\u092E\u093E\u0924\u094D\u0930\u092A\u091E\u094D\u091A\u0915\u0902 \u0924\u0924\u094D \u0936\u092C\u094D\u0926\u0903 \u0938\u094D\u092A\u0930\u094D\u0936\u094B \u092E\u0939\u094B \u0930\u0938\u094B \u0917\u0928\u094D\u0927\u0903 \u0965\u0968\u0967\u0965</p><p class="trans">E\u1E63\u0101\u1E41 gr\u0101hyo vi\u1E63aya\u1E25 s\u016Bk\u1E63ma\u1E25 pravibh\u0101gavarjito ya\u1E25 sy\u0101t \u0964<br> Tanm\u0101trapa\xF1caka\u1E41 tat \u015Babda\u1E25 spar\u015Bo maho raso gandha\u1E25 \u096521\u0965</p><p>\u0418\u0445 <em>(e\u1E63\u0101m)</em> \u0441\u0444\u0435\u0440\u044B \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u0438 <em>(vi\u1E63aya\u1E25)</em> \u0435\u0441\u0442\u044C <em>(sy\u0101t)</em> \u0442\u043E\u043D\u043A\u0438\u0435 <em>(s\u016Bk\u1E63ma\u1E25)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u044B <em>(gr\u0101hya\u1E25)</em> \u043A\u043E\u0442\u043E\u0440\u044B\u0435 <em>(ya\u1E25)</em> \u043B\u0438\u0448\u0435\u043D\u044B <em>(varjita\u1E25)</em> \u043A\u0430\u043A\u043E\u0433\u043E-\u043B\u0438\u0431\u043E \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F <em>(pravibh\u0101ga)</em>. \u042D\u0442\u043E <em>(tad)</em> \u043F\u044F\u0442\u0451\u0440\u043A\u0430 <em>(pa\xF1cakam)</em> \u0442\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 <em>(tad-m\u0101tra)</em>: \u0437\u0432\u0443\u043A <em>(\u015Babda\u1E25)</em>, \u043A\u0430\u0441\u0430\u043D\u0438\u0435 <em>(spar\u015Ba\u1E25)</em>, \u0441\u0432\u0435\u0442 <em>(maha\u1E25)</em>, \u0432\u043A\u0443\u0441 <em>(rasa\u1E25)</em> [\u0438] \u0437\u0430\u043F\u0430\u0445 <em>(gandha\u1E25)</em>.</p><p class="eng">The sphere of activity <em>(vi\u1E63aya\u1E25)</em> [or] object <em>(gr\u0101hya\u1E25)</em> of these [Buddh\u012Bndriya-s and Karmendriya-s] <em>(e\u1E63\u0101m)</em> is <em>(sy\u0101t)</em> [one] that <em>(ya\u1E25)</em> [is] subtle <em>(s\u016Bk\u1E63ma\u1E25)</em> [and] devoid of <em>(varjita\u1E25)</em> distinction or difference <em>(pravibh\u0101ga)</em>. That <em>(tad)</em> [is] the group of five <em>(pa\xF1cakam)</em> Tanm\u0101tra-s or Subtle Elements <em>(tad-m\u0101tra)</em>: Sound-as-such <em>(\u015Babda\u1E25)</em>, Touch-as-such <em>(spar\u015Ba\u1E25)</em>, Form or Color-as-such \u2013lit. light, luster\u2013 <em>(maha\u1E25)</em>, Flavor-as-such <em>(rasa\u1E25)</em> [and] Odor-as-such <em>(gandha\u1E25)</em></p></div><div class="stanza"><a href="#s22" id="s22" class="num">22</a><p class="sans">\u090F\u0924\u0924\u094D\u0938\u0902\u0938\u0930\u094D\u0917\u0935\u0936\u093E\u0924\u094D\u0938\u094D\u0925\u0942\u0932\u094B \u0935\u093F\u0937\u092F\u0938\u094D\u0924\u0941 \u092D\u0942\u0924\u092A\u091E\u094D\u091A\u0915\u0924\u093E\u092E\u094D \u0964<br> \u0905\u092D\u094D\u092F\u0947\u0924\u093F \u0928\u092D\u0903 \u092A\u0935\u0928\u0938\u094D\u0924\u0947\u091C\u0903 \u0938\u0932\u093F\u0932\u0902 \u091A \u092A\u0943\u0925\u094D\u0935\u0940 \u091A \u0965\u0968\u0968\u0965</p><p class="trans">Etatsa\u1E41sargava\u015B\u0101tsth\u016Blo vi\u1E63ayastu bh\u016Btapa\xF1cakat\u0101m \u0964<br> Abhyeti nabha\u1E25 pavanasteja\u1E25 salila\u1E41 ca p\u1E5Bthv\u012B ca \u096522\u0965</p><p>[\u041E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u043D\u044B\u0435] \u043F\u0443\u0442\u0451\u043C <em>(va\u015B\u0101t)</em> \u0438\u0445 <em>(etad)</em> \u0441\u043C\u0435\u0448\u0435\u043D\u0438\u044F <em>(sa\u1E41sarga)</em> \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u0435 <em>(sth\u016Bla\u1E25)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u044B <em>(vi\u1E63aya\u1E25)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u0442 \u0438\u0437 \u043F\u044F\u0442\u0451\u0440\u043A\u0438 <em>(pa\xF1cakat\u0101m abhyeti)</em> \u0433\u0440\u0443\u0431\u044B\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432: <em>(bh\u016Bta)</em> \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E <em>(nabha\u1E25)</em>, \u0432\u043E\u0437\u0434\u0443\u0445 <em>(pavana\u1E25)</em>, \u043E\u0433\u043E\u043D\u044C <em>(tejas)</em>, \u0432\u043E\u0434\u0430 <em>(salilam)</em> \u0438 <em>(ca)</em> \u0437\u0435\u043C\u043B\u044F <em>(p\u1E5Bthv\u012B)</em>.</p><p class="eng">By means of <em>(va\u015B\u0101t)</em> the mixture <em>(sa\u1E41sarga)</em> of these [Tanm\u0101tra-s or Subtle Elements] <em>(etad)</em>, the gross <em>(sth\u016Bla\u1E25)</em> object or sphere of activity [of a limited individual endowed with ego] <em>(vi\u1E63aya\u1E25)</em> becomes a group of five _(pa\xF1cakat\u0101m abhyeti)_elements <em>(bh\u016Bta)</em> [called:] Ether or Space <em>(nabha\u1E25)</em>, Air <em>(pavana\u1E25)</em>, Fire <em>(tejas)</em>, Water <em>(salilam)</em> and <em>(ca)</em>Earth _(p\u1E5Bthv\u012B)_</p></div><div class="stanza"><a href="#s23" id="s23" class="num">23</a><p class="sans">\u0924\u0941\u0937 \u0907\u0935 \u0924\u0923\u094D\u0921\u0941\u0932\u0915\u0923\u093F\u0915\u093E\u092E\u093E\u0935\u0943\u0923\u0941\u0924\u0947 \u092A\u094D\u0930\u0915\u0943\u0924\u093F\u092A\u0942\u0930\u094D\u0935\u0915\u0903 \u0938\u0930\u094D\u0917\u0903 \u0964<br> \u092A\u0943\u0925\u094D\u0935\u0940\u092A\u0930\u094D\u092F\u0928\u094D\u0924\u094B\u093D\u092F\u0902 \u091A\u0948\u0924\u0928\u094D\u092F\u0902 \u0926\u0947\u0939\u092D\u093E\u0935\u0947\u0928 \u0965\u0968\u0969\u0965</p><p class="trans">Tu\u1E63a iva ta\u1E47\u1E0Dulaka\u1E47ik\u0101m\u0101v\u1E5B\u1E47ute prak\u1E5Btip\u016Brvaka\u1E25 sarga\u1E25 \u0964<br> P\u1E5Bthv\u012Bparyanto\u2019ya\u1E41 caitanya\u1E41 dehabh\u0101vena \u096523\u0965</p><p>\u041A\u0430\u043A <em>(iva)</em> \u0448\u0435\u043B\u0443\u0445\u0430 <em>(tu\u1E63a\u1E25)</em> \u043F\u043E\u043A\u0440\u044B\u0432\u0430\u0435\u0442 <em>(\u0101v\u1E5B\u1E47ute)</em> \u0437\u0435\u0440\u043D\u043E \u0440\u0438\u0441\u0430 <em>(ta\u1E47\u1E0Dula-ka\u1E47ik\u0101m)</em>, \u0442\u0430\u043A <em>(ayam)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(sarga\u1E25)</em> \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0449\u0435\u0435\u0441\u044F \u0441 \u041F\u0440\u0430\u043A\u0440\u0438\u0442\u0438 <em>(prak\u1E5Bti-p\u016Brvaka\u1E25)</em> [\u0438] \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044E\u0449\u0435\u0435\u0441\u044F <em>(paryanta\u1E25)</em> \u0437\u0435\u043C\u043B\u0451\u0439 <em>(p\u1E5Bthv\u012B)</em> \u043D\u0430\u0434\u0435\u043B\u044F\u0435\u0442 <em>(bh\u0101vena)</em> \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(caitanyam)</em> \u0442\u0435\u043B\u043E\u043C <em>(deha)</em>.</p><p class="eng">This <em>(ayam)</em> Prak\u1E5Bti-related <em>(prak\u1E5Bti-p\u016Brvaka\u1E25)</em> emission [of tattva-s or categories] <em>(sarga\u1E25)</em> that ends in _(paryanta\u1E25)_P\u1E5Bthv\u012B \u2013also known as P\u1E5Bthiv\u012B or Earth, the last tattva\u2013 <em>(p\u1E5Bthv\u012B)</em> covers <em>(\u0101v\u1E5B\u1E47ute)</em> Caitanya \u2013Consciousness endowed with Absolute Freedom\u2013 <em>(caitanyam)</em> with the state <em>(bh\u0101vena)</em> of deha or physical body <em>(deha)</em> in the same way as _(iva)_the hull or husk <em>(tu\u1E63a\u1E25)</em> [covers] a little rice-grain _(ta\u1E47\u1E0Dula-ka\u1E47ik\u0101m)_</p></div><div class="stanza"><a href="#s24" id="s24" class="num">24</a><p class="sans">\u092A\u0930\u092E\u093E\u0935\u0930\u0923\u0902 \u092E\u0932 \u0907\u0939 \u0938\u0942\u0915\u094D\u0937\u094D\u092E\u0902 \u092E\u093E\u092F\u093E\u0926\u093F \u0915\u091E\u094D\u091A\u0941\u0915\u0902 \u0938\u094D\u0925\u0942\u0932\u092E\u094D \u0964<br> \u092C\u093E\u0939\u094D\u092F\u0902 \u0935\u093F\u0917\u094D\u0930\u0939\u0930\u0942\u092A\u0902 \u0915\u094B\u0936\u0924\u094D\u0930\u092F\u0935\u0947\u0937\u094D\u091F\u093F\u0924\u094B \u0939\u094D\u092F\u093E\u0924\u094D\u092E\u093E \u0965\u0968\u096A\u0965</p><p class="trans">Param\u0101vara\u1E47a\u1E41 mala iha s\u016Bk\u1E63ma\u1E41 m\u0101y\u0101di ka\xF1cuka\u1E41 sth\u016Blam \u0964<br> B\u0101hya\u1E41 vigrahar\u016Bpa\u1E41 ko\u015Batrayave\u1E63\u1E6Dito hy\u0101tm\u0101 \u096524\u0965</p><p>\u041F\u0435\u0440\u0432\u0438\u0447\u043D\u043E\u0435 \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435 <em>(mala\u1E25)</em> [\u0435\u0441\u0442\u044C] \u0442\u043E\u043D\u0447\u0430\u0439\u0448\u0430\u044F <em>(param)</em> \u043E\u0431\u043E\u043B\u043E\u0447\u043A\u0430 <em>[\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F]</em> <em>(\u0101vara\u1E47am)</em>. \u0422\u043E\u043D\u043A\u0430\u044F <em>[\u043E\u0431\u043E\u043B\u043E\u0447\u043A\u0430]</em> <em>(s\u016Bk\u1E63mam)</em> [\u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u0430] \u041C\u0430\u0439\u0435\u0439 \u0438 \u043F\u0440\u043E\u0447\u0438\u043C\u0438 <em>(m\u0101y\u0101-\u0101di)</em> \u043A\u0430\u043D\u0447\u0443\u043A\u0430\u043C\u0438 <em>(ka\xF1cukam)</em>. \u0413\u0440\u0443\u0431\u0430\u044F <em>(sth\u016Blam)</em> [\u043E\u0431\u043E\u043B\u043E\u0447\u043A\u0430] \u2014 \u0432\u043D\u0435\u0448\u043D\u044F\u044F <em>(b\u0101hyam)</em> \u0442\u0435\u043B\u0435\u0441\u043D\u0430\u044F \u0444\u043E\u0440\u043C\u0430 <em>(vigraha-r\u016Bpam)</em>. \u0422\u0430\u043A\u043E\u0432\u044B <em>(iha)</em> \u0442\u0440\u0438 <em>(traya)</em> \u043F\u043E\u043A\u0440\u043E\u0432\u0430 <em>(ko\u015Ba)</em>, \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E <em>(hi)</em> \u043E\u043A\u0443\u0442\u044B\u0432\u0430\u044E\u0449\u0438\u0435 <em>(ve\u1E63\u1E6Dita\u1E25)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0435 \xAB\u042F\xBB <em>(\u0101tm\u0101)</em>.</p><p class="eng">The Self <em>(\u0101tm\u0101)</em> [is] here <em>(iha)</em> certainly <em>(hi)</em> enveloped <em>(ve\u1E63\u1E6Dita\u1E25)</em> by three <em>(traya)</em> coverings <em>(ko\u015Ba)</em>: [1] The impurity <em>(mala\u1E25)</em> that is the supreme <em>(param)</em> Veil <em>(\u0101vara\u1E47am)</em>, [2] the subtle <em>(s\u016Bk\u1E63mam)</em> Sheath <em>(ka\xF1cukam)</em> composed of M\u0101y\u0101, etc. <em>(m\u0101y\u0101-\u0101di)</em> [and] [3] the gross <em>(sth\u016Blam)</em> [and] external <em>(b\u0101hyam)</em> bodily form <em>(vigraha-r\u016Bpam)</em></p></div><div class="stanza"><a href="#s25" id="s25" class="num">25</a><p class="sans">\u0905\u091C\u094D\u091E\u093E\u0928\u0924\u093F\u092E\u093F\u0930\u092F\u094B\u0917\u093E\u0926\u0947\u0915\u092E\u092A\u093F \u0938\u094D\u0935\u0902 \u0938\u094D\u0935\u092D\u093E\u0935\u092E\u093E\u0924\u094D\u092E\u093E\u0928\u092E\u094D \u0964<br> \u0917\u094D\u0930\u093E\u0939\u094D\u092F\u0917\u094D\u0930\u093E\u0939\u0915\u0928\u093E\u0928\u093E\u0935\u0948\u091A\u093F\u0924\u094D\u0930\u094D\u092F\u0947\u0923\u093E\u0935\u092C\u0941\u0927\u094D\u092F\u0947\u0924 \u0965\u0968\u096B\u0965</p><p class="trans">Aj\xF1\u0101natimirayog\u0101dekamapi sva\u1E41 svabh\u0101vam\u0101tm\u0101nam \u0964<br> Gr\u0101hyagr\u0101hakan\u0101n\u0101vaicitrye\u1E47\u0101vabudhyeta \u096525\u0965</p><p>[\u042D\u0442\u043E \xAB\u042F\xBB] \u0445\u043E\u0442\u044C \u0438 <em>(api)</em> \u0435\u0434\u0438\u043D\u043E\u0435 <em>(ekam)</em>, \u043F\u043E\u0433\u0440\u0443\u0436\u0430\u044F\u0441\u044C <em>(yog\u0101t)</em> \u0432\u043E \u0442\u044C\u043C\u0443 <em>(timira)</em> \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u044F <em>(aj\xF1\u0101na)</em>, \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 <em>(avabudhyeta)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(sva-bh\u0101vam)</em> \u0441\u0432\u043E\u0435\u0439 <em>(svam)</em> \u0434\u0443\u0448\u0438 <em>(\u0101tm\u0101nam)</em> \u043A\u0430\u043A \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u043E\u0435 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E <em>(n\u0101n\u0101-vaicitrye\u1E47a)</em> \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(gr\u0101haka)</em> [\u0438] \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 <em>(gr\u0101hya)</em>.</p><p class="eng">[This Self,] though <em>(api)</em> one <em>(ekam)</em>, on account of [His] contact <em>(yog\u0101t)</em> with the darkness <em>(timira)</em> of ignorance <em>(aj\xF1\u0101na)</em>, knows or perceive <em>(avabudhyeta)</em> Himself <em>(\u0101tm\u0101nam)</em> \u2014His own <em>(svam)</em> essential nature <em>(sva-bh\u0101vam)</em>\u2014 as the multiple variety <em>(n\u0101n\u0101-vaicitrye\u1E47a)</em> of subjects <em>(gr\u0101haka)</em> [and] objects <em>(gr\u0101hya)</em></p></div><div class="stanza"><a href="#s26" id="s26" class="num">26</a><p class="sans">\u0930\u0938\u092B\u093E\u0923\u093F\u0924\u0936\u0930\u094D\u0915\u0930\u093F\u0915\u093E\u0917\u0941\u0921\u0916\u0923\u094D\u0921\u093E\u0926\u094D\u092F\u093E \u092F\u0925\u0947\u0915\u094D\u0937\u0941\u0930\u0938 \u090F\u0935 \u0964<br> \u0924\u0926\u094D\u0935\u0926\u0935\u0938\u094D\u0925\u093E\u092D\u0947\u0926\u093E\u0903 \u0938\u0930\u094D\u0935\u0947 \u092A\u0930\u092E\u093E\u0924\u094D\u092E\u0928\u0903 \u0936\u092E\u094D\u092D\u094B\u0903 \u0965\u0968\u096C\u0965</p><p class="trans">Rasaph\u0101\u1E47ita\u015Barkarik\u0101gu\u1E0Dakha\u1E47\u1E0D\u0101dy\u0101 yathek\u1E63urasa eva \u0964<br> Tadvadavasth\u0101bhed\u0101\u1E25 sarve param\u0101tmana\u1E25 \u015Bambho\u1E25 \u096526\u0965</p><p>\u0420\u043E\u0432\u043D\u043E \u043A\u0430\u043A <em>(yath\u0101)</em> \u0441\u043B\u0430\u0434\u043A\u0438\u0439 \u0441\u043E\u043A <em>(rasa)</em>, \u0441\u0430\u0445\u0430\u0440-\u0441\u044B\u0440\u0435\u0446 <em>(ph\u0101\u1E47ita)</em>, \u043E\u0447\u0438\u0449\u0435\u043D\u043D\u044B\u0439 \u0441\u0430\u0445\u0430\u0440 <em>(\u015Barkarik\u0101)</em>, \u043F\u0430\u0442\u043E\u043A\u0430 <em>(gu\u1E0Da)</em>, \u043A\u0430\u0440\u0430\u043C\u0435\u043B\u044C <em>(kha\u1E47\u1E0Da)</em> \u0438 \u043F\u0440\u043E\u0447\u0438\u0435 <em>(\u0101dy\u0101\u1E25)</em> <em>\u2014</em> [\u0441\u0443\u0442\u044C] \u043B\u0438\u0448\u044C <em>(eva)</em> \u0441\u043E\u043A <em>(rasa)</em> \u0441\u0430\u0445\u0430\u0440\u043D\u043E\u0433\u043E \u0442\u0440\u043E\u0441\u0442\u043D\u0438\u043A\u0430 <em>(ik\u1E63u)</em>, \u0442\u0430\u043A\u0436\u0435 \u0438 <em>(tadvad)</em> \u0432\u0441\u0435 <em>(sarve)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bhed\u0101\u1E25)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(avasth\u0101)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \xAB\u042F\xBB <em>(parama-\u0101tmana\u1E25)</em> \u2014 [\u0441\u0443\u0442\u044C] \u0428\u0430\u043C\u0431\u0445\u0443 <em>(\u015Bambho\u1E25)</em>.</p><p class="eng">Just as <em>(yath\u0101)</em> juice of the sugar-cane <em>(rasa)</em>, jaggery <em>(ph\u0101\u1E47ita)</em>, refined sugar <em>(\u015Barkarik\u0101)</em>, molasses <em>(gu\u1E0Da)</em>, candied sugar <em>(kha\u1E47\u1E0Da)</em>, etc. <em>(\u0101dy\u0101\u1E25)</em> [are] only <em>(eva)</em> [the very] juice <em>(rasa)</em> of the sugar-cane <em>(ik\u1E63u)</em>, in the same way <em>(tadvad)</em>, all <em>(sarve)</em> the varieties <em>(bhed\u0101\u1E25)</em> of states <em>(avasth\u0101)</em> [are] of \u015Aambhu <em>(\u015Bambho\u1E25)</em>, the Supreme Self <em>(parama-\u0101tmana\u1E25)</em></p></div><div class="stanza"><a href="#s27" id="s27" class="num">27</a><p class="sans">\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u093E\u0928\u094D\u0924\u0930\u094D\u092F\u093E\u092E\u093F\u092A\u094D\u0930\u093E\u0923\u0935\u093F\u0930\u093E\u0921\u094D\u0926\u0947\u0939\u091C\u093E\u0924\u093F\u092A\u093F\u0923\u094D\u0921\u093E\u0928\u094D\u0924\u093E\u0903 \u0964<br> \u0935\u094D\u092F\u0935\u0939\u093E\u0930\u092E\u093E\u0924\u094D\u0930\u092E\u0947\u0924\u0924\u094D \u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0947\u0928 \u0924\u0941 \u0928 \u0938\u0928\u094D\u0924\u094D\u092F\u0947\u0935 \u0965\u0968\u096D\u0965</p><p class="trans">Vij\xF1\u0101n\u0101ntary\u0101mipr\u0101\u1E47avir\u0101\u1E0Ddehaj\u0101tipi\u1E47\u1E0D\u0101nt\u0101\u1E25 \u0964<br> Vyavah\u0101ram\u0101trametat param\u0101rthena tu na santyeva \u096527\u0965</p><p>\u041E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0435 \u0441\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(ant\u0101\u1E25)</em> [\u0432\u0440\u043E\u0434\u0435] \u201C\u043F\u043E\u0442\u043E\u043A \u043E\u0434\u043D\u043E\u043C\u043E\u043C\u0435\u043D\u0442\u043D\u043E\u0433\u043E \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F\u201D <em>(vij\xF1\u0101na)</em>, \u201C\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0439 \u043F\u0440\u0430\u0432\u0438\u0442\u0435\u043B\u044C\u201D <em>(antar-y\u0101mi)</em>, \u201C\u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F\u201D <em>(pr\u0101\u1E47a)</em>, \u201C\u043A\u043E\u0441\u043C\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0442\u0435\u043B\u043E\u201D <em>(vir\u0101\u1E6D-deha)</em>, \u201C\u0443\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u0438\u0438\u201D <em>(j\u0101ti)</em> [\u0438] \u201C\u0438\u043D\u0434\u0438\u0432\u0438\u0434\u044B\u201D <em>(pi\u1E47\u1E0Da)</em> \u2014 \u044D\u0442\u043E <em>(etad)</em> \u043B\u0438\u0448\u044C <em>(m\u0101tram)</em> \u0443\u0441\u043B\u043E\u0432\u043D\u043E\u0441\u0442\u0438 <em>(vyavah\u0101ra)</em> \u043F\u0440\u0438 \u044D\u0442\u043E\u043C <em>(tu)</em> \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(parama-arthena)</em> \u043D\u0435 <em>(na)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 <em>(santi)</em> \u0432\u043E\u0432\u0441\u0435 <em>(eva)</em>.</p><p class="eng">Definite ascertainments <em>(ant\u0101\u1E25)</em> [such as:] \u201CConsciousness as a stream\u201D <em>(vij\xF1\u0101na)</em>, \u201Cthe Indweller\u201D <em>(antar-y\u0101mi)</em>, \u201Cthe vital energy\u201D <em>(pr\u0101\u1E47a)</em>, \u201Cthe One whose Body is the macrocosm\u201D <em>(vir\u0101\u1E6D-deha)</em>, \u201Cthe Universal\u201D <em>(j\u0101ti)</em> [and] \u201Cthe Individuals\u201D <em>(pi\u1E47\u1E0Da)</em>\u2026 this <em>(etad)</em> [is] only <em>(m\u0101tram)</em> empirical discourse \u2013a mere conventionality\u2013 <em>(vyavah\u0101ra)</em>\u2026 nonetheless <em>(tu)</em>, [all those things] do not <em>(na)</em> really <em>(parama-arthena)</em> exist <em>(santi)</em> at all <em>(eva)</em>!</p></div><div class="stanza"><a href="#s28" id="s28" class="num">28</a><p class="sans">\u0930\u091C\u094D\u091C\u094D\u0935\u093E\u0902 \u0928\u093E\u0938\u094D\u0924\u093F \u092D\u0941\u091C\u0919\u094D\u0917\u0938\u094D\u0924\u094D\u0930\u093E\u0938\u0902 \u0915\u0941\u0930\u0941\u0924\u0947 \u091A \u092E\u0943\u0924\u094D\u092F\u0941\u092A\u0930\u094D\u092F\u0928\u094D\u0924\u092E\u094D \u0964<br> \u092D\u094D\u0930\u093E\u0928\u094D\u0924\u0947\u0930\u094D\u092E\u0939\u0924\u0940 \u0936\u0915\u094D\u0924\u093F\u0930\u094D\u0928 \u0935\u093F\u0935\u0947\u0915\u094D\u0924\u0941\u0902 \u0936\u0915\u094D\u092F\u0924\u0947 \u0928\u093E\u092E \u0965\u0968\u096E\u0965</p><p class="trans">Rajjv\u0101\u1E41 n\u0101sti bhuja\u1E45gastr\u0101sa\u1E41 kurute ca m\u1E5Btyuparyantam \u0964<br> Bhr\u0101ntermahat\u012B \u015Baktirna vivektu\u1E41 \u015Bakyate n\u0101ma \u096528\u0965</p><p>\u0412\u0435\u0440\u0451\u0432\u043A\u0430 <em>(rajjv\u0101m),</em> \u043D\u0435 <em>(na)</em> \u044F\u0432\u043B\u044F\u044E\u0449\u0430\u044F\u0441\u044F <em>(asti)</em> \u0437\u043C\u0435\u0451\u0439 <em>(bhuja\u1E45ga\u1E25)</em>, \u043C\u043E\u0436\u0435\u0442 \u043D\u0430\u043F\u0443\u0433\u0430\u0442\u044C <em>(tr\u0101sam kurute)</em> \u0445\u043E\u0442\u044C <em>(ca)</em> \u0432\u043F\u043B\u043E\u0442\u044C \u0434\u043E \u0441\u043C\u0435\u0440\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u0438\u0441\u0445\u043E\u0434\u0430 <em>(m\u1E5Btyu-paryantam)</em>. \u0412\u0435\u043B\u0438\u043A\u0430\u044F <em>(mahat\u012B)</em> \u0441\u0438\u043B\u0430 <em>(\u015Bakti\u1E25)</em> \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(bhr\u0101nte\u1E25)</em> \u0432\u043E\u0438\u0441\u0442\u0438\u043D\u0443 <em>(n\u0101ma)</em> \u043D\u0435\u043E\u0431\u044A\u044F\u0441\u043D\u0438\u043C\u0430 <em>(na vivektum \u015Bakyate)</em>!</p><p class="eng">A snake <em>(bhuja\u1E45ga\u1E25)</em> does not <em>(na)</em> exist <em>(asti)</em> in a rope <em>(rajjv\u0101m)</em>, yet <em>(ca)</em> it \u2013the rope being mistaken for a snake\u2013 terrifies <em>(tr\u0101sam kurute)</em> to death <em>(m\u1E5Btyu-paryantam)</em>. The great <em>(mahat\u012B)</em> power <em>(\u015Bakti\u1E25)</em> of confusion <em>(bhr\u0101nte\u1E25)</em> cannot be discerned <em>(na vivektum \u015Bakyate)</em> indeed <em>(n\u0101ma)</em>!</p></div><div class="stanza"><a href="#s29" id="s29" class="num">29</a><p class="sans">\u0924\u0926\u094D\u0935\u0926\u094D\u0927\u0930\u094D\u092E\u093E\u0927\u0930\u094D\u092E\u0938\u094D\u0935\u0930\u094D\u0928\u093F\u0930\u092F\u094B\u0924\u094D\u092A\u0924\u094D\u0924\u093F\u092E\u0930\u0923\u0938\u0941\u0916\u0926\u0941\u0903\u0916\u092E\u094D \u0964<br> \u0935\u0930\u094D\u0923\u093E\u0936\u094D\u0930\u092E\u093E\u0926\u093F \u091A\u093E\u0924\u094D\u092E\u0928\u094D\u092F\u0938\u0926\u092A\u093F \u0935\u093F\u092D\u094D\u0930\u092E\u092C\u0932\u093E\u0926\u094D\u092D\u0935\u0924\u093F \u0965\u0968\u096F\u0965</p><p class="trans">Tadvaddharm\u0101dharmasvarnirayotpattimara\u1E47asukhadu\u1E25kham \u0964<br> Var\u1E47\u0101\u015Bram\u0101di c\u0101tmanyasadapi vibhramabal\u0101dbhavati \u096529\u0965</p><p>\u0422\u0430\u043A \u0436\u0435 \u0438 <em>(tadvat)</em>, \u0431\u043B\u0430\u0433\u043E\u0447\u0435\u0441\u0442\u0438\u0435 <em>(dharma)</em> [\u0438] \u0433\u0440\u0435\u0445 <em>(adharma)</em>, \u0440\u0430\u0439 <em>(svar)</em> [\u0438] \u0430\u0434 <em>(niraya)</em>, \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435 <em>(utpatti)</em> [\u0438] \u0441\u043C\u0435\u0440\u0442\u044C <em>(mara\u1E47a)</em>, \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435 <em>(sukham)</em> [\u0438] \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0435 <em>(du\u1E25kham)</em>, \u0430 \u0442\u0430\u043A\u0436\u0435 <em>(ca)</em> \u043A\u0430\u0441\u0442\u044B <em>(var\u1E47a)</em>, \u0441\u0442\u0430\u0434\u0438\u0438 \u0436\u0438\u0437\u043D\u0438 <em>(\u0101\u015Brama)</em> \u0438 \u043F\u0440\u043E\u0447\u0435\u0435 <em>(\u0101di)</em>, \u0445\u043E\u0442\u044F \u0438 <em>(api)</em> \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 <em>(asat)</em> \u0434\u043B\u044F \u0412\u044B\u0441\u0448\u0435\u0433\u043E \xAB\u042F\xBB <em>(\u0101tmani)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F <em>(bhavati)</em> \u0441\u0438\u043B\u043E\u0439 <em>(bal\u0101t)</em> \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(vibhrama)</em>.</p><p class="eng">Likewise <em>(tadvat)</em>, [the group composed of] what is to be done <em>(dharma)</em>, what is not to be done <em>(adharma)</em>, heaven <em>(svar)</em>, hell <em>(niraya)</em>, birth <em>(utpatti)</em>, death <em>(mara\u1E47a)</em>, pleasure <em>(sukham)</em>, pain <em>(du\u1E25kham)</em>, together with <em>(ca)</em> castes <em>(var\u1E47a)</em>, stages of life <em>(\u0101\u015Brama)</em>, etc. <em>(\u0101di)</em>, though <em>(api)</em> non-existent <em>(asat)</em> in the Self <em>(\u0101tmani)</em>, arises <em>(bhavati)</em> in virtue of <em>(bal\u0101t)</em> confusion <em>(vibhrama)</em>.</p></div><div class="stanza"><a href="#s30" id="s30" class="num">30</a><p class="sans">\u090F\u0924\u0924\u094D\u0924\u0926\u0928\u094D\u0927\u0915\u093E\u0930\u0902 \u092F\u0926\u094D\u092D\u093E\u0935\u0947\u0937\u0941 \u092A\u094D\u0930\u0915\u093E\u0936\u092E\u093E\u0928\u0924\u092F\u093E \u0964<br> \u0906\u0924\u094D\u092E\u093E\u0928\u0924\u093F\u0930\u093F\u0915\u094D\u0924\u0947\u0937\u094D\u0935\u092A\u093F \u092D\u0935\u0924\u094D\u092F\u0928\u093E\u0924\u094D\u092E\u093E\u092D\u093F\u092E\u093E\u0928\u094B\u093D\u092F\u092E\u094D \u0965\u0969\u0966\u0965</p><p class="trans">Etattadandhak\u0101ra\u1E41 yadbh\u0101ve\u1E63u prak\u0101\u015Bam\u0101natay\u0101 \u0964<br> \u0100tm\u0101natirikte\u1E63vapi bhavatyan\u0101tm\u0101bhim\u0101no\u2019yam \u096530\u0965</p><p>\u042D\u0442\u043E \u0442\u0430 <em>(etad tad)</em> \u0442\u044C\u043C\u0430 <em>(andhak\u0101ram)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F <em>(yad)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u0432 \u0441\u0432\u0435\u0442\u043E\u043D\u043E\u0441\u043D\u044B\u0445 <em>(prak\u0101\u015Bam\u0101natay\u0101)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430\u0445 <em>(bh\u0101ve\u1E63u)</em> \u043D\u0435\u043E\u0442\u0434\u0435\u043B\u0438\u043C\u044B\u0445 <em>(anatirikte\u1E63u)</em> [\u043E\u0442] \u0412\u044B\u0441\u0448\u0435\u0433\u043E \xAB\u042F\xBB <em>(\u0101tma)</em>, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(bhavati)</em> \u044D\u0442\u043E\u0439 <em>(ayam)</em> \u043E\u0448\u0438\u0431\u043E\u0447\u043D\u043E\u0439 \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u0435\u0439 <em>(abhim\u0101na\u1E25)</em> \u043E \u201C\u043D\u0435-\u042F\u201D <em>(an-\u0101tma)</em>.</p><p class="eng">This very <em>(etad tad)</em> darkness <em>(andhak\u0101ram)</em> which <em>(yad)</em> appears <em>(prak\u0101\u015Bam\u0101natay\u0101)</em> in the positive entities \u2013subjects and objects\u2013 <em>(bh\u0101ve\u1E63u)</em> becomes <em>(bhavati)</em> this <em>(ayam)</em> erroneous conception <em>(abhim\u0101na\u1E25)</em> about the not-Self _(an-\u0101tma)_even <em>(api)</em> in [such positive entities] that are not different from <em>(anatirikte\u1E63u)</em>the Self _(\u0101tma)_</p></div><div class="stanza"><a href="#s31" id="s31" class="num">31</a><p class="sans">\u0924\u093F\u092E\u093F\u0930\u093E\u0926\u092A\u093F \u0924\u093F\u092E\u093F\u0930\u092E\u093F\u0926\u0902 \u0917\u0923\u094D\u0921\u0938\u094D\u092F\u094B\u092A\u0930\u093F \u092E\u0939\u093E\u0928\u092F\u0902 \u0938\u094D\u092B\u094B\u091F\u0903 \u0964<br> \u092F\u0926\u0928\u093E\u0924\u094D\u092E\u0928\u094D\u092F\u092A\u093F \u0926\u0947\u0939\u092A\u094D\u0930\u093E\u0923\u093E\u0926\u093E\u0935\u093E\u0924\u094D\u092E\u092E\u093E\u0928\u093F\u0924\u094D\u0935\u092E\u094D \u0965\u0969\u0967\u0965</p><p class="trans">Timir\u0101dapi timiramida\u1E41 ga\u1E47\u1E0Dasyopari mah\u0101naya\u1E41 spho\u1E6Da\u1E25 \u0964<br> Yadan\u0101tmanyapi dehapr\u0101\u1E47\u0101d\u0101v\u0101tmam\u0101nitvam \u096531\u0965</p><p>\u0414\u0430\u0436\u0435 <em>(api)</em> \u0432\u043E \u0442\u044C\u043C\u0435 <em>(timir\u0101t)</em> \u044D\u0442\u043E <em>(idam)</em> \u0442\u044C\u043C\u0430 <em>(timiram)</em>, [\u043A\u0430\u043A] \u0431\u043E\u043B\u044C\u0448\u0430\u044F \u043D\u0435\u0443\u0434\u0430\u0447\u0430 <em>(mah\u0101-anayam)</em> [\u0438\u043C\u0435\u0442\u044C] \u043E\u0436\u043E\u0433 <em>(spho\u1E6Da\u1E25)</em> \u043D\u0430 <em>(upari)</em> \u043D\u0430\u0440\u044B\u0432\u0435 <em>(ga\u1E47\u1E0Dasya)</em>, \u043A\u043E\u0433\u0434\u0430 <em>(yad)</em> \u044D\u0442\u043E \u201C\u043D\u0435-\u042F\u201D <em>(an-\u0101tmani api)</em> \u0442.\u0435. \u0442\u0435\u043B\u043E, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0443\u044E \u044D\u043D\u0435\u0440\u0433\u0438\u044E \u0438 \u043F\u0440\u043E\u0447\u0435\u0435 <em>(deha-pr\u0101\u1E47a-\u0101dau)</em> \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0442 \u0437\u0430 <em>(m\u0101nitvam)</em> \xAB\u042F\xBB <em>(\u0101tma)</em>.</p><p class="eng">This <em>(idam)</em> darkness <em>(timiram)</em> [arising] even <em>(api)</em> from darkness <em>(timir\u0101t)</em>, which <em>(yad)</em> [consists in] thinking <em>(m\u0101nitvam)</em> that the not-Self <em>(an-\u0101tmani api)</em> \u2014e.g. body, vital energy, etc. <em>(deha-pr\u0101\u1E47a-\u0101dau)</em>\u2014 is the Self <em>(\u0101tma)</em>, [may be compared to] the great misfortune <em>(mah\u0101-anayam)</em> [of having] a blister <em>(spho\u1E6Da\u1E25)</em> on <em>(upari)</em> a boil <em>(ga\u1E47\u1E0Dasya)</em></p></div><div class="stanza"><a href="#s32" id="s32" class="num">32</a><p class="sans">\u0926\u0947\u0939\u092A\u094D\u0930\u093E\u0923\u0935\u093F\u092E\u0930\u094D\u0936\u0928\u0927\u0940\u091C\u094D\u091E\u093E\u0928\u0928\u092D\u0903\u092A\u094D\u0930\u092A\u091E\u094D\u091A\u092F\u094B\u0917\u0947\u0928 \u0964<br> \u0906\u0924\u094D\u092E\u093E\u0928\u0902 \u0935\u0947\u0937\u094D\u091F\u092F\u0924\u0947 \u091A\u093F\u0924\u094D\u0930\u0902 \u091C\u093E\u0932\u0947\u0928 \u091C\u093E\u0932\u0915\u093E\u0930 \u0907\u0935 \u0965\u0969\u0968\u0965</p><p class="trans">Dehapr\u0101\u1E47avimar\u015Banadh\u012Bj\xF1\u0101nanabha\u1E25prapa\xF1cayogena \u0964<br> \u0100tm\u0101na\u1E41 ve\u1E63\u1E6Dayate citra\u1E41 j\u0101lena j\u0101lak\u0101ra iva \u096532\u0965</p><p>\u041E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u044F\u044F\u0441\u044C <em>(vimar\u015Bana)</em> [\u0441] \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u0442\u0435\u043B\u043E\u043C <em>(deha)</em> [\u0438] \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439 <em>(pr\u0101\u1E47a)</em> \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E <em>(yogena)</em> \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0443\u0430\u043B\u044C\u043D\u044B\u0445 \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u0439 <em>(dh\u012B-j\xF1\u0101na)</em> \u0438 \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u044F <em>(prapa\xF1ca)</em> \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0435\u0433\u043E \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430 <em>(nabhas)</em>, \u0412\u044B\u0441\u0448\u0435\u0435 \xAB\u042F\xBB <em>(\u0101tm\u0101nam)</em> \u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(citram)</em> \u043E\u043A\u0443\u0442\u044B\u0432\u0430\u0435\u0442 \u0441\u0435\u0431\u044F <em>(ve\u1E63\u1E6Dayate)</em> \u043A\u0430\u043A <em>(iva)</em> \u043F\u0430\u0443\u043A <em>(j\u0101lak\u0101ra\u1E25)</em> \u043F\u0430\u0443\u0442\u0438\u043D\u043E\u0439 <em>(j\u0101lena)</em>.</p><p class="eng">By means of <em>(yogena)</em> the act of considering [that he is] <em>(vimar\u015Bana)</em> physical body <em>(deha)</em> [and] vital energy <em>(pr\u0101\u1E47a)</em>,[by] the intellectual knowledge <em>(dh\u012B-j\xF1\u0101na)</em> [and through] the expansion <em>(prapa\xF1ca)</em> of the ethers <em>(nabhas)</em>, [the limited individual] wraps himself up <em>(\u0101tm\u0101nam ve\u1E63\u1E6Dayate)</em> astonishingly <em>(citram)</em> like <em>(iva)</em> a spider <em>(j\u0101lak\u0101ra\u1E25)</em> with [its] web <em>(j\u0101lena)</em></p></div><div class="stanza"><a href="#s33" id="s33" class="num">33</a><p class="sans">\u0938\u094D\u0935\u091C\u094D\u091E\u093E\u0928\u0935\u093F\u092D\u0935\u092D\u093E\u0938\u0928\u092F\u094B\u0917\u0947\u0928\u094B\u0926\u094D\u0935\u0947\u0937\u094D\u091F\u092F\u0947\u0928\u094D\u0928\u093F\u091C\u093E\u0924\u094D\u092E\u093E\u0928\u092E\u094D \u0964<br> \u0907\u0924\u093F \u092C\u0928\u094D\u0927\u092E\u094B\u0915\u094D\u0937\u091A\u093F\u0924\u094D\u0930\u093E\u0902 \u0915\u094D\u0930\u0940\u0921\u093E\u0902 \u092A\u094D\u0930\u0924\u0928\u094B\u0924\u093F \u092A\u0930\u092E\u0936\u093F\u0935\u0903 \u0965\u0969\u0969\u0965</p><p class="trans">Svaj\xF1\u0101navibhavabh\u0101sanayogenodve\u1E63\u1E6Dayennij\u0101tm\u0101nam \u0964<br> Iti bandhamok\u1E63acitr\u0101\u1E41 kr\u012B\u1E0D\u0101\u1E41 pratanoti parama\u015Biva\u1E25 \u096533\u0965</p><p>\u0412\u044B\u0441\u0448\u0438\u0439 \u0428\u0438\u0432\u0430 <em>(parama-\u015Biva\u1E25)</em> \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E <em>(yogena)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(bh\u0101sana)</em> \u0441\u0438\u044F\u043D\u0438\u044F <em>(vibhava)</em> \u0441\u0430\u043C\u043E\u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(sva-j\xF1\u0101na)</em> \u0440\u0430\u0441\u043F\u043B\u0435\u0442\u0430\u0435\u0442 <em>(udve\u1E63\u1E6Dayet)</em> \u0441\u0430\u043C \u0441\u0435\u0431\u044F <em>(nija-\u0101tm\u0101nam)</em>, \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(iti)</em> \u043E\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043B\u044F\u044F <em>(pratanoti)</em> \u0438\u0433\u0440\u0443 <em>(kr\u012B\u1E0D\u0101m)</em> \u0438\u043B\u043B\u044E\u0437\u043E\u0440\u043D\u043E\u0433\u043E <em>(citr\u0101m)</em> \u0441\u0432\u044F\u0437\u044B\u0432\u0430\u043D\u0438\u044F \u0438 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(bandha-mok\u1E63a)</em>.</p><p class="eng">The Supreme \u015Aiva <em>(parama-\u015Biva\u1E25)</em> untwists <em>(udve\u1E63\u1E6Dayet)</em> Himself <em>(nija-\u0101tm\u0101nam)</em> by constant concentration <em>(yogena)</em> on the splendorous manifestation <em>(bh\u0101sana)</em> of the Glory <em>(vibhava)</em> of Knowledge <em>(j\xF1\u0101na)</em> of the Self <em>(sva)</em>. In this way <em>(iti)</em>, He displays <em>(pratanoti)</em> the wonderful <em>(citr\u0101m)</em> Play <em>(kr\u012B\u1E0D\u0101m)</em> of bondage and liberation <em>(bandha-mok\u1E63a)</em>[by twisting and untwisting Himself]</p></div><div class="stanza"><a href="#s34" id="s34" class="num">34</a><p class="sans">\u0938\u0943\u0937\u094D\u091F\u093F\u0938\u094D\u0925\u093F\u0924\u093F\u0938\u0902\u0939\u093E\u0930\u093E \u091C\u093E\u0917\u094D\u0930\u0924\u094D\u0938\u094D\u0935\u092A\u094D\u0928\u094C \u0938\u0941\u0937\u0941\u092A\u094D\u0924\u092E\u093F\u0924\u093F \u0924\u0938\u094D\u092E\u093F\u0928\u094D \u0964<br> \u092D\u093E\u0928\u094D\u0924\u093F \u0924\u0941\u0930\u0940\u092F\u0947 \u0927\u093E\u092E\u0928\u093F \u0924\u0925\u093E\u092A\u093F \u0924\u0948\u0930\u094D\u0928\u093E\u0935\u0943\u0924\u0902 \u092D\u093E\u0924\u093F \u0965\u0969\u096A\u0965</p><p class="trans">S\u1E5B\u1E63\u1E6Disthitisa\u1E41h\u0101r\u0101 j\u0101gratsvapnau su\u1E63uptamiti tasmin \u0964<br> Bh\u0101nti tur\u012Bye dh\u0101mani tath\u0101pi tairn\u0101v\u1E5Bta\u1E41 bh\u0101ti \u096534\u0965</p><p>\u0421\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435 \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(s\u1E5B\u1E63\u1E6Di-sthiti-sa\u1E41h\u0101r\u0101\u1E25)</em> \u2014 \u0441\u0443\u0442\u044C <em>(iti)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043E\u043D <em>(j\u0101grat-svapnau)</em> \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D <em>(su\u1E63uptam)</em>, \u0441\u0438\u044F\u044E\u0442 <em>(bh\u0101nti)</em> \u0432 \u0442\u043E\u043C <em>(tasmin)</em> \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(tur\u012Bye dh\u0101mani)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 <em>(tath\u0101)</em> \u0441\u0438\u044F\u0435\u0442 <em>(bh\u0101ti)</em> \u0432\u0441\u0451 \u0436\u0435 <em>(api)</em> \u043D\u0435 <em>(na)</em> \u0441\u043E\u043A\u0440\u044B\u0442\u043E\u0435 <em>(\u0101v\u1E5Btam)</em> \u0438\u043C\u0438 <em>(tai\u1E25)</em>.</p><p class="eng">Manifestation, maintenance and dissolution [of the universe] <em>(s\u1E5B\u1E63\u1E6Di-sthiti-sa\u1E41h\u0101r\u0101\u1E25)</em> [as well as] waking and dreaming <em>(j\u0101grat-svapnau)</em> [together with] deep sleep <em>(su\u1E63uptam iti)</em> exist <em>(bh\u0101nti)</em> in Him <em>(tasmin)</em> in the Fourth State <em>(tur\u012Bye dh\u0101mani)</em>, [but] even so <em>(tath\u0101 api)</em> He is not <em>(na\u2026 bh\u0101ti)</em> covered <em>(\u0101v\u1E5Btam)</em> by them <em>(tai\u1E25)</em>.</p></div><div class="stanza"><a href="#s35" id="s35" class="num">35</a><p class="sans">\u091C\u093E\u0917\u094D\u0930\u0926\u094D\u0935\u093F\u0936\u094D\u0935\u0902 \u092D\u0947\u0926\u093E\u0924\u094D\u0938\u094D\u0935\u092A\u094D\u0928\u0938\u094D\u0924\u0947\u091C\u0903 \u092A\u094D\u0930\u0915\u093E\u0936\u092E\u093E\u0939\u093E\u0924\u094D\u092E\u094D\u092F\u093E\u0924\u094D \u0964<br> \u092A\u094D\u0930\u093E\u091C\u094D\u091E\u0903 \u0938\u0941\u092A\u094D\u0924\u093E\u0935\u0938\u094D\u0925\u093E \u091C\u094D\u091E\u093E\u0928\u0918\u0928\u0924\u094D\u0935\u093E\u0924\u094D\u0924\u0924\u0903 \u092A\u0930\u0902 \u0924\u0941\u0930\u094D\u092F\u092E\u094D \u0965\u0969\u096B\u0965</p><p class="trans">J\u0101gradvi\u015Bva\u1E41 bhed\u0101tsvapnasteja\u1E25 prak\u0101\u015Bam\u0101h\u0101tmy\u0101t \u0964<br> Pr\u0101j\xF1a\u1E25 supt\u0101vasth\u0101 j\xF1\u0101naghanatv\u0101ttata\u1E25 para\u1E41 turyam \u096535\u0965</p><p>\u0411\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 <em>(j\u0101grat)</em> \u2014 \u043F\u043E\u043B\u043D\u043E\u0435 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0439 <em>(bhed\u0101t)</em> \u0411\u044B\u0442\u0438\u0435 <em>(vi\u015Bvam)</em>, \u0441\u043E\u043D \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 <em>(svapna\u1E25)</em> \u2014 \u0441\u0438\u044F\u043D\u0438\u0435 <em>(tejas)</em> \u0432\u0435\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(m\u0101h\u0101tmy\u0101t)</em> \u0441\u0432\u0435\u0442\u0430 <em>(prak\u0101\u015Ba)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(avasth\u0101)</em> \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430 <em>(supta)</em> \u2014 \u043C\u0443\u0434\u0440\u043E\u0441\u0442\u044C <em>(pr\u0101j\xF1a\u1E25)</em> \u0441\u0436\u0430\u0442\u043E\u0433\u043E <em>(ghanatv\u0101t)</em> \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na)</em>, \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(turyam)</em> \u2014 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0438\u0442 <em>(param)</em> \u0432\u0441\u0435 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 <em>(tatas)</em>.</p><p class="eng">Wakefulness <em>(j\u0101grat)</em> [is called] \u201Cvi\u015Bva\u201D \u2013lit. universe\u2013 <em>(vi\u015Bvam)</em> due to differentiation <em>(bhed\u0101t)</em>; dreaming <em>(svapna\u1E25)</em> [is known as both] \u201Ctejas\u201D \u2013lit. light\u2013 [and \u201Ctaijasa\u201D \u2013lit. consisting of light\u2013] <em>(tejas)</em> because of the exalted position <em>(m\u0101h\u0101tmy\u0101t)</em> of light <em>(prak\u0101\u015Ba)</em> <em>(here)</em>; the state <em>(avasth\u0101)</em> of deep sleep <em>(supta)</em> [is designated] \u201Cpr\u0101j\xF1a\u201D \u2013lit. intelligent\u2013 <em>(pr\u0101j\xF1a\u1E25)</em> on account of how massive <em>(ghanatv\u0101t)</em> knowledge <em>(j\xF1\u0101na)</em> [is during this state. Finally,] \u201CTurya\u201D or the Fourth One <em>(turyam)</em> [is] another <em>(param)</em> than that one \u2013it is even beyond deep sleep\u2013 <em>(tatas)</em> [also] on account of the massive state <em>(ghanatv\u0101t)</em> of Knowledge <em>(j\xF1\u0101na)</em>[present in this state]</p></div><div class="stanza"><a href="#s36" id="s36" class="num">36</a><p class="sans">\u091C\u0932\u0927\u0930\u0927\u0942\u092E\u0930\u091C\u094B\u092D\u093F\u0930\u094D\u092E\u0932\u093F\u0928\u0940\u0915\u094D\u0930\u093F\u092F\u0924\u0947 \u092F\u0925\u093E \u0928 \u0917\u0917\u0928\u0924\u0932\u092E\u094D \u0964<br> \u0924\u0926\u094D\u0935\u0928\u094D\u092E\u093E\u092F\u093E\u0935\u093F\u0915\u0943\u0924\u093F\u092D\u093F\u0930\u092A\u0930\u093E\u092E\u0943\u0937\u094D\u091F\u0903 \u092A\u0930\u0903 \u092A\u0941\u0930\u0941\u0937\u0903 \u0965\u0969\u096C\u0965</p><p class="trans">Jaladharadh\u016Bmarajobhirmalin\u012Bkriyate yath\u0101 na gaganatalam \u0964<br> Tadvanm\u0101y\u0101vik\u1E5Btibhirapar\u0101m\u1E5B\u1E63\u1E6Da\u1E25 para\u1E25 puru\u1E63a\u1E25 \u096536\u0965</p><p>\u041A\u0430\u043A <em>(yath\u0101)</em> \u043E\u0431\u043B\u0430\u043A\u0430, \u0434\u044B\u043C \u0438\u043B\u0438 \u043F\u044B\u043B\u044C <em>(jaladhara-dh\u016Bma-rajobhi\u1E25)</em> \u043D\u0435 <em>(na)</em> \u043F\u044F\u0442\u043D\u0430\u044E\u0442 <em>(malin\u012B-kriyate)</em> \u043D\u0435\u0431\u043E\u0441\u0432\u043E\u0434 <em>(gagana-talam)</em>, \u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435 <em>(tadvat)</em> \u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(vik\u1E5Btibhi\u1E25)</em> \u041C\u0430\u0439\u0438 <em>(m\u0101y\u0101)</em> \u043D\u0435 \u0437\u0430\u0442\u0440\u0430\u0433\u0438\u0432\u0430\u044E\u0442 <em>(apar\u0101m\u1E5B\u1E63\u1E6Da\u1E25)</em> \u0412\u044B\u0441\u0448\u0443\u044E <em>(para\u1E25)</em> \u041B\u0438\u0447\u043D\u043E\u0441\u0442\u044C <em>(puru\u1E63a\u1E25)</em>.</p><p class="eng">Just as <em>(yath\u0101)</em> the vault of the sky <em>(gagana-talam)</em> [is] not <em>(na)</em> stained <em>(malin\u012B-kriyate)</em> by clouds, smoke or dust <em>(jaladhara-dh\u016Bma-rajobhi\u1E25)</em>, in the same way <em>(tadvat)</em> the Supreme <em>(para\u1E25)</em> Person <em>(puru\u1E63a\u1E25)</em> is not touched <em>(apar\u0101m\u1E5B\u1E63\u1E6Da\u1E25)</em> by the modifications <em>(vik\u1E5Btibhi\u1E25)</em> of M\u0101y\u0101 <em>(m\u0101y\u0101)</em></p></div><div class="stanza"><a href="#s37" id="s37" class="num">37</a><p class="sans">\u090F\u0915\u0938\u094D\u092E\u093F\u0928\u094D\u0918\u091F\u0917\u0917\u0928\u0947 \u0930\u091C\u0938\u093E \u0935\u094D\u092F\u093E\u092A\u094D\u0924\u0947 \u092D\u0935\u0928\u094D\u0924\u093F \u0928\u093E\u0928\u094D\u092F\u093E\u0928\u093F \u0964<br> \u092E\u0932\u093F\u0928\u093E\u0928\u093F \u0924\u0926\u094D\u0935\u0926\u0947\u0924\u0947 \u091C\u0940\u0935\u093E\u0903 \u0938\u0941\u0916\u0926\u0941\u0903\u0916\u092D\u0947\u0926\u091C\u0941\u0937\u0903 \u0965\u0969\u096D\u0965</p><p class="trans">Ekasmingha\u1E6Dagagane rajas\u0101 vy\u0101pte bhavanti n\u0101ny\u0101ni \u0964<br> Malin\u0101ni tadvadete j\u012Bv\u0101\u1E25 sukhadu\u1E25khabhedaju\u1E63a\u1E25 \u096537\u0965</p><p>\u041D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u0442\u043E, \u0447\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E \u043E\u0434\u043D\u043E\u0433\u043E \u0433\u043E\u0440\u0448\u043A\u0430 \u0437\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043E <em>(ekasmin gha\u1E6Da-gagane\u2026 vy\u0101pte)</em> \u043F\u044B\u043B\u044C\u044E <em>(rajas\u0101)</em>, \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u0433\u043E\u0440\u0448\u043A\u0438 <em>(any\u0101ni)</em> \u043D\u0435 \u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F <em>(bhavanti na)</em> \u0433\u0440\u044F\u0437\u043D\u044B\u043C\u0438 <em>(malin\u0101ni)</em>. \u0422\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435 <em>(tadvat)</em> \u044D\u0442\u0438 <em>(ete)</em> \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u0435 \u0434\u0443\u0448\u0438 <em>(j\u012Bv\u0101\u1E25)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u043E <em>(bheda)</em> \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u044E\u0442 <em>(ju\u1E63a\u1E25)</em> \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u0435 <em>(sukha)</em> [\u0438] \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0435 <em>(du\u1E25kha)</em>.</p><p class="eng">Although the space in one pot is full <em>(ekasmin gha\u1E6Da-gagane\u2026 vy\u0101pte)</em> of dust <em>(rajas\u0101)</em>, the other [spaces in other pots] <em>(any\u0101ni)</em> are not <em>(bhavanti na)</em> dirty <em>(malin\u0101ni)</em>. The same thing happens \u2013lit. likewise\u2013 <em>(tadvat)</em> [in the case of] these <em>(ete)</em> conditioned beings <em>(j\u012Bv\u0101\u1E25)</em> who frequent <em>(ju\u1E63a\u1E25)</em> the duality <em>(bheda)</em> of pleasure <em>(sukha)</em> [and] pain <em>(du\u1E25kha)</em></p></div><div class="stanza"><a href="#s38" id="s38" class="num">38</a><p class="sans">\u0936\u093E\u0928\u094D\u0924\u0947 \u0936\u093E\u0928\u094D\u0924 \u0907\u0935\u093E\u092F\u0902 \u0939\u0943\u0937\u094D\u091F\u0947 \u0939\u0943\u0937\u094D\u091F\u094B \u0935\u093F\u092E\u094B\u0939\u0935\u0924\u093F \u092E\u0942\u0922\u0903 \u0964<br> \u0924\u0924\u094D\u0924\u094D\u0935\u0917\u0923\u0947 \u0938\u0924\u093F \u092D\u0917\u0935\u093E\u0928\u094D\u0928 \u092A\u0941\u0928\u0903 \u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0924\u0903 \u0938 \u0924\u0925\u093E \u0965\u0969\u096E\u0965</p><p class="trans">\u015A\u0101nte \u015B\u0101nta iv\u0101ya\u1E41 h\u1E5B\u1E63\u1E6De h\u1E5B\u1E63\u1E6Do vimohavati m\u016B\u1E0Dha\u1E25 \u0964<br> Tattvaga\u1E47e sati bhagav\u0101nna puna\u1E25 param\u0101rthata\u1E25 sa tath\u0101 \u096538\u0965</p><p>\u041F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 \u0433\u0443\u0449\u0435 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0435\u0439 <em>(tattva-ga\u1E47e sati)</em> \u041E\u043D <em>(ayam)</em> \u043A\u0430\u0436\u0435\u0442\u0441\u044F <em>(iva)</em> \u0441\u043F\u043E\u043A\u043E\u0439\u043D\u044B\u043C <em>(\u015B\u0101nta\u1E25)</em> \u0432 \u0441\u043F\u043E\u043A\u043E\u0439\u0441\u0442\u0432\u0438\u0438 <em>(\u015B\u0101nte)</em>, \u0432\u0437\u0432\u043E\u043B\u043D\u043E\u0432\u0430\u043D\u043D\u044B\u043C <em>(h\u1E5B\u1E63\u1E6Da\u1E25)</em> \u0432 \u0432\u043E\u043B\u043D\u0435\u043D\u0438\u0438 <em>(h\u1E5B\u1E63\u1E6De)</em>, \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(m\u016B\u1E0Dha\u1E25)</em> \u0432 \u0440\u0430\u0441\u0442\u0435\u0440\u044F\u043D\u043D\u043E\u0441\u0442\u0438 <em>(vimohavati)</em>, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A <em>(punar)</em>, \u0432\u043E\u0438\u0441\u0442\u0438\u043D\u0443 <em>(parama-arthatas)</em> \u0411\u043E\u0433 <em>(bhagav\u0101n sa\u1E25)</em> \u043D\u0435 <em>(na)</em> \u0442\u0430\u043A\u043E\u0432 <em>(tath\u0101)</em>.</p><p class="eng">When the group of tattva-s or principles \u2013i.e. the group of indriya-s or powers of perception/action\u2013 is <em>(tattva-ga\u1E47e sati)</em> calm <em>(\u015B\u0101nte)</em> He <em>(ayam)</em> [is] calm <em>(\u015B\u0101nta\u1E25)</em>, as it were <em>(iva)</em>, when it is glad <em>(h\u1E5B\u1E63\u1E6De)</em> [He is] glad <em>(h\u1E5B\u1E63\u1E6Da\u1E25)</em>, when it is bewildered <em>(vimohavati)</em> [He is] bewildered <em>(m\u016B\u1E0Dha\u1E25)</em>. Nonetheless <em>(punar)</em>, the Fortunate One <em>(bhagav\u0101n sa\u1E25)</em> [is] not <em>(na)</em> so <em>(tath\u0101)</em> really <em>(parama-arthatas)</em></p></div><div class="stanza"><a href="#s39" id="s39" class="num">39</a><p class="sans">\u092F\u0926\u0928\u093E\u0924\u094D\u092E\u0928\u094D\u092F\u092A\u093F \u0924\u0926\u094D\u0930\u0942\u092A\u093E\u0935\u092D\u093E\u0938\u0928\u0902 \u0924\u0924\u094D\u092A\u0941\u0930\u093E \u0928\u093F\u0930\u093E\u0915\u0943\u0924\u094D\u092F \u0964<br> \u0906\u0924\u094D\u092E\u0928\u094D\u092F\u0928\u093E\u0924\u094D\u092E\u0930\u0942\u092A\u093E\u0902 \u092D\u094D\u0930\u093E\u0928\u094D\u0924\u093F\u0902 \u0935\u093F\u0926\u0932\u092F\u0924\u093F \u092A\u0930\u092E\u093E\u0924\u094D\u092E\u093E \u0965\u0969\u096F\u0965</p><p class="trans">Yadan\u0101tmanyapi tadr\u016Bp\u0101vabh\u0101sana\u1E41 tatpur\u0101 nir\u0101k\u1E5Btya \u0964<br> \u0100tmanyan\u0101tmar\u016Bp\u0101\u1E41 bhr\u0101nti\u1E41 vidalayati param\u0101tm\u0101 \u096539\u0965</p><p>\u041F\u0440\u0435\u0436\u0434\u0435 \u0432\u0441\u0435\u0433\u043E \u0443\u0441\u0442\u0440\u0430\u043D\u0438\u0432 <em>(pur\u0101 nir\u0101k\u1E5Btya)</em> \u0442\u043E <em>(yad\u2026 tad)</em> \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435 <em>(avabh\u0101sanam)</em> \u043E \u201C\u043D\u0435-\u042F\u201D <em>(an\u0101tmani)</em> \u043A\u0430\u043A <em>(api)</em> \u043E \u0435\u0433\u043E <em>(tad)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435 <em>(r\u016Bpa)</em>, \u0412\u044B\u0441\u0448\u0435\u0435 \xAB\u042F\xBB <em>(parama-\u0101tm\u0101)</em> \u043E\u0442\u0441\u0435\u043A\u0430\u0435\u0442 <em>(vidalayati)</em> \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435 <em>(bhr\u0101ntim)</em> \u043F\u0440\u0438\u043D\u044F\u0442\u0438\u044F <em>(r\u016Bp\u0101m)</em> \u201C\u043D\u0435-\u042F\u201D <em>(an\u0101tma)</em> \u0437\u0430 \xAB\u042F\xBB <em>(\u0101tmani)</em>.</p><p class="eng">Having firstly removed <em>(pur\u0101 nir\u0101k\u1E5Btya)</em> that which <em>(yad\u2026 tad)</em> [is constituted by] the manifestation <em>(avabh\u0101sanam)</em> of the not-Self <em>(an\u0101tmani api)</em> as being His <em>(tad)</em> nature <em>(r\u016Bpa)</em>, the Supreme Self <em>(parama-\u0101tm\u0101)</em> completely shatters <em>(vidalayati)</em> the confusion <em>(bhr\u0101ntim)</em> that consists in <em>(r\u016Bp\u0101m)</em> [considering] the Self <em>(\u0101tmani)</em> as the not-Self <em>(an\u0101tma)</em>.</p></div><div class="stanza"><a href="#s40" id="s40" class="num">40</a><p class="sans">\u0907\u0924\u094D\u0925\u0902 \u0935\u093F\u092D\u094D\u0930\u092E\u092F\u0941\u0917\u0932\u0915\u0938\u092E\u0942\u0932\u0935\u093F\u091A\u094D\u091B\u0947\u0926\u0928\u0947 \u0915\u0943\u0924\u093E\u0930\u094D\u0925\u0938\u094D\u092F \u0964<br> \u0915\u0930\u094D\u0924\u0935\u094D\u092F\u093E\u0928\u094D\u0924\u0930\u0915\u0932\u0928\u093E \u0928 \u091C\u093E\u0924\u0941 \u092A\u0930\u092F\u094B\u0917\u093F\u0928\u094B \u092D\u0935\u0924\u093F \u0965\u096A\u0966\u0965</p><p class="trans">Ittha\u1E41 vibhramayugalakasam\u016Blavicchedane k\u1E5Bt\u0101rthasya \u0964<br> Kartavy\u0101ntarakalan\u0101 na j\u0101tu parayogino bhavati \u096540\u0965</p><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(ittham)</em>, \u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435 \u043F\u043E\u043B\u043D\u043E\u0433\u043E \u0443\u0434\u0430\u043B\u0435\u043D\u0438\u044F <em>(sam\u016Bla-vicchedane)</em> \u043E\u0431\u043E\u0438\u0445 <em>(yugalaka)</em> \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0439 <em>(vibhrama)</em>, \u0434\u043B\u044F \u0434\u043E\u0441\u0442\u0438\u0433\u0448\u0435\u0433\u043E \u0446\u0435\u043B\u0438 <em>(k\u1E5Bta-arthasya)</em> \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0433\u043E \u0439\u043E\u0433\u0438\u043D\u0430 <em>(para-yogina\u1E25)</em>, \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F <em>(na j\u0101tu\u2026 bhavati)</em> \u043F\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u0439 <em>(kalan\u0101)</em> \u043A <em>(antara)</em> \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(kartavya)</em>.</p><p class="eng">In this way <em>(ittham)</em>, on the complete removal <em>(sam\u016Bla-vicchedane)</em> of the pair <em>(yugalaka)</em> of confusions <em>(vibhrama)</em>, there is never <em>(na j\u0101tu\u2026 bhavati)</em> mental activity <em>(kalan\u0101)</em> with reference to another <em>(antara)</em> task to be done <em>(kartavya)</em> in the case of the Supreme Yog\u012B <em>(para-yogina\u1E25)</em> who has attained the Goal <em>(k\u1E5Bta-arthasya)</em>.</p></div><div class="stanza"><a href="#s41" id="s41" class="num">41</a><p class="sans">\u092A\u0943\u0925\u093F\u0935\u0940 \u092A\u094D\u0930\u0915\u0943\u0924\u093F\u0930\u094D\u092E\u093E\u092F\u093E \u0924\u094D\u0930\u093F\u0924\u092F\u092E\u093F\u0926\u0902 \u0935\u0947\u0926\u094D\u092F\u0930\u0942\u092A\u0924\u093E\u092A\u0924\u093F\u0924\u092E\u094D \u0964<br> \u0905\u0926\u094D\u0935\u0948\u0924\u092D\u093E\u0935\u0928\u092C\u0932\u093E\u0926\u094D\u092D\u0935\u0924\u093F \u0939\u093F \u0938\u0928\u094D\u092E\u093E\u0924\u094D\u0930\u092A\u0930\u093F\u0936\u0947\u0937\u092E\u094D \u0965\u096A\u0967\u0965</p><p class="trans">P\u1E5Bthiv\u012B prak\u1E5Btirm\u0101y\u0101 tritayamida\u1E41 vedyar\u016Bpat\u0101patitam \u0964<br> Advaitabh\u0101vanabal\u0101dbhavati hi sanm\u0101trapari\u015Be\u1E63am \u096541\u0965</p><p>\u0417\u0435\u043C\u043B\u044F <em>(p\u1E5Bthiv\u012B)</em>, \u041F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(prak\u1E5Bti\u1E25)</em> [\u0438] \u041C\u0430\u0439\u044F <em>(m\u0101y\u0101)</em> \u2014 \u044D\u0442\u0430 <em>(idam)</em> \u0442\u0440\u0438\u0430\u0434\u0430 <em>(tritayam)</em> \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0430\u044F <em>(patitam)</em> \u0432 \u0444\u043E\u0440\u043C\u0435 <em>(r\u016Bpat\u0101)</em> \u043F\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u0433\u043E <em>(vedya)</em>, \u0441\u0438\u043B\u043E\u0439 <em>(bal\u0101t)</em> \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(advaita)</em> \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(bh\u0101vana)</em> \u0441\u0432\u043E\u0434\u0438\u0442\u0441\u044F <em>(bhavati)</em> \u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435 <em>(pari\u015Be\u1E63am)</em> \u0442\u043E\u043B\u044C\u043A\u043E \u043A <em>(hi)</em> \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C\u0443 <em>(m\u0101tra)</em> \u0411\u044B\u0442\u0438\u044E <em>(sat)</em>.</p><p class="eng">P\u1E5Bthiv\u012B <em>(p\u1E5Bthiv\u012B)</em>, Prak\u1E5Bti <em>(prak\u1E5Bti\u1E25)</em> [and] M\u0101y\u0101 <em>(m\u0101y\u0101)</em>\u2026 this <em>(idam)</em> triad [of eggs] <em>(tritayam)</em> that was in <em>(patitam)</em> the form <em>(r\u016Bpat\u0101)</em> of knowables \u2013objects\u2013 <em>(vedya)</em>, by force of <em>(bal\u0101t)</em> the contemplation <em>(bh\u0101vana)</em> on the Non-dual One \u2013Lord \u015Aiva\u2013 <em>(advaita)</em>, becomes <em>(bhavati)</em> as a result <em>(hi)</em> a remnant <em>(pari\u015Be\u1E63am)</em> that is only <em>(m\u0101tra)</em> Being <em>(sat)</em>.</p></div><div class="stanza"><a href="#s42" id="s42" class="num">42</a><p class="sans">\u0930\u0936\u0928\u093E\u0915\u0941\u0923\u094D\u0921\u0932\u0915\u091F\u0915\u0902 \u092D\u0947\u0926\u0924\u094D\u092F\u093E\u0917\u0947\u0928 \u0926\u0943\u0936\u094D\u092F\u0924\u0947 \u092F\u0925\u093E \u0939\u0947\u092E \u0964<br> \u0924\u0926\u094D\u0935\u0926\u094D\u092D\u0947\u0926\u0924\u094D\u092F\u093E\u0917\u0947 \u0938\u0928\u094D\u092E\u093E\u0924\u094D\u0930\u0902 \u0938\u0930\u094D\u0935\u092E\u093E\u092D\u093E\u0924\u093F \u0965\u096A\u0968\u0965</p><p class="trans">Ra\u015Ban\u0101ku\u1E47\u1E0Dalaka\u1E6Daka\u1E41 bhedaty\u0101gena d\u1E5B\u015Byate yath\u0101 hema \u0964<br> Tadvadbhedaty\u0101ge sanm\u0101tra\u1E41 sarvam\u0101bh\u0101ti \u096542\u0965</p><p>\u041F\u043E\u044F\u0441 <em>(ra\u015Ban\u0101)</em>, \u0441\u0435\u0440\u044C\u0433\u0430 <em>(ku\u1E47\u1E0Dala)</em>, \u0431\u0440\u0430\u0441\u043B\u0435\u0442 <em>(ka\u1E6Dakam)</em> \u043F\u0440\u0438 \u0443\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0438 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(bheda-ty\u0101gena)</em> \u0432\u0438\u0434\u044F\u0442\u0441\u044F <em>(d\u1E5B\u015Byate)</em> \u043A\u0430\u043A \u043E\u0434\u043D\u043E \u0442\u043E\u043B\u044C\u043A\u043E <em>(yath\u0101)</em> \u0437\u043E\u043B\u043E\u0442\u043E <em>(hema)</em>. \u0422\u0430\u043A\u043E\u0435 <em>(tadvat)</em> \u0443\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(bheda-ty\u0101ge)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442 <em>(\u0101bh\u0101ti)</em> \u0432\u0441\u0451 <em>(sarvam)</em> \u043A\u0430\u043A \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(m\u0101tram)</em> \u0411\u044B\u0442\u0438\u0435 <em>(sat)</em>.</p><p class="eng">A girdle <em>(ra\u015Ban\u0101)</em>, an earring <em>(ku\u1E47\u1E0Dala)</em>, a bracelet <em>(ka\u1E6Dakam)</em>\u2026 by abandoning duality [with respect to that group of objects made of gold] <em>(bheda-ty\u0101gena)</em>, [it] is seen <em>(d\u1E5B\u015Byate)</em> [only] as <em>(yath\u0101)</em> gold <em>(hema)</em>. Likewise <em>(tadvat)</em>, when duality is abandoned [regarding the universe] <em>(bheda-ty\u0101ge)</em>, all <em>(sarvam)</em> appears <em>(\u0101bh\u0101ti)</em> only <em>(m\u0101tram)</em> as Being <em>(sat)</em>.</p></div><div class="stanza"><a href="#s43" id="s43" class="num">43</a><p class="sans">\u0924\u0926\u094D\u092C\u094D\u0930\u0939\u094D\u092E \u092A\u0930\u0902 \u0936\u0941\u0926\u094D\u0927\u0902 \u0936\u093E\u0928\u094D\u0924\u092E\u092D\u0947\u0926\u093E\u0924\u094D\u092E\u0915\u0902 \u0938\u092E\u0902 \u0938\u0915\u0932\u092E\u094D \u0964<br> \u0905\u092E\u0943\u0924\u0902 \u0938\u0924\u094D\u092F\u0902 \u0936\u0915\u094D\u0924\u094C \u0935\u093F\u0936\u094D\u0930\u093E\u092E\u094D\u092F\u0924\u093F \u092D\u093E\u0938\u094D\u0935\u0930\u0942\u092A\u093E\u092F\u093E\u092E\u094D \u0965\u096A\u0969\u0965</p><p class="trans">Tadbrahma para\u1E41 \u015Buddha\u1E41 \u015B\u0101ntamabhed\u0101tmaka\u1E41 sama\u1E41 sakalam \u0964<br> Am\u1E5Bta\u1E41 satya\u1E41 \u015Baktau vi\u015Br\u0101myati bh\u0101svar\u016Bp\u0101y\u0101m \u096543\u0965</p><p>\u0422\u043E\u0442 <em>(tad)</em> \u0411\u0440\u0430\u0445\u043C\u0430\u043D <em>(brahma)</em>, \u0412\u044B\u0441\u0448\u0438\u0439 <em>(param)</em>, \u0427\u0438\u0441\u0442\u044B\u0439 <em>(\u015Buddham)</em>, \u0411\u0435\u0437\u043C\u044F\u0442\u0435\u0436\u043D\u044B\u0439 <em>(\u015B\u0101ntam)</em>, \u041D\u0435\u0434\u0435\u043B\u0438\u043C\u044B\u0439 <em>(abheda-\u0101tmakam)</em>, \u041E\u0434\u043D\u043E\u0440\u043E\u0434\u043D\u044B\u0439 <em>(samam)</em>, \u041F\u043E\u043B\u043D\u044B\u0439 <em>(sakalam)</em>, \u0411\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u043D\u044B\u0439 <em>(am\u1E5Btam)</em>, \u0418\u0441\u0442\u0438\u043D\u043D\u044B\u0439 <em>(satyam)</em> \u043F\u043E\u043A\u043E\u0438\u0442\u0441\u044F \u0432 <em>(vi\u015Br\u0101myati)</em> \u0428\u0430\u043A\u0442\u0438 <em>(\u015Baktau)</em>, \u0441\u0432\u043E\u0435\u0439 <em>(sva)</em> \u043B\u0443\u0447\u0435\u0437\u0430\u0440\u043D\u043E\u0439 <em>(bh\u0101)</em> \u043F\u0440\u0438\u0440\u043E\u0434\u0435 <em>(r\u016Bp\u0101y\u0101m)</em>.</p><p class="eng">That <em>(tad)</em> Brahma <em>(brahma)</em> [who is] Supreme <em>(param)</em>, Pure <em>(\u015Buddham)</em>, Calm <em>(\u015B\u0101ntam)</em>, Non-dual <em>(abheda-\u0101tmakam)</em>, Homogeneous <em>(samam)</em>, Complete <em>(sakalam)</em>, Immortal <em>(am\u1E5Btam)</em> [and] Real <em>(satyam)</em> rests <em>(vi\u015Br\u0101myati)</em> on \u015Aakti or Power <em>(\u015Baktau)</em> whose nature <em>(sva-r\u016Bp\u0101y\u0101m)</em> is Brightness <em>(bh\u0101)</em>.</p></div><div class="stanza"><a href="#s44" id="s44" class="num">44</a><p class="sans">\u0907\u0937\u094D\u092F\u0924 \u0907\u0924\u093F \u0935\u0947\u0926\u094D\u092F\u0924 \u0907\u0924\u093F \u0938\u092E\u094D\u092A\u093E\u0926\u094D\u092F\u0924 \u0907\u0924\u093F \u091A \u092D\u093E\u0938\u094D\u0935\u0930\u0942\u092A\u0947\u0923 \u0964<br> \u0905\u092A\u0930\u093E\u092E\u0943\u0937\u094D\u091F\u0902 \u092F\u0926\u092A\u093F \u0924\u0941 \u0928\u092D\u0903\u092A\u094D\u0930\u0938\u0942\u0928\u0924\u094D\u0935\u092E\u092D\u094D\u092F\u0947\u0924\u093F \u0965\u096A\u096A\u0965</p><p class="trans">I\u1E63yata iti vedyata iti samp\u0101dyata iti ca bh\u0101svar\u016Bpe\u1E47a \u0964<br> Apar\u0101m\u1E5B\u1E63\u1E6Da\u1E41 yadapi tu nabha\u1E25pras\u016Bnatvamabhyeti \u096544\u0965</p><p>[\u0422\u0430\u043A\u0438\u0435 \u0438\u0434\u0435\u0438,] \u043A\u0430\u043A <em>(yad)</em> \u201C\u042D\u0442\u043E \u0436\u0435\u043B\u0430\u0435\u043C\u043E <em>(i\u1E63yate iti)</em>\u201C, \u201C\u044D\u0442\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E <em>(vedyate iti)</em>\u201D \u0438 <em>(ca)</em> \u201C\u044D\u0442\u043E \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u043E\u201D <em>(samp\u0101dyate iti)</em> \u043D\u0435 \u0441\u043E\u043F\u0440\u0438\u043A\u0430\u0441\u0430\u044E\u0449\u0438\u0435\u0441\u044F <em>(apar\u0101m\u1E5B\u1E63\u1E6Dam)</em> \u0441 \u044D\u0442\u043E\u0439 \u043B\u0443\u0447\u0435\u0437\u0430\u0440\u043D\u043E\u0439 <em>(bh\u0101)</em> \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(sva-r\u016Bpe\u1E47a)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u044B <em>(abhyeti)</em> \u043B\u0438\u0448\u044C <em>(api tu)</em> \u0446\u0432\u0435\u0442\u043A\u0443 <em>(pras\u016Bnatvam)</em> [, \u0440\u0430\u0441\u0442\u0443\u0449\u0435\u043C\u0443] \u0432 \u043D\u0435\u0431\u0435\u0441\u0430\u0445 <em>(nabhas)</em>.</p><p class="eng">However <em>(api tu)</em>, that which <em>(yad)</em> is not touched <em>(apar\u0101m\u1E5B\u1E63\u1E6Dam)</em> by [Bodha or Consciousness] whose nature <em>(sva-r\u016Bpe\u1E47a)</em> [is] Brightness <em>(bh\u0101)</em> [in the form of] \u201Cit is wished <em>(i\u1E63yate iti)</em>\u201C, \u201Cit is known <em>(vedyate iti)</em>\u201D and <em>(ca)</em> \u201Cit is carried out\u201D <em>(samp\u0101dyate iti)</em> falls into <em>(abhyeti)</em> [the category of] being a flower <em>(pras\u016Bnatvam)</em> in the sky <em>(nabhas)</em>\u2013i.e. it does not exist at all\u2013.</p></div><div class="stanza"><a href="#s45" id="s45" class="num">45</a><p class="sans">\u0936\u0915\u094D\u0924\u093F\u0924\u094D\u0930\u093F\u0936\u0942\u0932\u092A\u0930\u093F\u0917\u092E\u092F\u094B\u0917\u0947\u0928 \u0938\u092E\u0938\u094D\u0924\u092E\u092A\u093F \u092A\u0930\u092E\u0947\u0936\u0947 \u0964<br> \u0936\u093F\u0935\u0928\u093E\u092E\u0928\u093F \u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0947 \u0935\u093F\u0938\u0943\u091C\u094D\u092F\u0924\u0947 \u0926\u0947\u0935\u0926\u0947\u0935\u0947\u0928 \u0965\u096A\u096B\u0965</p><p class="trans">\u015Aaktitri\u015B\u016Blaparigamayogena samastamapi parame\u015Be \u0964<br> \u015Aivan\u0101mani param\u0101rthe vis\u1E5Bjyate devadevena \u096545\u0965</p><p>\u0421 \u043F\u043E\u043C\u043E\u0449\u044C\u044E <em>(yogena)</em> \u043F\u0440\u0438\u043C\u0435\u043D\u0435\u043D\u0438\u044F <em>(parigama)</em> \u0442\u0440\u0435\u0437\u0443\u0431\u0446\u0430 <em>(tri\u015B\u016Bla)</em> \u0428\u0430\u043A\u0442\u0438 <em>(\u015Bakti)</em> \u0411\u043E\u0433 <em>(devena)</em> \u0431\u043E\u0433\u043E\u0432 <em>(deva)</em> \u043F\u0440\u043E\u0435\u0446\u0438\u0440\u0443\u0435\u0442 <em>(vis\u1E5Bjyate)</em> \u0432\u0441\u0451 \u0431\u044B\u0442\u0438\u0435 <em>(samastam api)</em> \u0432 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0412\u043B\u0430\u0434\u044B\u043A\u0443 <em>(parama-\u012B\u015Be)</em>, \u0437\u043E\u0432\u0443\u0449\u0443\u044E\u0441\u044F <em>(n\u0101mani)</em> \u0428\u0438\u0432\u0430 <em>(\u015Biva)</em> \u0412\u044B\u0441\u0448\u0443\u044E \u0418\u0441\u0442\u0438\u043D\u0443 <em>(parama-arthe)</em>.</p><p class="eng">The Whole \u2013the third Brahma\u2013 <em>(samastam api)</em> is emitted <em>(vis\u1E5Bjyate)</em> by the God <em>(devena)</em> of gods <em>(deva)</em> into the Supreme Lord <em>(parama-\u012B\u015Be)</em> called <em>(n\u0101mani)</em> \u015Aiva <em>(\u015Biva)</em> who is the Highest Reality <em>(parama-arthe)</em> through <em>(yogena)</em> its attaining \u2013on the part of the third Brahma\u2013 <em>(parigama)</em> the trident <em>(tri\u015B\u016Bla)</em> of powers <em>(\u015Bakti)</em>\u2013Will, Knowledge and Action\u2013.</p></div><div class="stanza"><a href="#s46" id="s46" class="num">46</a><p class="sans">\u092A\u0941\u0928\u0930\u092A\u093F \u091A \u092A\u091E\u094D\u091A\u0936\u0915\u094D\u0924\u093F\u092A\u094D\u0930\u0938\u0930\u0923\u0915\u094D\u0930\u092E\u0947\u0923 \u092C\u0939\u093F\u0930\u092A\u093F \u0924\u0924\u094D \u0964<br> \u0905\u0923\u094D\u0921\u0924\u094D\u0930\u092F\u0902 \u0935\u093F\u091A\u093F\u0924\u094D\u0930\u0902 \u0938\u0943\u0937\u094D\u091F\u0902 \u092C\u0939\u093F\u0930\u093E\u0924\u094D\u092E\u0932\u093E\u092D\u0947\u0928 \u0965\u096A\u096C\u0965</p><p class="trans">Punarapi ca pa\xF1ca\u015Baktiprasara\u1E47akrame\u1E47a bahirapi tat \u0964<br> A\u1E47\u1E0Datraya\u1E41 vicitra\u1E41 s\u1E5B\u1E63\u1E6Da\u1E41 bahir\u0101tmal\u0101bhena \u096546\u0965</p><p>\u0418 <em>(ca)</em> \u0441\u043D\u043E\u0432\u0430 <em>(punar api)</em> \u043F\u0443\u0442\u0451\u043C <em>(krame\u1E47a)</em> \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u044F <em>(prasara\u1E47a)</em> \u0432\u043E \u0432\u043D\u0435 <em>(bahis api)</em> \u043F\u044F\u0442\u0438 <em>(pa\xF1ca)</em> \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u0438\u043B <em>(\u015Bakti)</em> \u0434\u043B\u044F \u0432\u043D\u0435\u0448\u043D\u0435\u0433\u043E <em>(bahis)</em> \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F <em>(l\u0101bhena)</em> \u0421\u0435\u0431\u044F <em>(\u0101tma)</em> [\u041E\u043D] \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442 <em>(s\u1E5B\u1E63\u1E6Dam)</em> \u0442\u0443 <em>(tad)</em> \u0438\u0437\u0443\u043C\u0438\u0442\u0435\u043B\u044C\u043D\u0443\u044E <em>(vicitram)</em> \u0442\u0440\u043E\u0438\u0446\u0443 <em>(trayam)</em> \u043E\u0431\u043E\u043B\u043E\u0447\u0435\u043A <em>(a\u1E47\u1E0Da)</em>.</p><p class="eng">And <em>(ca)</em> even again <em>(punar api)</em> that <em>(tad)</em> wonderful and variegated <em>(vicitram)</em> triad <em>(trayam)</em> of eggs <em>(a\u1E47\u1E0Da)</em> [is]emitted <em>(s\u1E5B\u1E63\u1E6Dam)</em> [by the Supreme \u015Aiva] outside <em>(bahis api)</em> through the method <em>(krame\u1E47a)</em> of expanding <em>(prasara\u1E47a)</em> [His] five <em>(pa\xF1ca)</em> powers <em>(\u015Bakti)</em> for the purpose of perceiving <em>(l\u0101bhena)</em> Himself <em>(\u0101tma)</em> externally <em>(bahis)</em>.</p></div><div class="stanza"><a href="#s47" id="s47" class="num">47</a><p class="sans">\u0907\u0924\u093F \u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u092F\u0928\u094D\u0924\u094D\u0930\u0902 \u0915\u094D\u0930\u0940\u0921\u093E\u092F\u094B\u0917\u0947\u0928 \u0935\u093E\u0939\u092F\u0928\u094D\u0926\u0947\u0935\u0903 \u0964<br> \u0905\u0939\u092E\u0947\u0935 \u0936\u0941\u0926\u094D\u0927\u0930\u0942\u092A\u0903 \u0936\u0915\u094D\u0924\u093F\u092E\u0939\u093E\u091A\u0915\u094D\u0930\u0928\u093E\u092F\u0915\u092A\u0926\u0938\u094D\u0925\u0903 \u0965\u096A\u096D\u0965</p><p class="trans">Iti \u015Bakticakrayantra\u1E41 kr\u012B\u1E0D\u0101yogena v\u0101hayandeva\u1E25 \u0964<br> Ahameva \u015Buddhar\u016Bpa\u1E25 \u015Baktimah\u0101cakran\u0101yakapadastha\u1E25 \u096547\u0965</p><p>\u0422\u0430\u043A <em>(iti)</em>, \u0411\u043E\u0433 <em>(deva\u1E25)</em>, \u0438\u0433\u0440\u0430\u044F, \u0434\u0432\u0438\u0436\u0435\u0442 <em>(kr\u012B\u1E0D\u0101-yogena v\u0101hayan)</em> \u0443\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E <em>(yantram)</em> \u043A\u043E\u043B\u0435\u0441\u0430 <em>(cakra)</em> \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u044D\u043D\u0435\u0440\u0433\u0438\u0439 <em>(\u015Bakti)</em>. \u0418\u043C\u0435\u043D\u043D\u043E <em>(eva)</em> \xAB\u042F\xBB <em>(aham)</em>, \u0447\u0438\u0441\u0442\u043E\u0435 \u043F\u043E \u043F\u0440\u0438\u0440\u043E\u0434\u0435 <em>(\u015Buddha-r\u016Bpa\u1E25)</em>, \u0441\u0442\u043E\u0438\u0442 <em>(pada)</em> \u043D\u0430 \u043C\u0435\u0441\u0442\u0435 <em>(stha\u1E25)</em> \u0443\u043F\u0440\u0430\u0432\u0438\u0442\u0435\u043B\u044F <em>(n\u0101yaka)</em> \u0412\u0435\u043B\u0438\u043A\u043E\u0433\u043E <em>(mah\u0101)</em> \u043A\u043E\u043B\u0435\u0441\u0430 <em>(cakra)</em> \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u0438\u043B <em>(\u015Bakti)</em>.</p><p class="eng">Thus <em>(iti)</em>, the God <em>(deva\u1E25)</em>, Pure in nature <em>(\u015Buddha-r\u016Bpa\u1E25)</em>, by playfully guiding and propelling <em>(kr\u012B\u1E0D\u0101-yogena v\u0101hayan)</em> the machine <em>(yantram)</em> [known as] the group <em>(cakra)</em> of powers <em>(\u015Bakti)</em>, remains <em>(stha\u1E25)</em> as \u201CAham\u201D or \u201CI\u201D <em>(aham eva)</em> in the state <em>(pada)</em> of Leader <em>(n\u0101yaka)</em> of the great <em>(mah\u0101)</em> group <em>(cakra)</em> of \u015Bakti-s <em>(\u015Bakti)</em>.</p></div><div class="stanza"><a href="#s48" id="s48" class="num">48</a><p class="sans">\u092E\u092F\u094D\u092F\u0947\u0935 \u092D\u093E\u0924\u093F \u0935\u093F\u0936\u094D\u0935\u0902 \u0926\u0930\u094D\u092A\u0923 \u0907\u0935 \u0928\u093F\u0930\u094D\u092E\u0932\u0947 \u0918\u091F\u093E\u0926\u0940\u0928\u093F \u0964<br> \u092E\u0924\u094D\u0924\u0903 \u092A\u094D\u0930\u0938\u0930\u0924\u093F \u0938\u0930\u094D\u0935\u0902 \u0938\u094D\u0935\u092A\u094D\u0928\u0935\u093F\u091A\u093F\u0924\u094D\u0930\u0924\u094D\u0935\u092E\u093F\u0935 \u0938\u0941\u092A\u094D\u0924\u093E\u0924\u094D \u0965\u096A\u096E\u0965</p><p class="trans">Mayyeva bh\u0101ti vi\u015Bva\u1E41 darpa\u1E47a iva nirmale gha\u1E6D\u0101d\u012Bni \u0964<br> Matta\u1E25 prasarati sarva\u1E41 svapnavicitratvamiva supt\u0101t \u096548\u0965</p><p>\u0412\u0441\u044F \u0412\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F <em>(vi\u015Bva)</em> \u043E\u0442\u0440\u0430\u0436\u0430\u0435\u0442\u0441\u044F <em>(bh\u0101ti)</em> \u0432\u043E \u041C\u043D\u0435 <em>(mayi)</em> \u043E\u0434\u043D\u043E\u043C <em>(eva)</em> \u043A\u0430\u043A <em>(iva)</em> \u0433\u043E\u0440\u0448\u043A\u0438 <em>(gha\u1E6Da)</em> \u0438 \u043F\u0440\u043E\u0447\u0435\u0435 <em>(\u0101d\u012Bni)</em> \u0432 \u043D\u0435\u0437\u0430\u043F\u044F\u0442\u043D\u0430\u043D\u043D\u043E\u043C <em>(nirmale)</em> \u0437\u0435\u0440\u043A\u0430\u043B\u0435 <em>(darpa\u1E47e)</em>. \u0412\u0441\u0451 <em>(sarvam)</em> \u043F\u0440\u043E\u0438\u0441\u0442\u0435\u043A\u0430\u0435\u0442 <em>(prasarati)</em> \u0438\u0437 \u041C\u0435\u043D\u044F <em>(matta\u1E25)</em> \u043A\u0430\u043A <em>(iva)</em> \u043C\u043D\u043E\u0433\u043E\u043E\u0431\u0440\u0430\u0437\u0438\u0435 <em>(vicitratvam)</em> \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u0439 <em>(svapna)</em> \u0438\u0437 \u0441\u043D\u0430 <em>(supt\u0101t)</em>.</p><p class="eng">The universe <em>(vi\u015Bva)</em> shines forth <em>(bh\u0101ti)</em> in Myself <em>(mayi)</em> alone <em>(eva)</em> just as <em>(iva)</em> a pot <em>(gha\u1E6Da)</em>, etc. <em>(\u0101d\u012Bni)</em> [appear] in a spotless <em>(nirmale)</em> mirror <em>(darpa\u1E47e)</em>. All <em>(sarvam)</em> springs up <em>(prasarati)</em> from Myself <em>(matta\u1E25)</em> just like <em>(iva)</em> the variegated variety <em>(vicitratvam)</em> of dreams <em>(svapna)</em> [arises] from sleep <em>(supt\u0101t)</em>.</p></div><div class="stanza"><a href="#s49" id="s49" class="num">49</a><p class="sans">\u0905\u0939\u092E\u0947\u0935 \u0935\u093F\u0936\u094D\u0935\u0930\u0942\u092A\u0903 \u0915\u0930\u091A\u0930\u0923\u093E\u0926\u093F\u0938\u094D\u0935\u092D\u093E\u0935 \u0907\u0935 \u0926\u0947\u0939\u0903 \u0964<br> \u0938\u0930\u094D\u0935\u0938\u094D\u092E\u093F\u0928\u094D\u0928\u0939\u092E\u0947\u0935 \u0938\u094D\u092B\u0941\u0930\u093E\u092E\u093F \u092D\u093E\u0935\u0947\u0937\u0941 \u092D\u093E\u0938\u094D\u0935\u0930\u0942\u092A\u092E\u093F\u0935 \u0965\u096A\u096F\u0965</p><p class="trans">Ahameva vi\u015Bvar\u016Bpa\u1E25 karacara\u1E47\u0101disvabh\u0101va iva deha\u1E25 \u0964<br> Sarvasminnahameva sphur\u0101mi bh\u0101ve\u1E63u bh\u0101svar\u016Bpamiva \u096549\u0965</p><p>\u0412 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(eva)</em> \u042F <em>(aham)</em> \u0438\u043C\u0435\u044E \u0444\u043E\u0440\u043C\u0443 <em>(r\u016Bpa\u1E25)</em> \u0412\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u0430\u043A <em>(iva)</em> \u0442\u0435\u043B\u043E <em>(deha\u1E25)</em> \u043F\u043E \u0441\u0432\u043E\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435 <em>(sva-bh\u0101va\u1E25)</em> [\u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437] \u0440\u0443\u043A <em>(kara)</em>, \u043D\u043E\u0433 <em>(cara\u1E47a)</em> \u0438 \u043F\u0440\u043E\u0447\u0435\u0433\u043E <em>(\u0101di)</em>. \u0418\u043C\u0435\u043D\u043D\u043E <em>(eva)</em> \u042F <em>(aham)</em> \u0431\u043B\u0438\u0441\u0442\u0430\u044E <em>(sphur\u0101mi)</em> \u0432\u043E \u0432\u0441\u0451\u043C <em>(sarvasmin)</em> \u043A\u0430\u043A <em>(iva)</em> \u0441\u0438\u044F\u043D\u0438\u0435 <em>(bh\u0101)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpam)</em> [\u0432\u0441\u0435\u0445] \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(bh\u0101ve\u1E63u)</em>.</p><p class="eng">I <em>(aham)</em> Myself <em>(eva)</em> have the form <em>(r\u016Bpa\u1E25)</em> of the universe <em>(vi\u015Bva)</em> as if it were <em>(iva)</em> a Body <em>(deha\u1E25)</em> that by nature <em>(sva-bh\u0101va\u1E25)</em> consists of hands <em>(kara)</em>, feet <em>(cara\u1E47a)</em>, etc. <em>(\u0101di)</em>. I <em>(aham)</em> Myself <em>(eva)</em> shines forth <em>(sphur\u0101mi)</em> in all <em>(sarvasmin)</em> as <em>(iva)</em> [the \u015Aakti or Power] whose essential nature <em>(sva-r\u016Bpam)</em> is Brightness <em>(bh\u0101)</em> with reference to [all]the positive entities <em>(bh\u0101ve\u1E63u)</em>.</p></div><div class="stanza"><a href="#s50" id="s50" class="num">50</a><p class="sans">\u0926\u094D\u0930\u0937\u094D\u091F\u093E \u0936\u094D\u0930\u094B\u0924\u093E \u0918\u094D\u0930\u093E\u0924\u093E \u0926\u0947\u0939\u0947\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u0935\u0930\u094D\u091C\u093F\u0924\u094B\u093D\u092A\u094D\u092F\u0915\u0930\u094D\u0924\u093E\u092A\u093F \u0964<br> \u0938\u093F\u0926\u094D\u0927\u093E\u0928\u094D\u0924\u093E\u0917\u092E\u0924\u0930\u094D\u0915\u093E\u0902\u0936\u094D\u091A\u093F\u0924\u094D\u0930\u093E\u0928\u0939\u092E\u0947\u0935 \u0930\u091A\u092F\u093E\u092E\u093F \u0965\u096B\u0966\u0965</p><p class="trans">Dra\u1E63\u1E6D\u0101 \u015Brot\u0101 ghr\u0101t\u0101 dehendriyavarjito\u2019pyakart\u0101pi \u0964<br> Siddh\u0101nt\u0101gamatark\u0101\u1E41\u015Bcitr\u0101nahameva racay\u0101mi \u096550\u0965</p><p>\u0412\u0438\u0434\u044F\u0449\u0438\u0439 <em>(dra\u1E63\u1E6D\u0101)</em>, \u0441\u043B\u044B\u0448\u0430\u0449\u0438\u0439 <em>(\u015Brot\u0101)</em> [\u0438] \u043E\u0431\u043E\u043D\u044F\u044E\u0449\u0438\u0439 <em>(ghr\u0101t\u0101)</em>, \u0445\u043E\u0442\u044F \u0438 <em>(api)</em> \u043B\u0438\u0448\u0451\u043D\u043D\u044B\u0439 <em>(varjita\u1E25)</em> \u0442\u0435\u043B\u0430 <em>(deha)</em> [\u0438] \u0447\u0443\u0432\u0441\u0442\u0432 <em>(indriya)</em>, \u0438\u043C\u0435\u043D\u043D\u043E <em>(eva)</em> \u042F <em>(aham)</em>, \u0445\u043E\u0442\u044C \u0438 <em>(api)</em> \u0431\u0435\u0437\u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0439 <em>(akart\u0101)</em>, \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u044E <em>(racay\u0101mi)</em> \u043C\u043D\u043E\u0433\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u044B\u0435 <em>(citr\u0101n)</em> \u0443\u0447\u0435\u043D\u0438\u044F <em>(siddh\u0101nta)</em>, \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u044B\u0435 \u0442\u0435\u043A\u0441\u0442\u044B <em>(\u0101gama)</em> [\u0438] \u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B <em>(tark\u0101n)</em>.</p><p class="eng">Though <em>(api)</em> devoid of <em>(varjita\u1E25)</em> body <em>(deha)</em> [and] senses <em>(indriya)</em>, I <em>(aham)</em> Myself <em>(eva)</em> [am] the One who sees <em>(dra\u1E63\u1E6D\u0101)</em>, hears <em>(\u015Brot\u0101)</em> [and] smells <em>(ghr\u0101t\u0101)</em>. Though <em>(api)</em> not being an agent <em>(akart\u0101)</em>, I <em>(aham)</em> Myself <em>(eva)</em> produce <em>(racay\u0101mi)</em> the different and wonderful <em>(citr\u0101n)</em> reasonings <em>(tark\u0101n)</em> [to be found] in the Siddh\u0101nt\u0101gama-s \u2013Tantric scriptures in general\u2013 <em>(siddh\u0101nta-\u0101gama)</em>. \u2013An alternative translation of the final portion being: \u201Cthe different and wonderful <em>(citr\u0101n)</em> doctrines <em>(siddh\u0101nta)</em>, revealed scriptures <em>(\u0101gama)</em> [and] tarka-s or systems dealing with logic <em>(tark\u0101n)</em>\u201C\u2013.</p></div><div class="stanza"><a href="#s51" id="s51" class="num">51</a><p class="sans">\u0907\u0924\u094D\u0925\u0902 \u0926\u094D\u0935\u0948\u0924\u0935\u093F\u0915\u0932\u094D\u092A\u0947 \u0917\u0932\u093F\u0924\u0947 \u092A\u094D\u0930\u0935\u093F\u0932\u0919\u094D\u0918\u094D\u092F \u092E\u094B\u0939\u0928\u0940\u0902 \u092E\u093E\u092F\u093E\u092E\u094D \u0964<br> \u0938\u0932\u093F\u0932\u0947 \u0938\u0932\u093F\u0932\u0902 \u0915\u094D\u0937\u0940\u0930\u0947 \u0915\u094D\u0937\u0940\u0930\u092E\u093F\u0935 \u092C\u094D\u0930\u0939\u094D\u092E\u0923\u093F \u0932\u092F\u0940 \u0938\u094D\u092F\u093E\u0924\u094D \u0965\u096B\u0967\u0965</p><p class="trans">Ittha\u1E41 dvaitavikalpe galite pravila\u1E45ghya mohan\u012B\u1E41 m\u0101y\u0101m \u0964<br> Salile salila\u1E41 k\u1E63\u012Bre k\u1E63\u012Bramiva brahma\u1E47i lay\u012B sy\u0101t \u096551\u0965</p><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(ittham)</em>, \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0438\u0432\u0448\u0438\u0439 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F <em>(dvaita-vikalpe galite)</em>, \u043F\u043E\u0434\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u043D\u0430\u0434 <em>(pravila\u1E45ghya)</em> \u0437\u0430\u0442\u0443\u043C\u0430\u043D\u0438\u0432\u0430\u044E\u0449\u0435\u0439 <em>(mohan\u012Bm)</em> \u041C\u0430\u0439\u0435\u0439 <em>(m\u0101y\u0101m)</em>, \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u044F\u0441\u044C <em>(lay\u012B sy\u0101t)</em> \u0432 \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0435 <em>(brahma\u1E47i)</em> \u043A\u0430\u043A <em>(iva)</em> \u0432\u043E\u0434\u0430 <em>(salilam)</em> \u0432 \u0432\u043E\u0434\u0435 <em>(salile)</em> [\u0438\u043B\u0438] \u043C\u043E\u043B\u043E\u043A\u043E <em>(k\u1E63\u012Bram)</em> \u0432 \u043C\u043E\u043B\u043E\u043A\u0435 <em>(k\u1E63\u012Bre)</em>.</p><p class="eng">In this way <em>(ittham)</em>, when the dualistic thought perishes <em>(dvaita-vikalpe galite)</em>, [the great Yog\u012B,] rising beyond <em>(pravila\u1E45ghya)</em> the delusive <em>(mohan\u012Bm)</em> M\u0101y\u0101 <em>(m\u0101y\u0101m)</em>, gets dissolved <em>(lay\u012B sy\u0101t)</em> in Brahma <em>(brahma\u1E47i)</em> like <em>(iva)</em> water <em>(salilam)</em> in water <em>(salile)</em> [or] milk <em>(k\u1E63\u012Bram)</em> in milk <em>(k\u1E63\u012Bre)</em>.</p></div><div class="stanza"><a href="#s52" id="s52" class="num">52</a><p class="sans">\u0907\u0924\u094D\u0925\u0902 \u0924\u0924\u094D\u0924\u094D\u0935\u0938\u092E\u0942\u0939\u0947 \u092D\u093E\u0935\u0928\u092F\u093E \u0936\u093F\u0935\u092E\u092F\u0924\u094D\u0935\u092E\u092D\u093F\u092F\u093E\u0924\u0947 \u0964<br> \u0915\u0903 \u0936\u094B\u0915\u0903 \u0915\u094B \u092E\u094B\u0939\u0903 \u0938\u0930\u094D\u0935\u0902 \u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0935\u0932\u094B\u0915\u092F\u0924\u0903 \u0965\u096B\u0968\u0965</p><p class="trans">Ittha\u1E41 tattvasam\u016Bhe bh\u0101vanay\u0101 \u015Bivamayatvamabhiy\u0101te \u0964<br> Ka\u1E25 \u015Boka\u1E25 ko moha\u1E25 sarva\u1E41 brahm\u0101valokayata\u1E25 \u096552\u0965</p><p>\u0422\u0430\u043A <em>(ittham)</em>, \u043F\u0440\u0438 \u0441\u043B\u0438\u044F\u043D\u0438\u0438 \u0432\u0441\u0435\u0439 \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u0438 \u0442\u0430\u0442\u0442\u0432 \u0441 \u0428\u0438\u0432\u043E\u0439 <em>(tattva-sam\u016Bhe\u2026 \u015Biva-mayatvam abhiy\u0101te)</em> \u0447\u0435\u0440\u0435\u0437 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435 <em>(bh\u0101vanay\u0101)</em>, \u043E\u0442\u043A\u0443\u0434\u0430 \u0432\u0437\u044F\u0442\u044C\u0441\u044F <em>(ka\u1E25)</em> \u043F\u0435\u0447\u0430\u043B\u0438 <em>(\u015Boka\u1E25)</em>, \u043E\u0442\u043A\u0443\u0434\u0430 \u0432\u0437\u044F\u0442\u044C\u0441\u044F <em>(ka\u1E25)</em> \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u044E <em>(moha\u1E25)</em> \u0434\u043B\u044F \u0432\u0438\u0434\u044F\u0449\u0435\u0433\u043E <em>(avalokayata\u1E25)</em> \u0432\u0441\u0451 <em>(sarvam)</em> \u043A\u0430\u043A \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430 <em>(brahma)</em>?</p><p class="eng">In this manner <em>(ittham)</em>, when the aggregate of tattva-s or categories attains identity with \u015Aiva <em>(tattva-sam\u016Bhe\u2026 \u015Biva-mayatvam abhiy\u0101te)</em> through the contemplation <em>(bh\u0101vanay\u0101)</em>, what <em>(ka\u1E25)</em> sorrow <em>(\u015Boka\u1E25)</em> [and] what <em>(ka\u1E25)</em> delusion <em>(moha\u1E25)</em> [can befall] the one who sees <em>(avalokayata\u1E25)</em> all <em>(sarvam)</em> as Brahma <em>(brahma)</em>?</p></div><div class="stanza"><a href="#s53" id="s53" class="num">53</a><p class="sans">\u0915\u0930\u094D\u092E\u092B\u0932\u0902 \u0936\u0941\u092D\u092E\u0936\u0941\u092D\u0902 \u092E\u093F\u0925\u094D\u092F\u093E\u091C\u094D\u091E\u093E\u0928\u0947\u0928 \u0938\u0919\u094D\u0917\u092E\u093E\u0926\u0947\u0935 \u0964<br> \u0935\u093F\u0937\u092E\u094B \u0939\u093F \u0938\u0919\u094D\u0917\u0926\u094B\u0937\u0938\u094D\u0924\u0938\u094D\u0915\u0930\u092F\u094B\u0917\u094B\u093D\u092A\u094D\u092F\u0924\u0938\u094D\u0915\u0930\u0938\u094D\u092F\u0947\u0935 \u0965\u096B\u0969\u0965</p><p class="trans">Karmaphala\u1E41 \u015Bubhama\u015Bubha\u1E41 mithy\u0101j\xF1\u0101nena sa\u1E45gam\u0101deva \u0964<br> Vi\u1E63amo hi sa\u1E45gado\u1E63astaskarayogo\u2019pyataskarasyeva \u096553\u0965</p><p>\u0411\u043B\u0430\u0433\u043E\u0439 <em>(\u015Bubham)</em> [\u0438\u043B\u0438] \u0434\u0443\u0440\u043D\u043E\u0439 <em>(a\u015Bubham)</em> \u043F\u043B\u043E\u0434 <em>(phalam)</em> \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439 <em>(karma)</em> [\u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442] \u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u0438\u0437-\u0437\u0430 \u0441\u0432\u044F\u0437\u0438 <em>(sa\u1E45gam\u0101t)</em> \u0441 \u043B\u043E\u0436\u043D\u044B\u043C \u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(mithy\u0101-j\xF1\u0101nena)</em>. \u0411\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F <em>(hi)</em> \u043E\u043F\u0430\u0441\u043D\u0430 <em>(vi\u1E63ama\u1E25)</em> \u0441\u0432\u044F\u0437\u044C <em>(sa\u1E45ga)</em> \u0441 [\u043B\u044E\u0431\u044B\u043C] \u043D\u0435\u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u043E\u043C <em>(do\u1E63a\u1E25)</em> \u043A\u0430\u043A <em>(iva)</em> \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435 <em>(yoga\u1E25)</em> \u043D\u0435 \u0432\u043E\u0440\u0430 <em>(ataskarasya)</em> \u0441 \u0432\u043E\u0440\u043E\u043C <em>(taskara\u2026 api)</em>.</p><p class="eng">The fruit <em>(phalam)</em> of actions <em>(karma)</em>, [whether it is] good <em>(\u015Bubham)</em> [or] bad <em>(a\u015Bubham)</em>, [comes] certainly <em>(eva)</em> from the association <em>(sa\u1E45gam\u0101t)</em> with the false knowledge <em>(mithy\u0101-j\xF1\u0101nena)</em>. [Any] deficiency <em>(do\u1E63a\u1E25)</em> with respect to association <em>(sa\u1E45ga)</em> [is] undoubtedly <em>(hi)</em> adverse <em>(vi\u1E63ama\u1E25)</em>, like <em>(iva)</em> the contact <em>(yoga\u1E25)</em> of someone who is not a thief <em>(ataskarasya)</em> with a thief <em>(taskara\u2026 api)</em>.</p></div><div class="stanza"><a href="#s54" id="s54" class="num">54</a><p class="sans">\u0932\u094B\u0915\u0935\u094D\u092F\u0935\u0939\u093E\u0930\u0915\u0943\u0924\u093E\u0902 \u092F \u0907\u0939\u093E\u0935\u093F\u0926\u094D\u092F\u093E\u092E\u0941\u092A\u093E\u0938\u0924\u0947 \u092E\u0942\u0922\u093E\u0903 \u0964<br> \u0924\u0947 \u092F\u093E\u0928\u094D\u0924\u093F \u091C\u0928\u094D\u092E\u092E\u0943\u0924\u094D\u092F\u0942 \u0927\u0930\u094D\u092E\u093E\u0927\u0930\u094D\u092E\u093E\u0930\u094D\u0917\u0932\u093E\u092C\u0926\u094D\u0927\u093E\u0903 \u0965\u096B\u096A\u0965</p><p class="trans">Lokavyavah\u0101rak\u1E5Bt\u0101\u1E41 ya ih\u0101vidy\u0101mup\u0101sate m\u016B\u1E0Dh\u0101\u1E25 \u0964<br> Te y\u0101nti janmam\u1E5Bty\u016B dharm\u0101dharm\u0101rgal\u0101baddh\u0101\u1E25 \u096554\u0965</p><p>\u0413\u043B\u0443\u043F\u0446\u044B <em>(m\u016B\u1E0Dh\u0101\u1E25\u2026 te)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 <em>(ye)</em> \u0441\u043B\u0443\u0436\u0430\u0442 <em>(up\u0101sate)</em> \u0437\u0434\u0435\u0441\u044C <em>(iha)</em> \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0443 <em>(avidy\u0101m)</em> \u0441\u043E\u0437\u0434\u0430\u0432\u0430\u0435\u043C\u043E\u043C\u0443 <em>(k\u1E5Bt\u0101m)</em> \u043C\u0438\u0440\u0441\u043A\u043E\u0439 <em>(loka)</em> \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E <em>(vyavah\u0101ra)</em>, \u043E\u0431\u0440\u0435\u0447\u0435\u043D\u044B \u043D\u0430 <em>(y\u0101nti)</em> \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0438 \u0441\u043C\u0435\u0440\u0442\u044C <em>(janma-m\u1E5Bty\u016B)</em>, \u0437\u0430\u043F\u0435\u0440\u0442\u044B\u0435 <em>(\u0101baddh\u0101\u1E25)</em> \u043D\u0430 \u0437\u0430\u0441\u043E\u0432 <em>(argala)</em> \u0434\u043E\u043B\u0436\u043D\u043E\u0433\u043E <em>(dharma)</em> [\u0438] \u043D\u0435\u0434\u043E\u043B\u0436\u043D\u043E\u0433\u043E <em>(adharma)</em>.</p><p class="eng">The confused [beings] <em>(m\u016B\u1E0Dh\u0101\u1E25\u2026 te)</em> who <em>(ye)</em> serve <em>(up\u0101sate)</em> here \u2013in this world\u2013 <em>(iha)</em> the ignorance <em>(avidy\u0101m)</em> made of <em>(k\u1E5Bt\u0101m)</em> worldly <em>(loka)</em> practices <em>(vyavah\u0101ra)</em> \u2013mundane ways of behaving\u2013, being imprisoned <em>(\u0101baddh\u0101\u1E25)</em> by the bolt <em>(argala)</em> of what is to be done <em>(dharma)</em> [and] what is not to be done <em>(adharma)</em>, head for <em>(y\u0101nti)</em> birth and death <em>(janma-m\u1E5Bty\u016B)</em>.</p></div><div class="stanza"><a href="#s55" id="s55" class="num">55</a><p class="sans">\u0905\u091C\u094D\u091E\u093E\u0928\u0915\u093E\u0932\u0928\u093F\u091A\u093F\u0924\u0902 \u0927\u0930\u094D\u092E\u093E\u0927\u0930\u094D\u092E\u093E\u0924\u094D\u092E\u0915\u0902 \u0924\u0941 \u0915\u0930\u094D\u092E\u093E\u092A\u093F \u0964<br> \u091A\u093F\u0930\u0938\u091E\u094D\u091A\u093F\u0924\u092E\u093F\u0935 \u0924\u0942\u0932\u0902 \u0928\u0936\u094D\u092F\u0924\u093F \u0935\u093F\u091C\u094D\u091E\u093E\u0928\u0926\u0940\u092A\u094D\u0924\u093F\u0935\u0936\u093E\u0924\u094D \u0965\u096B\u096B\u0965</p><p class="trans">Aj\xF1\u0101nak\u0101lanicita\u1E41 dharm\u0101dharm\u0101tmaka\u1E41 tu karm\u0101pi \u0964<br> Cirasa\xF1citamiva t\u016Bla\u1E41 na\u015Byati vij\xF1\u0101nad\u012Bptiva\u015B\u0101t \u096555\u0965</p><p>\u0414\u0430\u0436\u0435 <em>(api)</em> \u043A\u0430\u0440\u043C\u0430 <em>(karma)</em>, \u043D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u043D\u0430\u044F <em>(nicitam)</em> \u0432\u043E \u0432\u0440\u0435\u043C\u044F <em>(k\u0101la)</em> [\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u044F \u0432] \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0438 <em>(aj\xF1\u0101na)</em>, [\u0438] \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u043D\u0430\u044F <em>(\u0101tmakam)</em> \u0431\u043B\u0430\u0433\u0438\u043C\u0438 \u0438 \u043D\u0435\u0431\u043B\u0430\u0433\u0438\u043C\u0438 \u0434\u0435\u044F\u043D\u0438\u044F\u043C\u0438 <em>(dharma-adharma\u2026 tu)</em>, \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0430\u0435\u0442\u0441\u044F <em>(na\u015Byati)</em> \u0441\u0438\u043B\u043E\u0439 <em>(va\u015B\u0101t)</em> \u0441\u0432\u0435\u0442\u0430 <em>(d\u012Bpti)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F <em>(vij\xF1\u0101na)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E <em>(iva)</em> \u0434\u0430\u0432\u043D\u043E <em>(cira)</em> \u0441\u0432\u0430\u043B\u0435\u043D\u043D\u043E\u043C\u0443 \u0432 \u043A\u0443\u0447\u0443 <em>(sa\xF1citam)</em> \u0445\u043B\u043E\u043F\u043A\u0443 <em>(t\u016Blam)</em>.</p><p class="eng">Even <em>(api)</em> the residual impression [derived from actions] <em>(karma)</em> based on <em>(\u0101tmakam)</em> what is to be done and what is not to be done <em>(dharma-adharma\u2026 tu)</em> which was accumulated <em>(nicitam)</em> during the time <em>(k\u0101la)</em> of ignorance <em>(aj\xF1\u0101na)</em> [just] disappears <em>(na\u015Byati)</em> by force of <em>(va\u015B\u0101t)</em> the Light <em>(d\u012Bpti)</em> of the special Knowledge <em>(vij\xF1\u0101na)</em> just as <em>(iva)</em> goose-cotton \u2013the soft feathers of a goose\u2013 <em>(t\u016Blam)</em> heaped up <em>(sa\xF1citam)</em> for a long time <em>(cira)</em>[is instantly reduced to ashes by means of a luminous fire].</p></div><div class="stanza"><a href="#s56" id="s56" class="num">56</a><p class="sans">\u091C\u094D\u091E\u093E\u0928\u092A\u094D\u0930\u093E\u092A\u094D\u0924\u094C \u0915\u0943\u0924\u092E\u092A\u093F \u0928 \u092B\u0932\u093E\u092F \u0924\u0924\u094B\u093D\u0938\u094D\u092F \u091C\u0928\u094D\u092E \u0915\u0925\u092E\u094D \u0964<br> \u0917\u0924\u091C\u0928\u094D\u092E\u092C\u0928\u094D\u0927\u092F\u094B\u0917\u094B \u092D\u093E\u0924\u093F \u0936\u093F\u0935\u093E\u0930\u094D\u0915\u0903 \u0938\u094D\u0935\u0926\u0940\u0927\u093F\u0924\u093F\u092D\u093F\u0903 \u0965\u096B\u096C\u0965</p><p class="trans">J\xF1\u0101napr\u0101ptau k\u1E5Btamapi na phal\u0101ya tato\u2019sya janma katham \u0964<br> Gatajanmabandhayogo bh\u0101ti \u015Biv\u0101rka\u1E25 svad\u012Bdhitibhi\u1E25 \u096556\u0965</p><p>\u0414\u043B\u044F \u0434\u043E\u0441\u0442\u0438\u0433\u0448\u0435\u0433\u043E <em>(pr\u0101ptau)</em> \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na)</em>, \u0434\u0430\u0436\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(k\u1E5Btam api)</em> \u043D\u0435 <em>(na)</em> \u043F\u0440\u0438\u043D\u043E\u0441\u044F\u0442 \u043F\u043B\u043E\u0434\u0430 <em>(phal\u0101ya)</em>. \u041A\u0430\u043A <em>(katham)</em> \u043F\u043E\u0441\u043B\u0435 \u044D\u0442\u043E\u0433\u043E <em>(tatas)</em> [\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E] \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435 <em>(janma)</em> \u0434\u043B\u044F \u043D\u0435\u0433\u043E <em>(asya)</em>? \u0421\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439 <em>(gata)</em> \u043E\u0442 \u0441\u0432\u044F\u0437\u0438 <em>(yoga\u1E25)</em> \u0441 \u0443\u0437\u0430\u043C\u0438 <em>(bandha)</em> \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(janma)</em> \u0421\u043E\u043B\u043D\u0446\u0435\u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0439 \u0428\u0438\u0432\u0430 <em>(\u015Biv\u0101rka\u1E25)</em> \u0431\u043B\u0438\u0441\u0442\u0430\u0435\u0442 <em>(bh\u0101ti)</em> \u0432 \u043B\u0443\u0447\u0430\u0445 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0438\u044F\u043D\u0438\u044F <em>(sva-d\u012Bdhitibhi\u1E25)</em>.</p><p class="eng">On the attainment <em>(pr\u0101ptau)</em> of Knowledge <em>(j\xF1\u0101na)</em>, [the residual impression of the action] which was done [before] <em>(k\u1E5Btam api)</em> does not <em>(na)</em> bear fruit <em>(phal\u0101ya)</em>. How <em>(katham)</em> then <em>(tatas)</em> [would there be] a birth <em>(janma)</em> for this [Yog\u012B] <em>(asya)</em>? [Such a great Yog\u012B] in whom the connection <em>(yoga\u1E25)</em> with bondage <em>(bandha)</em> [consisting of] birth <em>(janma)</em> is gone <em>(gata)</em> shines forth <em>(bh\u0101ti)</em> as a Sun <em>(arka\u1E25)</em> [whose essence is] \u015Aiva <em>(\u015Biva)</em> endowed with His own rays <em>(sva-d\u012Bdhitibhi\u1E25)</em>.</p></div><div class="stanza"><a href="#s57" id="s57" class="num">57</a><p class="sans">\u0924\u0941\u0937\u0915\u092E\u094D\u092C\u0941\u0915\u0915\u093F\u0902\u0936\u093E\u0930\u0941\u0915\u092E\u0941\u0915\u094D\u0924\u0902 \u092C\u0940\u091C\u0902 \u092F\u0925\u093E\u0919\u094D\u0915\u0941\u0930\u0902 \u0915\u0941\u0930\u0941\u0924\u0947 \u0964<br> \u0928\u0948\u0935 \u0924\u0925\u093E\u0923\u0935\u092E\u093E\u092F\u093E\u0915\u0930\u094D\u092E\u0935\u093F\u092E\u0941\u0915\u094D\u0924\u094B \u092D\u0935\u093E\u0919\u094D\u0915\u0941\u0930\u0902 \u0939\u094D\u092F\u093E\u0924\u094D\u092E\u093E \u0965\u096B\u096D\u0965</p><p class="trans">Tu\u1E63akambukaki\u1E41\u015B\u0101rukamukta\u1E41 b\u012Bja\u1E41 yath\u0101\u1E45kura\u1E41 kurute \u0964<br> Naiva tath\u0101\u1E47avam\u0101y\u0101karmavimukto bhav\u0101\u1E45kura\u1E41 hy\u0101tm\u0101 \u096557\u0965</p><p>\u041A\u0430\u043A <em>(yath\u0101)</em> \u0441\u0435\u043C\u044F <em>(b\u012Bjam)</em>, \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0451\u043D\u043D\u043E\u0435 <em>(muktam)</em> \u043E\u0442 \u0448\u0435\u043B\u0443\u0445\u0438 <em>(tu\u1E63a)</em>, \u043E\u0441\u0442\u0438 <em>(kambuka)</em> [\u0438] \u0437\u0430\u0440\u043E\u0434\u044B\u0448\u0430 <em>(ki\u1E41\u015B\u0101ruka)</em> \u043D\u0435 \u0434\u0430\u0451\u0442 <em>(kurute)</em> \u0440\u043E\u0441\u0442\u043A\u0430 <em>(a\u1E45kura)</em>, \u0442\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em> \u0434\u0443\u0448\u0430 <em>(\u0101tm\u0101)</em>, \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0441\u0432\u043E\u0431\u043E\u0434\u0438\u0432\u0448\u0435\u0435\u0441\u044F \u043E\u0442 <em>(vimukta\u1E25)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(\u0101\u1E47ava)</em>, \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(m\u0101y\u0101)</em> [\u0438] \u043A\u0430\u0440\u043C\u044B <em>(karma)</em>, \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(hi)</em> \u043D\u0435 <em>(na eva)</em> \u0434\u0430\u0451\u0442 \u0440\u043E\u0441\u0442\u043A\u0430 <em>(a\u1E45kuram)</em> [\u0431\u0443\u0434\u0443\u0449\u0435\u0433\u043E] \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(bhava)</em>.</p><p class="eng">Just as <em>(yath\u0101)</em> a grain or seed <em>(b\u012Bjam)</em> being separated <em>(muktam)</em> from [its] husk <em>(tu\u1E63a)</em>, bran <em>(kambuka)</em> [and] beard <em>(ki\u1E41\u015B\u0101ruka)</em> does not produce <em>(kurute)</em> a sprout <em>(a\u1E45kura)</em>, similarly <em>(tath\u0101)</em> the Self <em>(\u0101tm\u0101)</em>, when He is completely freed from <em>(vimukta\u1E25)</em> \u0100\u1E47avamala <em>(\u0101\u1E47ava)</em>, M\u0101y\u012Byamala <em>(m\u0101y\u0101)</em> [and] K\u0101rmamala <em>(karma)</em>, does not <em>(na eva)</em> [produce] the sprout <em>(a\u1E45kuram)</em> [known as] Transmigration <em>(bhava)</em> undoubtedly <em>(hi)</em>.</p></div><div class="stanza"><a href="#s58" id="s58" class="num">58</a><p class="sans">\u0906\u0924\u094D\u092E\u091C\u094D\u091E\u094B \u0928 \u0915\u0941\u0924\u0936\u094D\u091A\u0928 \u092C\u093F\u092D\u0947\u0924\u093F \u0938\u0930\u094D\u0935\u0902 \u0939\u093F \u0924\u0938\u094D\u092F \u0928\u093F\u091C\u0930\u0942\u092A\u092E\u094D \u0964<br> \u0928\u0948\u0935 \u091A \u0936\u094B\u091A\u0924\u093F \u092F\u0938\u094D\u092E\u093E\u0924\u094D\u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0947 \u0928\u093E\u0936\u093F\u0924\u093E \u0928\u093E\u0938\u094D\u0924\u093F \u0965\u096B\u096E\u0965</p><p class="trans">\u0100tmaj\xF1o na kuta\u015Bcana bibheti sarva\u1E41 hi tasya nijar\u016Bpam \u0964<br> Naiva ca \u015Bocati yasm\u0101tparam\u0101rthe n\u0101\u015Bit\u0101 n\u0101sti \u096558\u0965</p><p>\u041E\u0441\u043E\u0437\u043D\u0430\u0432\u0448\u0438\u0439 <em>(j\xF1a\u1E25)</em> \xAB\u042F\xBB <em>(\u0101tma)</em> \u043D\u0438\u043A\u043E\u0433\u043E <em>(kuta\u015Bcana)</em> \u043D\u0435 <em>(na)</em> \u0431\u043E\u0438\u0442\u0441\u044F <em>(bibheti)</em> \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(hi)</em> \u0432\u0441\u0451 <em>(sarvam)</em> \u0438\u043C\u0435\u0435\u0442 \u0444\u043E\u0440\u043C\u0443 <em>(r\u016Bpam)</em> \u0435\u0433\u043E <em>(tasya)</em> \u0421\u0430\u043C\u043E\u0433\u043E <em>(nija)</em>, \u0438 \u0442\u0430\u043A\u0436\u0435 \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 <em>(na eva ca)</em> \u043E\u0433\u043E\u0440\u0447\u0430\u0435\u0442\u0441\u044F <em>(\u015Bocati)</em>, \u0432\u0435\u0434\u044C <em>(yasm\u0101t)</em> \u0432 \u0412\u044B\u0441\u0448\u0435\u0439 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(parama-arthe)</em> \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(na asti)</em> \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u044F <em>(n\u0101\u015Bit\u0101)</em>.</p><p class="eng">The one who knows <em>(j\xF1a\u1E25)</em> [his] Self <em>(\u0101tma)</em> is not <em>(na)</em> afraid <em>(bibheti)</em> of anyone <em>(kuta\u015Bcana)</em> because <em>(hi)</em> all <em>(sarvam)</em> has the form <em>(r\u016Bpam)</em> of his <em>(tasya)</em> own Self <em>(nija)</em>, nor does <em>(na eva ca)</em> he grieve <em>(\u015Bocati)</em> since <em>(yasm\u0101t)</em> in the Highest Reality <em>(parama-arthe)</em> there is no <em>(na asti)</em> state of perishing <em>(n\u0101\u015Bit\u0101)</em>.</p></div><div class="stanza"><a href="#s59" id="s59" class="num">59</a><p class="sans">\u0905\u0924\u093F\u0917\u0942\u0922\u0939\u0943\u0926\u092F\u0917\u091E\u094D\u091C\u092A\u094D\u0930\u0930\u0942\u0922\u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0930\u0924\u094D\u0928\u0938\u091E\u094D\u091A\u092F\u0924\u0903 \u0964<br> \u0905\u0939\u092E\u0947\u0935\u0947\u0924\u093F \u092E\u0939\u0947\u0936\u094D\u0935\u0930\u092D\u093E\u0935\u0947 \u0915\u093E \u0926\u0941\u0930\u094D\u0917\u0924\u093F\u0903 \u0915\u0938\u094D\u092F \u0965\u096B\u096F\u0965</p><p class="trans">Atig\u016B\u1E0Dhah\u1E5Bdayaga\xF1japrar\u016B\u1E0Dhaparam\u0101rtharatnasa\xF1cayata\u1E25 \u0964<br> Ahameveti mahe\u015Bvarabh\u0101ve k\u0101 durgati\u1E25 kasya \u096559\u0965</p><p>\u0412 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 <em>(bh\u0101ve)</em> \u0412\u0435\u043B\u0438\u043A\u043E\u0433\u043E <em>(mah\u0101)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(\u012B\u015Bvara)</em>, [\u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u043E\u043C] \u043A\u0430\u043A \u201C\u0422\u043E\u043B\u044C\u043A\u043E \u042F\u201D <em>(aham eva iti)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442\u043E\u043C \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u0435\u043C <em>(sa\xF1cayata\u1E25)</em> \u0434\u0440\u0430\u0433\u043E\u0446\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(ratna)</em> \u0412\u044B\u0441\u0448\u0435\u0439 \u0438\u0441\u0442\u0438\u043D\u044B <em>(parama-artha)</em>, \u0434\u043E\u0431\u044B\u0442\u043E\u0439 <em>(prar\u016B\u1E0Dha)</em> \u0432 \u043D\u0430\u0434\u0451\u0436\u043D\u043E \u0441\u043E\u043A\u0440\u044B\u0442\u043E\u0439 <em>(ati-g\u016B\u1E0Dha)</em> \u0441\u043E\u043A\u0440\u043E\u0432\u0438\u0449\u043D\u0438\u0446\u0435 <em>(ga\xF1ja)</em> \u0441\u0435\u0440\u0434\u0446\u0430 <em>(h\u1E5Bdaya)</em>, \u043E\u0442\u043A\u0443\u0434\u0430 \u0432\u0437\u044F\u0442\u044C\u0441\u044F <em>(k\u0101)</em> \u043D\u0435\u0443\u0434\u0430\u0447\u0435 <em>(durgati\u1E25)</em> [\u0438] \u0434\u043B\u044F \u043A\u043E\u0433\u043E <em>(kasya)</em>?</p><p class="eng">In the State <em>(bh\u0101ve)</em> of the Great <em>(mah\u0101)</em> Lord <em>(\u012B\u015Bvara)</em> [in the form of] \u201CI\u201D <em>(aham eva iti)</em>, acquired by the collection <em>(sa\xF1cayata\u1E25)</em> of gems <em>(ratna)</em> [known as] the Highest Truth <em>(parama-artha)</em> arisen from <em>(prar\u016B\u1E0Dha)</em> the well hidden <em>(ati-g\u016B\u1E0Dha)</em> treasury \u2013jewel room\u2013 <em>(ga\xF1ja)</em> of the Heart \u2013Consciousness in Absolute Freedom\u2013 <em>(h\u1E5Bdaya)</em>, what <em>(k\u0101)</em> poverty <em>(durgati\u1E25)</em> [could there be?, and even if there was such a poverty,] whose <em>(kasya)</em>[would it be]?</p></div><div class="stanza"><a href="#s60" id="s60" class="num">60</a><p class="sans">\u092E\u094B\u0915\u094D\u0937\u0938\u094D\u092F \u0928\u0948\u0935 \u0915\u093F\u091E\u094D\u091A\u093F\u0926\u094D\u0927\u093E\u092E\u093E\u0938\u094D\u0924\u093F \u0928 \u091A\u093E\u092A\u093F \u0917\u092E\u0928\u092E\u0928\u094D\u092F\u0924\u094D\u0930 \u0964<br> \u0905\u091C\u094D\u091E\u093E\u0928\u0917\u094D\u0930\u0928\u094D\u0925\u093F\u092D\u093F\u0926\u093E \u0938\u094D\u0935\u0936\u0915\u094D\u0924\u094D\u092F\u092D\u093F\u0935\u094D\u092F\u0915\u094D\u0924\u0924\u093E \u092E\u094B\u0915\u094D\u0937\u0903 \u0965\u096C\u0966\u0965</p><p class="trans">Mok\u1E63asya naiva ki\xF1ciddh\u0101m\u0101sti na c\u0101pi gamanamanyatra \u0964<br> Aj\xF1\u0101nagranthibhid\u0101 sva\u015Baktyabhivyaktat\u0101 mok\u1E63a\u1E25 \u096560\u0965</p><p>\u0412 \u0441\u043B\u0443\u0447\u0430\u0435 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(mok\u1E63asya)</em>, \u043D\u0435 \u0438\u043C\u0435\u0435\u0442 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F <em>(na eva ki\xF1cid asti)</em> \u043C\u0435\u0441\u0442\u043E \u043E\u0431\u0438\u0442\u0430\u043D\u0438\u044F <em>(dh\u0101ma)</em> \u0438\u043B\u0438 <em>(na ca api)</em> \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 <em>(gamanam)</em> \u043A\u0443\u0434\u0430-\u0442\u043E \u0435\u0449\u0451 <em>(anyatra)</em>. \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 <em>(mok\u1E63a\u1E25)</em> <em>\u2014</em>\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(abhivyaktat\u0101)</em> \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0438\u043B\u044B <em>(\u015Bakti)</em>, \u0440\u0430\u0437\u0440\u0443\u0431\u0430\u044E\u0449\u0435\u0439 <em>(bhid\u0101)</em> \u0443\u0437\u0435\u043B <em>(granthi)</em> \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0430 <em>(aj\xF1\u0101na)</em>.</p><p class="eng">In the case of Liberation <em>(mok\u1E63asya)</em>, there is neither <em>(na eva ki\xF1cid asti)</em> an abode <em>(dh\u0101ma)</em> nor <em>(na ca api)</em> a going <em>(gamanam)</em> to another place <em>(anyatra)</em>. Liberation <em>(mok\u1E63a\u1E25)</em> [is simply] the manifestation <em>(abhivyaktat\u0101)</em> of one\u2019s own <em>(sva)</em> Powers <em>(\u015Bakti)</em> by the piercing <em>(bhid\u0101)</em> of the knot <em>(granthi)</em> of ignorance <em>(aj\xF1\u0101na)</em>.</p></div><div class="stanza"><a href="#s61" id="s61" class="num">61</a><p class="sans">\u092D\u093F\u0928\u094D\u0928\u093E\u091C\u094D\u091E\u093E\u0928\u0917\u094D\u0930\u0928\u094D\u0925\u093F\u0930\u094D\u0917\u0924\u0938\u0928\u094D\u0926\u0947\u0939\u0903 \u092A\u0930\u093E\u0915\u0943\u0924\u092D\u094D\u0930\u093E\u0928\u094D\u0924\u093F\u0903 \u0964<br> \u092A\u094D\u0930\u0915\u094D\u0937\u0940\u0923\u092A\u0941\u0923\u094D\u092F\u092A\u093E\u092A\u094B \u0935\u093F\u0917\u094D\u0930\u0939\u092F\u094B\u0917\u0947\u093D\u092A\u094D\u092F\u0938\u094C \u092E\u0941\u0915\u094D\u0924\u0903 \u0965\u096C\u0967\u0965</p><p class="trans">Bhinn\u0101j\xF1\u0101nagranthirgatasandeha\u1E25 par\u0101k\u1E5Btabhr\u0101nti\u1E25 \u0964<br> Prak\u1E63\u012B\u1E47apu\u1E47yap\u0101po vigrahayoge\u2019pyasau mukta\u1E25 \u096561\u0965</p><p>\u0422\u043E\u0442 <em>(asau)</em>, \u0440\u0430\u0437\u0440\u0443\u0431\u0438\u0432\u0448\u0438\u0439 \u0443\u0437\u0435\u043B \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0430 <em>(bhinna-aj\xF1\u0101na-granthi\u1E25)</em>, \u0447\u044C\u0438 \u0441\u043E\u043C\u0435\u043D\u0438\u044F <em>(sandeha\u1E25)</em> \u0443\u0448\u043B\u0438 <em>(gata)</em>, \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(bhr\u0101nti\u1E25)</em> \u043E\u0442\u0431\u0440\u043E\u0448\u0435\u043D\u044B <em>(par\u0101k\u1E5Bta)</em>, [\u0430] \u0431\u043B\u0430\u0433\u043E\u0447\u0435\u0441\u0442\u0438\u0435 <em>(pu\u1E47ya)</em> [\u0438] \u0433\u0440\u0435\u0445 <em>(p\u0101pa\u1E25)</em> \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u044B <em>(prak\u1E63\u012B\u1E47a)</em>, \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0451\u043D <em>(mukta\u1E25)</em>, \u0445\u043E\u0442\u044F <em>(api)</em> \u0438 \u0441\u043E\u043F\u0440\u0438\u043A\u043E\u0441\u0430\u0435\u0442\u0441\u044F <em>(yoge)</em> \u0441 \u0442\u0435\u043B\u0435\u0441\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u043E\u0439 <em>(vigraha)</em>.</p><p class="eng">He <em>(asau)</em> who has pierced the knot of ignorance <em>(bhinna-aj\xF1\u0101na-granthi\u1E25)</em>, whose doubts <em>(sandeha\u1E25)</em> are gone <em>(gata)</em>, in whom confusion <em>(bhr\u0101nti\u1E25)</em> is disregarded <em>(par\u0101k\u1E5Bta)</em> [and] for whom virtue <em>(pu\u1E47ya)</em> [and] sin <em>(p\u0101pa\u1E25)</em> have vanished <em>(prak\u1E63\u012B\u1E47a)</em>, [is] a liberated one <em>(mukta\u1E25)</em> although <em>(api)</em> [he is] in connection <em>(yoge)</em> with the physical body \u2013the individual form\u2013 <em>(vigraha)</em>.</p></div><div class="stanza"><a href="#s62" id="s62" class="num">62</a><p class="sans">\u0905\u0917\u094D\u0928\u094D\u092F\u092D\u093F\u0926\u0917\u094D\u0927\u0902 \u092C\u0940\u091C\u0902 \u092F\u0925\u093E \u092A\u094D\u0930\u0930\u094B\u0939\u093E\u0938\u092E\u0930\u094D\u0925\u0924\u093E\u092E\u0947\u0924\u093F \u0964<br> \u091C\u094D\u091E\u093E\u0928\u093E\u0917\u094D\u0928\u093F\u0926\u0917\u094D\u0927\u092E\u0947\u0935\u0902 \u0915\u0930\u094D\u092E \u0928 \u091C\u0928\u094D\u092E\u092A\u094D\u0930\u0926\u0902 \u092D\u0935\u0924\u093F \u0965\u096C\u0968\u0965</p><p class="trans">Agnyabhidagdha\u1E41 b\u012Bja\u1E41 yath\u0101 praroh\u0101samarthat\u0101meti \u0964<br> J\xF1\u0101n\u0101gnidagdhameva\u1E41 karma na janmaprada\u1E41 bhavati \u096562\u0965</p><p>\u041A\u0430\u043A <em>(yath\u0101)</em> \u0441\u0435\u043C\u044F <em>(b\u012Bjam)</em>, \u043F\u0440\u043E\u043A\u0430\u043B\u0451\u043D\u043D\u043E\u0435 <em>(abhidagdham)</em> \u043D\u0430 \u043E\u0433\u043D\u0435 <em>(agni)</em>, \u043D\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E <em>(asamarthat\u0101m eti)</em> \u043F\u0440\u043E\u0440\u0430\u0441\u0442\u0438 <em>(praroha)</em>, \u0442\u0430\u043A\u0436\u0435 <em>(evam)</em> \u043A\u0430\u0440\u043C\u0430 <em>(karma)</em> \u043F\u0440\u043E\u043A\u0430\u043B\u0451\u043D\u043D\u0430\u044F <em>(dagdham)</em> \u043D\u0430 \u043E\u0433\u043D\u0435 <em>(agni)</em> \u0417\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na)</em> \u043D\u0435 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(na\u2026 bhavati)</em> \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 <em>(pradam)</em> \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(janma)</em>.</p><p class="eng">Just as <em>(yath\u0101)</em> a grain or seed <em>(b\u012Bjam)</em> burnt <em>(abhidagdham)</em> by fire <em>(agni)</em> is not capable of <em>(asamarthat\u0101m eti)</em> sprouting <em>(praroha)</em>, similarly <em>(evam)</em> the karma \u2013the residual impression of an action\u2013 <em>(karma)</em> scorched <em>(dagdham)</em> by the Fire <em>(agni)</em> of Knowledge <em>(j\xF1\u0101na)</em> is not <em>(na\u2026 bhavati)</em> a bestower <em>(pradam)</em> of birth <em>(janma)</em>.</p></div><div class="stanza"><a href="#s63" id="s63" class="num">63</a><p class="sans">\u092A\u0930\u093F\u092E\u093F\u0924\u092C\u0941\u0926\u094D\u0927\u093F\u0924\u094D\u0935\u0947\u0928 \u0939\u093F \u0915\u0930\u094D\u092E\u094B\u091A\u093F\u0924\u092D\u093E\u0935\u093F\u0926\u0947\u0939\u092D\u093E\u0935\u0928\u092F\u093E \u0964<br> \u0938\u0919\u094D\u0915\u0941\u091A\u093F\u0924\u093E \u091A\u093F\u0924\u093F\u0930\u0947\u0924\u0926\u094D\u0926\u0947\u0939\u0927\u094D\u0935\u0902\u0938\u0947 \u0924\u0925\u093E \u092D\u0935\u0924\u093F \u0965\u096C\u0969\u0965</p><p class="trans">Parimitabuddhitvena hi karmocitabh\u0101videhabh\u0101vanay\u0101 \u0964<br> Sa\u1E45kucit\u0101 citiretaddehadhva\u1E41se tath\u0101 bhavati \u096563\u0965</p><p>\u0421 \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435\u043C <em>(dhva\u1E41se)</em> \u044D\u0442\u043E\u0433\u043E <em>(etad)</em> \u0442\u0435\u043B\u0430 <em>(deha)</em>, \u0421\u0438\u043B\u0430 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(citi\u1E25)</em>, \u0441\u043E\u043A\u0440\u0430\u0449\u0430\u044F\u0441\u044C <em>(sa\u1E45kucit\u0101)</em>, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(bhavati)</em> \u0442\u043E\u0439 <em>(tath\u0101)</em> \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(bh\u0101vanay\u0101)</em> \u0431\u0443\u0434\u0443\u0449\u0435\u0433\u043E <em>(bh\u0101vi)</em> \u0442\u0435\u043B\u0430 <em>(deha)</em>, \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0433\u043E <em>(ucita)</em> \u043A\u0430\u0440\u043C\u0435 <em>(karma)</em>, [\u043D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u043D\u043E\u0439] \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u043E\u043C <em>(parimita-buddhitvena hi)</em>.</p><p class="eng">On the destruction <em>(dhva\u1E41se)</em> of this <em>(etad)</em> body <em>(deha)</em>, the [Power of] Consciousness <em>(citi\u1E25)</em>, by assuming contraction <em>(sa\u1E45kucit\u0101)</em>, becomes <em>(bhavati)</em> like that <em>(tath\u0101)</em> \u2013i.e. ready to generate a new birth\u2013 in accordance with the production or formation <em>(bh\u0101vanay\u0101)</em> of a future <em>(bh\u0101vi)</em> body <em>(deha)</em> that is suitable <em>(ucita)</em> for the karma or action <em>(karma)</em> [previously performed] with a limited intellectual state \u2013by a limited buddhi or intellect\u2013 <em>(parimita-buddhitvena hi)</em>.</p></div><div class="stanza"><a href="#s64-66" id="s64-66" class="num">64-66</a><p class="sans">\u092F\u0926\u093F \u092A\u0941\u0928\u0930\u092E\u0932\u0902 \u092C\u094B\u0927\u0902 \u0938\u0930\u094D\u0935\u0938\u092E\u0941\u0924\u094D\u0924\u0940\u0930\u094D\u0923\u092C\u094B\u0926\u094D\u0927\u0943\u0915\u0930\u094D\u0924\u0943\u092E\u092F\u092E\u094D \u0964<br> \u0935\u093F\u0924\u0924\u092E\u0928\u0938\u094D\u0924\u092E\u093F\u0924\u094B\u0926\u093F\u0924\u092D\u093E\u0930\u0942\u092A\u0902 \u0938\u0924\u094D\u092F\u0938\u0919\u094D\u0915\u0932\u094D\u092A\u092E\u094D \u0965\u096C\u096A\u0965</p><p class="sans">\u0926\u093F\u0915\u094D\u0915\u093E\u0932\u0915\u0932\u0928\u0935\u093F\u0915\u0932\u0902 \u0927\u094D\u0930\u0941\u0935\u092E\u0935\u094D\u092F\u092F\u092E\u0940\u0936\u094D\u0935\u0930\u0902 \u0938\u0941\u092A\u0930\u093F\u092A\u0942\u0930\u094D\u0923\u092E\u094D \u0964<br> \u092C\u0939\u0941\u0924\u0930\u0936\u0915\u094D\u0924\u093F\u0935\u094D\u0930\u093E\u0924\u092A\u094D\u0930\u0932\u092F\u094B\u0926\u092F\u0935\u093F\u0930\u091A\u0928\u0948\u0915\u0915\u0930\u094D\u0924\u093E\u0930\u092E\u094D \u0965\u096C\u096B\u0965</p><p class="sans">\u0938\u0943\u0937\u094D\u091F\u094D\u092F\u093E\u0926\u093F\u0935\u093F\u0927\u093F\u0938\u0941\u0935\u0947\u0927\u0938\u092E\u093E\u0924\u094D\u092E\u093E\u0928\u0902 \u0936\u093F\u0935\u092E\u092F\u0902 \u0935\u093F\u092C\u0941\u0927\u094D\u092F\u0947\u0924 \u0964<br> \u0915\u0925\u092E\u093F\u0935 \u0938\u0902\u0938\u093E\u0930\u0940 \u0938\u094D\u092F\u093E\u0926\u094D\u0935\u093F\u0924\u0924\u0938\u094D\u092F \u0915\u0941\u0924\u0903 \u0915\u094D\u0935 \u0935\u093E \u0938\u0930\u0923\u092E\u094D \u0965\u096C\u096C\u0965</p><p class="trans">Yadi punaramala\u1E41 bodha\u1E41 sarvasamutt\u012Br\u1E47aboddh\u1E5Bkart\u1E5Bmayam \u0964<br> Vitatamanastamitoditabh\u0101r\u016Bpa\u1E41 satyasa\u1E45kalpam \u096564\u0965</p><p class="trans">Dikk\u0101lakalanavikala\u1E41 dhruvamavyayam\u012B\u015Bvara\u1E41 suparip\u016Br\u1E47am \u0964<br> Bahutara\u015Baktivr\u0101tapralayodayaviracanaikakart\u0101ram \u096565\u0965</p><p class="trans">S\u1E5B\u1E63\u1E6Dy\u0101dividhisuvedhasam\u0101tm\u0101na\u1E41 \u015Bivamaya\u1E41 vibudhyeta \u0964<br> Kathamiva sa\u1E41s\u0101r\u012B sy\u0101dvitatasya kuta\u1E25 kva v\u0101 sara\u1E47am \u096566\u0965</p><p>\u0412\u043F\u0440\u043E\u0447\u0435\u043C <em>(punar)</em>, \u0435\u0441\u043B\u0438 <em>(yadi)</em> \u043A\u0442\u043E-\u0442\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u043B <em>(vibudhyeta)</em> \u0441\u0435\u0431\u044F <em>(\u0101tm\u0101nam)</em> \u043A\u0430\u043A <em>(mayam)</em> \u0428\u0438\u0432\u0443 <em>(\u015Biva)</em>, \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E\u0435 \u043E\u0442 \u043E\u043C\u0440\u0430\u0447\u0435\u043D\u0438\u0439 <em>(amalam)</em> \u0447\u0438\u0441\u0442\u043E\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(bodham)</em>, \u043A\u0430\u043A \u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0433\u043E <em>(boddh\u1E5B-kart\u1E5B-mayam)</em>, \u0442\u0440\u0430\u043D\u0441\u0446\u0435\u043D\u0434\u0435\u043D\u0442\u043D\u043E\u0433\u043E <em>(samutt\u012Br\u1E47am)</em> \u0432\u0441\u0435\u043C\u0443 <em>(sarva)</em>, \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0433\u043E <em>(vitatam)</em>, [\u0438\u043C\u0435\u044E\u0449\u0435\u0433\u043E] \u0444\u043E\u0440\u043C\u0443 <em>(r\u016Bpam)</em> \u043D\u0435 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0433\u043E \u0438 \u043D\u0435 \u0438\u0441\u0447\u0435\u0437\u0430\u044E\u0449\u0435\u0433\u043E <em>(anastamita-udita)</em> \u0441\u0438\u044F\u043D\u0438\u044F <em>(bh\u0101)</em>, \u0447\u044C\u0438 \u043D\u0430\u043C\u0435\u0440\u0435\u043D\u0438\u044F <em>(sa\u1E45kalpam)</em> [\u0432\u0441\u0435\u0433\u0434\u0430] \u0438\u0441\u0442\u0438\u043D\u043D\u044B <em>(satya)</em>, \u043A\u0442\u043E \u0441\u0432\u043E\u0431\u043E\u0434\u0435\u043D \u043E\u0442 <em>(vikalam)</em> \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430 <em>(dik)</em>, \u0432\u0440\u0435\u043C\u0435\u043D\u0438 <em>(k\u0101la)</em> [\u0438] \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F <em>(kalana)</em>, \u043D\u0435\u0434\u0432\u0438\u0436\u0438\u043C\u043E\u0433\u043E <em>(dhruvam)</em>, \u043D\u0435\u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0438\u043C\u043E\u0433\u043E <em>(avyayam)</em>, \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043F\u043E\u043B\u043D\u043E\u0433\u043E <em>(suparip\u016Br\u1E47am)</em> \u0412\u043B\u0430\u0434\u044B\u043A\u0443 <em>(\u012B\u015Bvaram)</em>, \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(eka)</em> \u0434\u0435\u044F\u0442\u0435\u043B\u044F <em>(kart\u0101ram)</em>, \u043F\u0440\u0435\u0442\u0432\u043E\u0440\u044F\u044E\u0449\u0435\u0433\u043E <em>(viracana)</em> \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(udaya)</em> [\u0438] \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(pralaya)</em> \u0431\u0435\u0441\u0447\u0438\u0441\u043B\u0435\u043D\u043D\u044B\u0445 <em>(bahutara)</em> \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432 <em>(vr\u0101ta)</em> \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u0438\u043B <em>(\u015Bakti)</em>, \u0432\u0438\u0440\u0442\u0443\u043E\u0437\u043D\u043E\u0433\u043E \u0430\u0432\u0442\u043E\u0440\u0430 <em>(suvedhasam)</em> \u0441\u0443\u0434\u044C\u0431\u044B <em>(vidhi)</em> \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F <em>(s\u1E5B\u1E63\u1E6Di)</em> \u0438 \u043F\u0440\u043E\u0447\u0435\u0433\u043E <em>(\u0101di)</em>, \u043A\u0430\u043A \u0442\u043E\u0433\u0434\u0430 <em>(katham iva)</em> \u043E\u043D \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C <em>(sy\u0101t)</em> \u0437\u0430\u043B\u043E\u0436\u043D\u0438\u043A\u043E\u043C \u0441\u0430\u043D\u0441\u0430\u0440\u044B <em>(sa\u1E41s\u0101r\u012B)</em>? \u0414\u043B\u044F \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0435\u0433\u043E <em>(vitatasya)</em>, \u043E\u0442\u043A\u0443\u0434\u0430 <em>(kutas)</em> \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435 <em>(sara\u1E47am)</em> \u0438 \u043A\u0443\u0434\u0430 <em>(kva v\u0101)</em>?</p><p class="eng">However <em>(punar)</em>, if <em>(yadi)</em> someone became aware of <em>(vibudhyeta)</em> the Self <em>(\u0101tm\u0101nam)</em> as being <em>(mayam)</em> \u015Aiva <em>(\u015Biva)</em>,[that is to say, if he realized that his own Self is Him] who is Pure Consciousness <em>(bodham)</em> devoid of mala-s or impurities <em>(amalam)</em>, who is the Knower and Doer <em>(boddh\u1E5B-kart\u1E5B-mayam)</em> that transcends <em>(samutt\u012Br\u1E47am)</em> all <em>(sarva)</em>, All-pervasive <em>(vitatam)</em>, whose Form <em>(r\u016Bpam)</em> is Brightness <em>(bh\u0101)</em> [never] setting [or] rising <em>(anastamita-udita)</em>, whose Resolutions or definite Desires <em>(sa\u1E45kalpam)</em> [always] come true <em>(satya)</em>, who is Free from <em>(vikalam)</em> directions \u2013space\u2013 <em>(dik)</em>, time <em>(k\u0101la)</em> [and] formation \u2013generation of forms\u2013 <em>(kalana)</em>, Immovable <em>(dhruvam)</em>, Imperishable <em>(avyayam)</em>, the [Free] Lord <em>(\u012B\u015Bvaram)</em> who is exceedingly Complete \u2013very Full\u2013 <em>(suparip\u016Br\u1E47am)</em>, the sole <em>(eka)</em> Agent <em>(kart\u0101ram)</em> performing <em>(viracana)</em> the emergence <em>(udaya)</em> [and] dissolution <em>(pralaya)</em> of the numerous <em>(bahutara)</em> groups <em>(vr\u0101ta)</em> of powers <em>(\u015Bakti)</em>, [and] the very skillful Author <em>(suvedhasam)</em> of the acts and precepts <em>(vidhi)</em> relating to the universal manifestation \u2013creation\u2013 <em>(s\u1E5B\u1E63\u1E6Di)</em> and so forth <em>(\u0101di)</em>, [then] how <em>(katham iva)</em> could he [possibly] be <em>(sy\u0101t)</em> a transmigratory creature <em>(sa\u1E41s\u0101r\u012B)</em>? In the case of someone who is that Vitata or All-pervasive <em>(vitatasya)</em>, how <em>(kutas)</em> [could there be his] moving \u2013transmigrating\u2013 <em>(sara\u1E47am)</em> [and] to where possibly <em>(kva v\u0101)</em>?</p></div><div class="stanza"><a href="#s67" id="s67" class="num">67</a><p class="sans">\u0907\u0924\u093F \u092F\u0941\u0915\u094D\u0924\u093F\u092D\u093F\u0930\u092A\u093F \u0938\u093F\u0926\u094D\u0927\u0902 \u092F\u0924\u094D\u0915\u0930\u094D\u092E \u091C\u094D\u091E\u093E\u0928\u093F\u0928\u094B \u0928 \u0938\u092B\u0932\u0902 \u0924\u0924\u094D \u0964<br> \u0928 \u092E\u092E\u0947\u0926\u092E\u092A\u093F \u0924\u0941 \u0924\u0938\u094D\u092F\u0947\u0924\u093F \u0926\u093E\u0930\u094D\u0922\u094D\u092F\u0924\u094B \u0928\u0939\u093F \u092B\u0932\u0902 \u0932\u094B\u0915\u0947 \u0965\u096C\u096D\u0965</p><p class="trans">Iti yuktibhirapi siddha\u1E41 yatkarma j\xF1\u0101nino na saphala\u1E41 tat \u0964<br> Na mamedamapi tu tasyeti d\u0101r\u1E0Dhyato nahi phala\u1E41 loke \u096567\u0965</p><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(iti \u2026api)</em> \u0430\u0440\u0433\u0443\u043C\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E <em>(yuktibhi\u1E25)</em> \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442\u0441\u044F <em>(siddham)</em>, \u0447\u0442\u043E <em>(yat)</em> \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(karma\u2026 tad)</em> \u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E <em>(j\xF1\u0101nina\u1E25)</em> \u043D\u0435 \u043F\u0440\u0438\u043D\u043E\u0441\u044F\u0442 \u043F\u043B\u043E\u0434\u043E\u0432 <em>(na sa-phalam)</em>. \u201C\u042D\u0442\u043E <em>(idam)</em> \u043D\u0435 <em>(na)</em> \u043C\u043E\u0451 <em>(mama)</em>, \u043D\u043E \u0442\u043E\u043B\u044C\u043A\u043E <em>(api tu)</em> \u0415\u0433\u043E <em>(tasya iti)</em>\u201C, \u0434\u043B\u044F \u0443\u0442\u0432\u0435\u0440\u0434\u0438\u0432\u0449\u0435\u0433\u043E\u0441\u044F \u0432 \u044D\u0442\u043E\u043C <em>(d\u0101r\u1E0Dhyatas)</em> \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(nahi)</em> \u043F\u043B\u043E\u0434\u0430 <em>(phalam)</em> \u0432 [\u044D\u0442\u043E\u043C] \u043C\u0438\u0440\u0435 <em>(loke)</em>.</p><p class="eng">Through the firm conviction that <em>(d\u0101r\u1E0Dhyatas)</em> \u201CThis <em>(idam)</em> is not <em>(na)</em> mine <em>(mama)</em> but <em>(api tu)</em> His \u2013of the Great Lord\u2013 <em>(tasya iti)</em>\u201C, there is no <em>(nahi)</em> [action-related] fruit <em>(phalam)</em> in [this] world <em>(loke)</em>. By reasonings <em>(yuktibhi\u1E25 api)</em> of that type <em>(iti)</em>, it is proved <em>(siddham)</em> that <em>(yat)</em> the action <em>(karma\u2026 tad)</em> does not bear fruit <em>(na sa-phalam)</em> as far as a Knower of the Self is concerned <em>(j\xF1\u0101nina\u1E25)</em>.</p></div><div class="stanza"><a href="#s68" id="s68" class="num">68</a><p class="sans">\u0907\u0924\u094D\u0925\u0902 \u0938\u0915\u0932\u0935\u093F\u0915\u0932\u094D\u092A\u093E\u0928\u094D\u092A\u094D\u0930\u0924\u093F\u092C\u0941\u0926\u094D\u0927\u094B \u092D\u093E\u0935\u0928\u093E\u0938\u092E\u0940\u0930\u0923\u0924\u0903 \u0964<br> \u0906\u0924\u094D\u092E\u091C\u094D\u092F\u094B\u0924\u093F\u0937\u093F \u0926\u0940\u092A\u094D\u0924\u0947 \u091C\u0941\u0939\u094D\u0935\u091C\u094D\u091C\u094D\u092F\u094B\u0924\u093F\u0930\u094D\u092E\u092F\u094B \u092D\u0935\u0924\u093F \u0965\u096C\u096E\u0965</p><p class="trans">Ittha\u1E41 sakalavikalp\u0101npratibuddho bh\u0101van\u0101sam\u012Bra\u1E47ata\u1E25 \u0964<br> \u0100tmajyoti\u1E63i d\u012Bpte juhvajjyotirmayo bhavati \u096568\u0965</p><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(ittham)</em>, \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0451\u043D\u043D\u044B\u0439 <em>(pratibuddha\u1E25)</em> \u0432\u0435\u0442\u0440\u043E\u043C <em>(sam\u012Bra\u1E47ata\u1E25)</em> \u0441\u0430\u043C\u043E\u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F <em>(bh\u0101van\u0101)</em>, \u043F\u0440\u0435\u0434\u0430\u0432\u0448\u0438\u0439 <em>(juhvat)</em> \u0432\u0441\u0435 \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u0438 <em>(sakala-vikalp\u0101n)</em> \u0441\u0438\u044F\u044E\u0449\u0435\u043C\u0443 <em>(d\u012Bpte)</em> \u0441\u0432\u0435\u0442\u0443 <em>(jyoti\u1E63i)</em> \xAB\u042F\xBB <em>(\u0101tma)</em>, [\u0441\u0430\u043C] \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(bhavati)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u043C \u0441\u0432\u0435\u0442\u0443 <em>(jyotis-maya\u1E25)</em>.</p><p class="eng">In this way <em>(ittham)</em>, the Awakened one <em>(pratibuddha\u1E25)</em>, [who is like a fire covered with ashes that is revived] through the wind <em>(sam\u012Bra\u1E47ata\u1E25)</em> of contemplation <em>(bh\u0101van\u0101)</em>, by offering <em>(juhvat)</em> all [his] false notions <em>(sakala-vikalp\u0101n)</em> [as an oblation] in the brilliant <em>(d\u012Bpte)</em> Light <em>(jyoti\u1E63i)</em> of the Self <em>(\u0101tma)</em>, becomes <em>(bhavati)</em> Luminous \u2013identical with this Light, full of this Light\u2013 <em>(jyotis-maya\u1E25)</em>.</p></div><div class="stanza"><a href="#s69" id="s69" class="num">69</a><p class="sans">\u0905\u0936\u094D\u0928\u0928\u094D\u092F\u0926\u094D\u0935\u093E \u0924\u0926\u094D\u0935\u093E \u0938\u0902\u0935\u0940\u0924\u094B \u092F\u0947\u0928 \u0915\u0947\u0928\u091A\u093F\u091A\u094D\u091B\u093E\u0928\u094D\u0924\u0903 \u0964<br> \u092F\u0924\u094D\u0930 \u0915\u094D\u0935\u091A\u0928 \u0928\u093F\u0935\u093E\u0938\u0940 \u0935\u093F\u092E\u0941\u091A\u094D\u092F\u0924\u0947 \u0938\u0930\u094D\u0935\u092D\u0942\u0924\u093E\u0924\u094D\u092E\u093E \u0965\u096C\u096F\u0965</p><p class="trans">A\u015Bnanyadv\u0101 tadv\u0101 sa\u1E41v\u012Bto yena kenacicch\u0101nta\u1E25 \u0964<br> Yatra kvacana niv\u0101s\u012B vimucyate sarvabh\u016Bt\u0101tm\u0101 \u096569\u0965</p><p>\u0423\u043C\u0438\u0440\u043E\u0442\u0432\u043E\u0440\u0451\u043D\u043D\u044B\u0439 <em>(\u015B\u0101nta\u1E25)</em>, \u043F\u0438\u0442\u0430\u044F\u0441\u044C <em>(a\u015Bnan)</em> \u0447\u0435\u043C \u0443\u0433\u043E\u0434\u043D\u043E <em>(yadv\u0101 tadv\u0101)</em>, \u043E\u0434\u0435\u0432\u0430\u044F\u0441\u044C <em>(sa\u1E41v\u012Bta\u1E25)</em> \u043A\u0430\u043A \u0443\u0433\u043E\u0434\u043D\u043E <em>(yena kenacid)</em>, [\u0438] \u043E\u0431\u0438\u0442\u0430\u044F <em>(niv\u0101s\u012B)</em> \u0433\u0434\u0435 \u0443\u0433\u043E\u0434\u043D\u043E <em>(yatra kvacana)</em> \u0431\u0443\u0434\u0443\u0447\u0438 \xAB\u042F\xBB <em>(\u0101tm\u0101)</em> \u0432\u0441\u0435\u0445 <em>(sarva)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432 <em>(bh\u016Bta)</em> \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u0432\u043E\u0431\u043E\u0434\u0435\u043D <em>(vimucyate)</em>.</p><p class="eng">The Peaceful One <em>(\u015B\u0101nta\u1E25)</em> who eats <em>(a\u015Bnan)</em> anything whatever <em>(yadv\u0101 tadv\u0101)</em>, who covers [his body] <em>(sa\u1E41v\u012Bta\u1E25)</em> with anything whatever <em>(yena kenacid)</em> [and] who lives <em>(niv\u0101s\u012B)</em> in any place whatever <em>(yatra kvacana)</em>, being the Self <em>(\u0101tm\u0101)</em> of all <em>(sarva)</em> beings <em>(bh\u016Bta)</em>, becomes totally liberated <em>(vimucyate)</em>[while he spends his time engaged in the goal of giving Grace to other people].</p></div><div class="stanza"><a href="#s70" id="s70" class="num">70</a><p class="sans">\u0939\u092F\u092E\u0947\u0927\u0936\u0924\u0938\u0939\u0938\u094D\u0930\u093E\u0923\u094D\u092F\u092A\u093F \u0915\u0941\u0930\u0941\u0924\u0947 \u092C\u094D\u0930\u0939\u094D\u092E\u0918\u093E\u0924\u0932\u0915\u094D\u0937\u093E\u0923\u093F \u0964<br> \u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0935\u093F\u0928\u094D\u0928 \u092A\u0941\u0923\u094D\u092F\u0948\u0930\u094D\u0928 \u091A \u092A\u093E\u092A\u0948\u0903 \u0938\u094D\u092A\u0943\u0936\u094D\u092F\u0924\u0947 \u0935\u093F\u092E\u0932\u0903 \u0965\u096D\u0966\u0965</p><p class="trans">Hayamedha\u015Batasahasr\u0101\u1E47yapi kurute brahmagh\u0101talak\u1E63\u0101\u1E47i \u0964<br> Param\u0101rthavinna pu\u1E47yairna ca p\u0101pai\u1E25 sp\u1E5B\u015Byate vimala\u1E25 \u096570\u0965</p><p>\u0414\u0430\u0436\u0435 <em>(api)</em> \u0441\u043E\u0432\u0435\u0440\u0448\u0438\u0432\u0448\u0438\u0439 <em>(kurute)</em> \u0441\u043E\u0442\u043D\u044E <em>(\u015Bata)</em> \u0442\u044B\u0441\u044F\u0447 <em>(sahasr\u0101\u1E47i)</em> \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u0439 \u043A\u043E\u043D\u044F <em>(haya-medha)</em> [\u0438\u043B\u0438] \u0441\u0442\u043E \u0442\u044B\u0441\u044F\u0447 <em>(lak\u1E63\u0101\u1E47i)</em> \u0443\u0431\u0438\u0439\u0441\u0442\u0432 <em>(gh\u0101ta)</em> \u0436\u0440\u0435\u0446\u043E\u0432 <em>(brahma)</em> \u0437\u043D\u0430\u044E\u0449\u0438\u0439 <em>(vit)</em> \u0412\u044B\u0441\u0448\u0443\u044E <em>(parama)</em> \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C <em>(artha)</em> [\u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F] \u043D\u0435\u0437\u0430\u043F\u044F\u0442\u043D\u0430\u043D <em>(vimala\u1E25)</em>, \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435\u043C <em>(sp\u1E5B\u015Byate)</em> \u043D\u0438 <em>(na)</em> \u0437\u0430\u0441\u043B\u0443\u0433 <em>(pu\u1E47yai\u1E25)</em>, \u043D\u0438 <em>(na ca)</em> \u0433\u0440\u0435\u0445\u043E\u0432 <em>(p\u0101pai\u1E25)</em>.</p><p class="eng">Though <em>(api)</em> the Knower <em>(vit)</em> of the Highest <em>(parama)</em> Reality <em>(artha)</em> performs <em>(kurute)</em> one hundred <em>(\u015Bata)</em> thousand <em>(sahasr\u0101\u1E47i)</em> horse-sacrifices <em>(haya-medha)</em> [or] one hundred thousand <em>(lak\u1E63\u0101\u1E47i)</em> assassinations <em>(gh\u0101ta)</em> of priests <em>(brahma)</em>, [he,] the Immaculate one <em>(vimala\u1E25)</em>, is not <em>(na\u2026 na ca)</em> touched <em>(sp\u1E5B\u015Byate)</em> by the good or bad fruits [of his actions] <em>(pu\u1E47yai\u1E25\u2026 p\u0101pai\u1E25)</em>.</p></div><div class="stanza"><a href="#s71" id="s71" class="num">71</a><p class="sans">\u092E\u0926\u0939\u0930\u094D\u0937\u0915\u094B\u092A\u092E\u0928\u094D\u092E\u0925\u0935\u093F\u0937\u093E\u0926\u092D\u092F\u0932\u094B\u092D\u092E\u094B\u0939\u092A\u0930\u093F\u0935\u0930\u094D\u091C\u0940 \u0964<br> \u0928\u093F\u0903\u0938\u094D\u0924\u094B\u0924\u094D\u0930\u0935\u0937\u091F\u094D\u0915\u093E\u0930\u094B \u091C\u0921 \u0907\u0935 \u0935\u093F\u091A\u0930\u0947\u0926\u0935\u093E\u0926\u092E\u0924\u093F\u0903 \u0965\u096D\u0967\u0965</p><p class="trans">Madahar\u1E63akopamanmathavi\u1E63\u0101dabhayalobhamohaparivarj\u012B \u0964<br> Ni\u1E25stotrava\u1E63a\u1E6Dk\u0101ro ja\u1E0Da iva vicaredav\u0101damati\u1E25 \u096571\u0965</p><p>\u0418\u0437\u0431\u0435\u0433\u0430\u044E\u0449\u0438\u0439 <em>(parivarj\u012B)</em> \u0432\u043E\u0437\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(mada)</em>, \u0432\u043E\u0441\u0442\u043E\u0440\u0433\u0430 <em>(har\u1E63a)</em>, \u0433\u043D\u0435\u0432\u0430 <em>(kopa)</em>, \u0441\u0442\u0440\u0430\u0441\u0442\u0438 <em>(manmatha)</em>, \u043F\u0435\u0447\u0430\u043B\u0438 <em>(vi\u1E63\u0101da)</em>, \u0441\u0442\u0440\u0430\u0445\u0430 <em>(bhaya)</em>, \u0436\u0430\u0434\u043D\u043E\u0441\u0442\u0438 <em>(lobha)</em><em>,</em> \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0439 <em>(moha)</em>, \u043D\u0435 \u0432\u043E\u0441\u043A\u043B\u0438\u0446\u0430\u044E\u0449\u0438\u0439 \u201C\u0432\u0430\u0448\u0430\u0442\u201D \u0432 \u0433\u0438\u043C\u043D\u0430\u0445 <em>(ni\u1E25-stotra-va\u1E63a\u1E6D-k\u0101ra\u1E25)</em> \u043A\u0430\u043A <em>(iva)</em> \u0438\u0434\u0438\u043E\u0442 <em>(ja\u1E0Da\u1E25)</em> \u0431\u0440\u043E\u0434\u0438\u0442 [\u043E\u043D] \u043F\u043E\u0432\u0441\u044E\u0434\u0443 <em>(vicaret)</em> \u0431\u0435\u0437 \u0440\u0430\u0437\u0433\u043E\u0432\u043E\u0440\u043E\u0432 \u0438 \u0440\u0430\u0441\u0441\u0443\u0436\u0434\u0435\u043D\u0438\u0439 <em>(a-v\u0101da-mati\u1E25)</em>.</p><p class="eng">Avoiding <em>(parivarj\u012B)</em> conceit <em>(mada)</em>, joy for obtaining what had not been obtained before <em>(har\u1E63a)</em>, wrath <em>(kopa)</em>, sexual desire <em>(manmatha)</em>, disappointment <em>(vi\u1E63\u0101da)</em>, fear <em>(bhaya)</em>, avarice <em>(lobha)</em> [and] delusion <em>(moha)</em>, the one who is free from the exclamations Va\u1E63a\u1E6D \u2013an interjection denoting praise\u2013 [uttered while chanting certain] hymns <em>(ni\u1E25-stotra-va\u1E63a\u1E6D-k\u0101ra\u1E25)</em> moves in different directions <em>(vicaret)</em> as if <em>(iva)</em>[he were] an insentient being \u2013apathetic, dull\u2013 _(ja\u1E0Da\u1E25)_without speech and intelligence _(a-v\u0101da-mati\u1E25)_.</p></div><div class="stanza"><a href="#s72" id="s72" class="num">72</a><p class="sans">\u092E\u0926\u0939\u0930\u094D\u0937\u092A\u094D\u0930\u092D\u0943\u0924\u093F\u0930\u092F\u0902 \u0935\u0930\u094D\u0917\u0903 \u092A\u094D\u0930\u092D\u0935\u0924\u093F \u0935\u093F\u092D\u0947\u0926\u0938\u092E\u094D\u092E\u094B\u0939\u093E\u0924\u094D \u0964<br> \u0905\u0926\u094D\u0935\u0948\u0924\u093E\u0924\u094D\u092E\u0935\u093F\u092C\u094B\u0927\u0938\u094D\u0924\u0947\u0928 \u0915\u0925\u0902 \u0938\u094D\u092A\u0943\u0936\u094D\u092F\u0924\u093E\u0902 \u0928\u093E\u092E \u0965\u096D\u0968\u0965</p><p class="trans">Madahar\u1E63aprabh\u1E5Btiraya\u1E41 varga\u1E25 prabhavati vibhedasammoh\u0101t \u0964<br> Advait\u0101tmavibodhastena katha\u1E41 sp\u1E5B\u015Byat\u0101\u1E41 n\u0101ma \u096572\u0965</p><p>\u042D\u0442\u0430 <em>(ayam)</em> \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C <em>(varga\u1E25)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0449\u0430\u044F\u0441\u044F \u0441 <em>(prabh\u1E5Bti\u1E25)</em> \u0432\u043E\u0437\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(mada)</em> [\u0438] \u0432\u043E\u0441\u0442\u043E\u0440\u0433\u0430 <em>(har\u1E63a)</em>, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 <em>(prabhavati)</em> \u0438\u0437 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u044F <em>(sammoh\u0101t)</em> \u043E \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(vibheda)</em>. \u0414\u043B\u044F \u043F\u0440\u043E\u0431\u0443\u0434\u0438\u0432\u0448\u0435\u0433\u043E <em>(vibodha\u1E25)</em> \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E <em>(advaita)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C <em>(\u0101tma)</em>, \u043A\u0430\u043A <em>(katham)</em> \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0441\u043E\u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435 <em>(sp\u1E5B\u015Byat\u0101m n\u0101ma)</em> \u0441 \u043D\u0435\u0439 <em>(tena)</em>?</p><p class="eng">This <em>(ayam)</em> group <em>(varga\u1E25)</em> beginning with <em>(prabh\u1E5Bti\u1E25)</em> conceit <em>(mada)</em>, joy for obtaining what had not been obtained before <em>(har\u1E63a)</em>, [etc.] springs up <em>(prabhavati)</em> from bewilderment <em>(sammoh\u0101t)</em> of differentiation <em>(vibheda)</em>. [However, in the case of] one who is possessed of Knowledge <em>(vibodha\u1E25)</em> whose essence <em>(\u0101tma)</em> is [supreme] non-dualism <em>(advaita)</em>, how <em>(katham)</em> could he be possibly touched or affected <em>(sp\u1E5B\u015Byat\u0101m n\u0101ma)</em> by that [group] <em>(tena)</em>?</p></div><div class="stanza"><a href="#s73" id="s73" class="num">73</a><p class="sans">\u0938\u094D\u0924\u0941\u0924\u094D\u092F\u0902 \u0935\u093E \u0939\u094B\u0924\u0935\u094D\u092F\u0902 \u0928\u093E\u0938\u094D\u0924\u093F \u0935\u094D\u092F\u0924\u093F\u0930\u093F\u0915\u094D\u0924\u092E\u0938\u094D\u092F \u0915\u093F\u091E\u094D\u091A\u0928 \u091A \u0964<br> \u0938\u094D\u0924\u094B\u0924\u094D\u0930\u093E\u0926\u093F\u0928\u093E \u0938 \u0924\u0941\u0937\u094D\u092F\u0947\u0928\u094D\u092E\u0941\u0915\u094D\u0924\u0938\u094D\u0924\u0928\u094D\u0928\u093F\u0930\u094D\u0928\u092E\u0938\u094D\u0915\u0943\u0924\u093F\u0935\u0937\u091F\u094D\u0915\u0903 \u0965\u096D\u0969\u0965</p><p class="trans">Stutya\u1E41 v\u0101 hotavya\u1E41 n\u0101sti vyatiriktamasya ki\xF1cana ca \u0964<br> Stotr\u0101din\u0101 sa tu\u1E63yenmuktastannirnamask\u1E5Btiva\u1E63a\u1E6Dka \u096573\u0965</p><p>\u0412 \u0442\u0430\u043A\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 <em>(asya)</em> \u043D\u0435 <em>(na)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(asti)</em> \u043D\u0438\u0447\u0435\u0433\u043E <em>(ki\xF1cana)</em> \u043E\u0442\u043B\u0438\u0447\u043D\u043E\u0433\u043E <em>[\u043E\u0442 \u043D\u0435\u0433\u043E]</em> <em>(vyatiriktam)</em>, \u0434\u043E\u0441\u0442\u043E\u0439\u043D\u043E\u0433\u043E \u043F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u044F <em>(stutyam)</em> \u0438\u043B\u0438 <em>(v\u0101)</em> \u043F\u0440\u0438\u043D\u0435\u0441\u0435\u043D\u0438\u044F \u0436\u0435\u0440\u0442\u0432 <em>(hotavyam)</em>, \u0443\u0431\u043B\u0430\u0436\u0435\u043D\u0438\u044F <em>(ca\u2026 sa\u1E25 tu\u1E63yet)</em> \u0433\u0438\u043C\u043D\u0430\u043C\u0438 \u0438 \u043F\u0440\u043E\u0447\u0438\u043C <em>(stotra-\u0101din\u0101)</em>. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(tad)</em> \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0451\u043D\u043D\u044B\u0439 <em>(mukta\u1E25)</em> \u043D\u0435 \u043F\u043E\u043A\u043B\u043E\u043D\u044F\u0435\u0442\u0441\u044F \u0438 \u043D\u0435 \u0432\u043E\u0441\u043A\u043B\u0438\u0446\u0430\u0435\u0442 \u201C\u0432\u0430\u0448\u0430\u0442\u201D <em>(nis-namask\u1E5Bti-va\u1E63a\u1E6D-ka\u1E25)</em>.</p><p class="eng">In his case <em>(asya)</em> there is <em>(asti)</em> neither <em>(na)</em> at all <em>(ki\xF1cana)</em> something to be praised <em>(stutyam)</em> or <em>(v\u0101)</em> worshiped with sacrifices <em>(hotavyam)</em> which is different [from himself] <em>(vyatiriktam)</em>, nor is he pleased <em>(ca\u2026 sa\u1E25 tu\u1E63yet)</em> with hymns, etc. <em>(stotra-\u0101din\u0101)</em>. Therefore <em>(tad)</em>, the Liberated one <em>(mukta\u1E25)</em> is free from homage and \u201Cva\u1E63a\u1E6D-s\u201D \u2013exclamations of praise\u2013 <em>(nis-namask\u1E5Bti-va\u1E63a\u1E6D-ka\u1E25)</em>.</p></div><div class="stanza"><a href="#s74" id="s74" class="num">74</a><p class="sans">\u0937\u091F\u094D\u0924\u094D\u0930\u093F\u0902\u0936\u0924\u094D\u0924\u0924\u094D\u0924\u094D\u0935\u092D\u0943\u0924\u0902 \u0935\u093F\u0917\u094D\u0930\u0939\u0930\u091A\u0928\u093E\u0917\u0935\u093E\u0915\u094D\u0937\u092A\u0930\u093F\u092A\u0942\u0930\u094D\u0923\u092E\u094D \u0964<br> \u0928\u093F\u091C\u092E\u0928\u094D\u092F\u0926\u0925 \u0936\u0930\u0940\u0930\u0902 \u0918\u091F\u093E\u0926\u093F \u0935\u093E \u0924\u0938\u094D\u092F \u0926\u0947\u0935\u0917\u0943\u0939\u092E\u094D \u0965\u096D\u096A\u0965</p><p class="trans">\u1E62a\u1E6Dtri\u1E41\u015Battattvabh\u1E5Bta\u1E41 vigraharacan\u0101gav\u0101k\u1E63aparip\u016Br\u1E47am \u0964<br> Nijamanyadatha \u015Bar\u012Bra\u1E41 gha\u1E6D\u0101di v\u0101 tasya devag\u1E5Bham \u096574\u0965</p><p>\u041D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0435 <em>(bh\u1E5Btam)</em> \u0442\u0440\u0438\u0434\u0446\u0430\u0442\u0438 \u0448\u0435\u0441\u0442\u044C\u044E <em>(\u1E63a\u1E6Dtri\u1E41\u015Bat)</em> \u0442\u0430\u0442\u0442\u0432\u0430\u043C\u0438 <em>(tattva)</em>, \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0435\u043D\u043D\u044B\u0435 \u043F\u043E\u043B\u043D\u044B\u043C <em>(parip\u016Br\u1E47am)</em> \u043D\u0430\u0431\u043E\u0440\u043E\u043C <em>(racan\u0101)</em> \u043E\u043A\u043E\u043D <em>(gav\u0101k\u1E63a)</em> \u0444\u043E\u0440\u043C\u044B <em>(vigraha)</em>, \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(nijam)</em> [\u0438\u043B\u0438] \u0447\u044C\u0435-\u0442\u043E \u0435\u0449\u0435 <em>(anyat atha)</em> \u0442\u0435\u043B\u043E <em>(\u015Bar\u012Bram)</em>, \u0438\u043B\u0438 <em>(v\u0101)</em> [\u0434\u0430\u0436\u0435] \u0433\u043E\u0440\u0448\u043E\u043A <em>(gha\u1E6Da)</em> \u0438 \u043F\u0440\u043E\u0447\u0435\u0435 <em>(\u0101di)</em> \u2014 \u0435\u0433\u043E <em>(tasya)</em> \u0445\u0440\u0430\u043C <em>(deva-g\u1E5Bham)</em>.</p><p class="eng">His own <em>(nijam)</em> body <em>(\u015Bar\u012Bram)</em> [or] that of some other [living being] <em>(anyat atha)</em>, full of <em>(bh\u1E5Btam)</em> the thirty-six <em>(\u1E63a\u1E6Dtri\u1E41\u015Bat)</em> principles or categories <em>(tattva)</em> [and] replete with <em>(parip\u016Br\u1E47am)</em> windows <em>(gav\u0101k\u1E63a)</em> [creating] an arrangement [of openings in the form of the senses] <em>(racan\u0101)</em> within the body [itself] <em>(vigraha)</em>; or <em>(v\u0101)</em> [even any external object such as] a pot <em>(gha\u1E6Da)</em> and so on <em>(\u0101di)</em>, [having Pure Consciousness for their seat, is also] his <em>(tasya)</em> temple <em>(deva-g\u1E5Bham)</em>.</p></div><div class="stanza"><a href="#s75" id="s75" class="num">75</a><p class="sans">\u0924\u0924\u094D\u0930 \u091A \u092A\u0930\u092E\u093E\u0924\u094D\u092E\u092E\u0939\u093E\u092D\u0948\u0930\u0935\u0936\u093F\u0935\u0926\u0947\u0935\u0924\u093E\u0902 \u0938\u094D\u0935\u0936\u0915\u094D\u0924\u093F\u092F\u0941\u0924\u093E\u092E\u094D \u0964<br> \u0906\u0924\u094D\u092E\u093E\u092E\u0930\u094D\u0936\u0928\u0935\u093F\u092E\u0932\u0926\u094D\u0930\u0935\u094D\u092F\u0948\u0903 \u092A\u0930\u093F\u092A\u0942\u091C\u092F\u0928\u094D\u0928\u093E\u0938\u094D\u0924\u0947 \u0965\u096D\u096B\u0965</p><p class="trans">Tatra ca param\u0101tmamah\u0101bhairava\u015Bivadevat\u0101\u1E41 sva\u015Baktiyut\u0101m \u0964<br> \u0100tm\u0101mar\u015Banavimaladravyai\u1E25 parip\u016Bjayann\u0101ste \u096575\u0965</p><p>\u0418 <em>(ca)</em> \u0442\u0430\u043C <em>(tatra)</em> \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442\u0441\u044F <em>(\u0101ste)</em> \u043F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0435 <em>(parip\u016Bjayan)</em> \u0411\u043E\u0433\u0443 <em>(devat\u0101m)</em> \u0428\u0438\u0432\u0435 <em>(\u015Biva)</em>, \u0412\u044B\u0441\u0448\u0435\u043C\u0443 \u042F <em>(parama-\u0101tma)</em> \u0432\u0435\u043B\u0438\u043A\u043E\u043C\u0443 \u0411\u0445\u0430\u0439\u0440\u0430\u0432\u0435 <em>(mah\u0101-bhairava)</em>, \u0441\u043E\u043F\u0440\u043E\u0432\u043E\u0436\u0434\u0430\u0435\u043C\u043E\u043C\u0443 <em>(yut\u0101m)</em> \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u0428\u0430\u043A\u0442\u0438 <em>(\u015Bakti)</em>, \u0441 \u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u044F\u043C\u0438 <em>(dravyai\u1E25)</em>, \u043E\u0447\u0438\u0449\u0435\u043D\u043D\u044B\u043C\u0438 <em>(vimala)</em> \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435\u043C <em>(\u0101mar\u015Bana)</em> \u0434\u0443\u0448\u0438 <em>(\u0101tma)</em>.</p><p class="eng">And <em>(ca)</em> in that [temple of his own body] <em>(tatra)</em>, [the Knower of the Self] continues <em>(\u0101ste)</em> worshiping <em>(parip\u016Bjayan)</em> the deity <em>(devat\u0101m)</em> [called] \u015Aiva <em>(\u015Biva)</em>, [also known as both] the Supreme Self <em>(parama-\u0101tma)</em> [and] the Great Bhairava <em>(mah\u0101-bhairava)</em>, who is accompanied by <em>(yut\u0101m)</em> His own <em>(sva)</em> Powers <em>(\u015Bakti)</em>. [He worships Him] with substances <em>(dravyai\u1E25)</em> [which are] totally pure <em>(vimala)</em> [due to his] remembrance <em>(\u0101mar\u015Bana)</em> of the Self <em>(\u0101tma)</em>.</p></div><div class="stanza"><a href="#s76" id="s76" class="num">76</a><p class="sans">\u092C\u0939\u093F\u0930\u0928\u094D\u0924\u0930\u092A\u0930\u093F\u0915\u0932\u094D\u092A\u0928\u092D\u0947\u0926\u092E\u0939\u093E\u092C\u0940\u091C\u0928\u093F\u091A\u092F\u092E\u0930\u094D\u092A\u092F\u0924\u0903 \u0964<br> \u0924\u0938\u094D\u092F\u093E\u0924\u093F\u0926\u0940\u092A\u094D\u0924\u0938\u0902\u0935\u093F\u091C\u094D\u091C\u094D\u0935\u0932\u0928\u0947 \u092F\u0924\u094D\u0928\u093E\u0926\u094D\u0935\u093F\u0928\u093E \u092D\u0935\u0924\u093F \u0939\u094B\u092E\u0903 \u0965\u096D\u096C\u0965</p><p class="trans">Bahirantaraparikalpanabhedamah\u0101b\u012Bjanicayamarpayata\u1E25 \u0964<br> Tasy\u0101tid\u012Bptasa\u1E41vijjvalane yatn\u0101dvin\u0101 bhavati homa\u1E25 \u096576\u0965</p><p>\u0414\u043B\u044F \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u044E\u0449\u0435\u0433\u043E <em>(arpayata\u1E25)</em> \u0432\u0435\u043B\u0438\u043A\u043E\u0435 <em>(mah\u0101)</em> \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E <em>(nicayam)</em> \u0441\u0435\u043C\u044F\u043D <em>(b\u012Bja)</em> \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(bheda)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445 <em>(antara)</em> [\u0438] \u0432\u043D\u0435\u0448\u043D\u0438\u0445 <em>(bahis)</em> \u0443\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u043A\u043E\u043D\u0441\u0442\u0440\u0443\u043A\u0446\u0438\u0439 <em>(parikalpana)</em> \u0441\u0432\u0435\u0440\u043A\u0430\u044E\u0449\u0435\u043C\u0443 \u043E\u0433\u043D\u044E <em>(atid\u012Bpta\u2026 jvalane)</em> \u0435\u0433\u043E <em>(tasya)</em> \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(sa\u1E41vid)</em>, \u043E\u0433\u043D\u0435\u043D\u043D\u043E\u0435 \u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u0435 <em>(homa\u1E25)</em> \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(bhavati)</em> \u0431\u0435\u0437 <em>(vin\u0101)</em> \u043A\u0430\u043A\u043E\u0433\u043E-\u043B\u0438\u0431\u043E \u0443\u0441\u0438\u043B\u0438\u044F <em>(yatn\u0101t)</em>.</p><p class="eng">In the case of the [Knower of the Self] who offers <em>(arpayata\u1E25)</em> the great <em>(mah\u0101)</em> pile <em>(nicayam)</em> of seeds <em>(b\u012Bja)</em> of duality <em>(bheda)</em> [constituted by] internal <em>(antara)</em> [and] external <em>(bahis)</em> mental inventions <em>(parikalpana)</em> into the extremely bright Fire <em>(atid\u012Bpta\u2026 jvalane)</em> of his <em>(tasya)</em> Pure Consciousness <em>(sa\u1E41vid)</em>, there is <em>(bhavati)</em> \u201Choma\u201D \u2013the act of offering oblations to the fire\u2013 <em>(homa\u1E25)</em> without <em>(vin\u0101)</em> any effort <em>(yatn\u0101t)</em>.</p></div><div class="stanza"><a href="#s77" id="s77" class="num">77</a><p class="sans">\u0927\u094D\u092F\u093E\u0928\u092E\u0928\u0938\u094D\u0924\u092E\u093F\u0924\u0902 \u092A\u0941\u0928\u0930\u0947\u0937 \u0939\u093F \u092D\u0917\u0935\u093E\u0928\u094D\u0935\u093F\u091A\u093F\u0924\u094D\u0930\u0930\u0942\u092A\u093E\u0923\u093F \u0964<br> \u0938\u0943\u091C\u0924\u093F \u0924\u0926\u0947\u0935 \u0927\u094D\u092F\u093E\u0928\u0902 \u0938\u0919\u094D\u0915\u0932\u094D\u092A\u093E\u0932\u093F\u0916\u093F\u0924\u0938\u0924\u094D\u092F\u0930\u0942\u092A\u0924\u094D\u0935\u092E\u094D \u0965\u096D\u096D\u0965</p><p class="trans">Dhy\u0101namanastamita\u1E41 punare\u1E63a hi bhagav\u0101nvicitrar\u016Bp\u0101\u1E47i \u0964<br> S\u1E5Bjati tadeva dhy\u0101na\u1E41 sa\u1E45kalp\u0101likhitasatyar\u016Bpatvam \u096577\u0965</p><p>\u041C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u044F <em>(dhy\u0101nam)</em> \u0432\u0441\u0435 \u0436\u0435 <em>(punar)</em> \u043D\u0435 \u0443\u0433\u0430\u0441\u0430\u0435\u0442 <em>(anastamitam)</em> \u0438\u0431\u043E <em>(hi)</em> \u044D\u0442\u043E\u0442 \u0413\u043E\u0441\u043F\u043E\u0434\u044C <em>(e\u1E63a\u1E25\u2026 bhagav\u0101n)</em> \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u0435\u0442 <em>(s\u1E5Bjati)</em> \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u044B\u0435 <em>(vicitra)</em> \u0444\u043E\u0440\u043C\u044B <em>(r\u016Bp\u0101\u1E47i)</em>. \u0418\u043C\u0435\u043D\u043D\u043E \u044D\u0442\u0430 <em>(tad eva)</em> \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u044F <em>(dhy\u0101nam)</em> \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u0435\u0442 <em>(\u0101likhita)</em> \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F <em>(sa\u1E45kalpa)</em> \u043E\u0431 \u0418\u0441\u0442\u0438\u043D\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435 <em>(satya-r\u016Bpatvam)</em>.</p><p class="eng">The meditation [of this Knower of the Self] <em>(dhy\u0101nam)</em> [is] however <em>(punar)</em> not subject to declining \u2013it does not cease\u2013 <em>(anastamitam)</em> because <em>(hi)</em> the Fortunate One \u2013the Great Lord\u2013 <em>(e\u1E63a\u1E25\u2026 bhagav\u0101n)</em> emits \u2013manifests\u2013 <em>(s\u1E5Bjati)</em> forms <em>(r\u016Bp\u0101\u1E47i)</em> which are manifold and variegated <em>(vicitra)</em>. That <em>(tad eva)</em> meditation <em>(dhy\u0101nam)</em> [of his is one in which all that] is depicted <em>(\u0101likhita)</em> [on the canvas of Pure Consciousness] by the mind <em>(sa\u1E45kalpa)</em> [constitutes] the Highest Truth <em>(satya-r\u016Bpatvam)</em>.</p></div><div class="stanza"><a href="#s78" id="s78" class="num">78</a><p class="sans">\u092D\u0941\u0935\u0928\u093E\u0935\u0932\u0940\u0902 \u0938\u092E\u0938\u094D\u0924\u093E\u0902 \u0924\u0924\u094D\u0924\u094D\u0935\u0915\u094D\u0930\u092E\u0915\u0932\u094D\u092A\u0928\u093E\u092E\u0925\u093E\u0915\u094D\u0937\u0917\u0923\u092E\u094D \u0964<br> \u0905\u0928\u094D\u0924\u0930\u094D\u092C\u094B\u0927\u0947 \u092A\u0930\u093F\u0935\u0930\u094D\u0924\u092F\u0924\u093F \u091A \u092F\u0924\u094D\u0938\u094B\u093D\u0938\u094D\u092F \u091C\u092A \u0909\u0926\u093F\u0924\u0903 \u0965\u096D\u096E\u0965</p><p class="trans">Bhuvan\u0101val\u012B\u1E41 samast\u0101\u1E41 tattvakramakalpan\u0101math\u0101k\u1E63aga\u1E47am \u0964<br> Antarbodhe parivartayati ca yatso\u2019sya japa udita\u1E25 \u096578\u0965</p><p>\u041E\u0431\u044A\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 <em>(samast\u0101m)</em> \u0446\u0435\u043F\u043E\u0447\u0435\u043A <em>(\u0101val\u012Bm)</em> \u043C\u0438\u0440\u043E\u0432 <em>(bhuvana)</em>, \u0440\u0430\u0437\u0432\u043E\u0440\u0430\u0447\u0438\u0432\u0430\u043D\u0438\u0435 <em>(kalpan\u0101m)</em> \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(krama)</em> \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0439 <em>(tattva)</em>, \u0438 <em>(atha)</em> \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 <em>(ga\u1E47am)</em> \u043E\u0440\u0433\u0430\u043D\u043E\u0432 <em>(ak\u1E63a)</em> \u0432\u0440\u0430\u0449\u0430\u044E\u0442\u0441\u044F \u043A\u0430\u043A \u0447\u0451\u0442\u043A\u0438 <em>(parivartayati ca yad)</em> \u0432\u043E \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u043C \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0438 <em>(antar-bodhe)</em>. \u042D\u0442\u043E <em>(sa\u1E25)</em> \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(udita\u1E25)</em> \u0435\u0433\u043E <em>(asya)</em> \u0440\u0435\u0446\u0438\u0442\u0430\u0446\u0438\u0435\u0439 <em>(japa\u1E25)</em>.</p><p class="eng">[The Knower of the Self \u2013the great Yog\u012B\u2013 causes] the whole <em>(samast\u0101m)</em> series <em>(\u0101val\u012Bm)</em> of worlds <em>(bhuvana)</em>, the accurate division [known as \u201C\u0101tma-vidy\u0101-\u015Biva\u201D] <em>(kalpan\u0101m)</em> of the succession <em>(krama)</em> of categories <em>(tattva)</em>, and <em>(atha)</em> the aggregate <em>(ga\u1E47am)</em> of Powers composed of Anta\u1E25kara\u1E47a \u2013intellect, ego and mind\u2013 and Bahi\u1E63kara\u1E47a \u2013Powers of perception and action\u2013 <em>(ak\u1E63a)</em> to move round [like the beads of a rosary] <em>(parivartayati ca yad)</em> in the internal Consciousness <em>(antar-bodhe)</em>. That <em>(sa\u1E25)</em> is said to be <em>(udita\u1E25)</em> his <em>(asya)</em> muttering of the Mantra <em>(japa\u1E25)</em>.</p></div><div class="stanza"><a href="#s79-80" id="s79-80" class="num">79-80</a><p class="sans">\u0938\u0930\u094D\u0935\u0902 \u0938\u092E\u092F\u093E \u0926\u0943\u0937\u094D\u091F\u094D\u092F\u093E \u092F\u0924\u094D\u092A\u0936\u094D\u092F\u0924\u093F \u092F\u091A\u094D\u091A \u0938\u0902\u0935\u093F\u0926\u0902 \u092E\u0928\u0941\u0924\u0947 \u0964<br> \u0935\u093F\u0936\u094D\u0935\u0936\u094D\u092E\u0936\u093E\u0928\u0928\u093F\u0930\u0924\u093E\u0902 \u0935\u093F\u0917\u094D\u0930\u0939\u0916\u091F\u094D\u0935\u093E\u0919\u094D\u0917\u0915\u0932\u094D\u092A\u0928\u093E\u0915\u0932\u093F\u0924\u093E\u092E\u094D \u0965\u096D\u096F\u0965</p><p class="sans">\u0935\u093F\u0936\u094D\u0935\u0930\u0938\u093E\u0938\u0935\u092A\u0942\u0930\u094D\u0923\u0902 \u0928\u093F\u091C\u0915\u0930\u0917\u0902 \u0935\u0947\u0926\u094D\u092F\u0916\u0923\u094D\u0921\u0915\u0915\u092A\u093E\u0932\u092E\u094D \u0964<br> \u0930\u0938\u092F\u0924\u093F \u091A \u092F\u0924\u094D\u0924\u0926\u0947\u0924\u0926\u094D\u0935\u094D\u0930\u0924\u092E\u0938\u094D\u092F \u0938\u0941\u0926\u0941\u0930\u094D\u0932\u092D\u0902 \u091A \u0938\u0941\u0932\u092D\u0902 \u091A \u0965\u096E\u0966\u0965</p><p class="trans">Sarva\u1E41 samay\u0101 d\u1E5B\u1E63\u1E6Dy\u0101 yatpa\u015Byati yacca sa\u1E41vida\u1E41 manute \u0964<br> Vi\u015Bva\u015Bma\u015B\u0101nanirat\u0101\u1E41 vigrahakha\u1E6Dv\u0101\u1E45gakalpan\u0101kalit\u0101m \u096579\u0965</p><p class="trans">Vi\u015Bvaras\u0101savap\u016Br\u1E47a\u1E41 nijakaraga\u1E41 vedyakha\u1E47\u1E0Dakakap\u0101lam \u0964<br> Rasayati ca yattadetadvratamasya sudurlabha\u1E41 ca sulabha\u1E41 ca \u096580\u0965</p><p>[\u041E\u043D] \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 <em>(pa\u015Byati)</em> \u0432\u0441\u0451 <em>(sarvam\u2026 yad)</em> \u0441\u043F\u043E\u043A\u043E\u0439\u043D\u043E \u0438 \u043D\u0435\u043F\u0440\u0435\u0434\u0432\u0437\u044F\u0442\u043E <em>(samay\u0101 d\u1E5B\u1E63\u1E6Dy\u0101)</em>, \u0442\u043E \u0435\u0441\u0442\u044C <em>(yad ca)</em>, \u0441\u0447\u0438\u0442\u0430\u0435\u0442 <em>(manute)</em> \u0427\u0438\u0441\u0442\u043E\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(sa\u1E41vidam)</em> \u043E\u0431\u0438\u0442\u0430\u044E\u0449\u0438\u043C <em>(nirat\u0101m)</em> \u043D\u0430 \u043A\u043B\u0430\u0434\u0431\u0438\u0449\u0435 <em>(\u015Bma\u015B\u0101na)</em> \u0412\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em> [\u0438] \u043E\u0442\u043C\u0435\u0447\u0435\u043D\u043D\u043E\u0435 <em>(kalit\u0101m)</em> \u0438\u0437\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0435\u043C <em>(kalpan\u0101)</em> \u0441\u043A\u0435\u043B\u0435\u0442\u0430 <em>(kha\u1E6Dv\u0101\u1E45ga)</em> \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0442\u0435\u043B\u0430 <em>(vigraha)</em>. \u041E\u043D \u0432\u043A\u0443\u0448\u0430\u0435\u0442 <em>(rasayati ca yad)</em> \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u043C\u043E\u0435 \u0447\u0435\u0440\u0435\u043F\u0430 <em>(kap\u0101lam)</em>, \u0444\u0440\u0430\u0433\u043C\u0435\u043D\u0442\u0430 <em>(kha\u1E47\u1E0Daka)</em> \u043E\u0431\u044A\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vedya)</em>, \u043B\u0435\u0436\u0430\u0449\u0435\u0433\u043E <em>(gam)</em> \u0432 \u0435\u0433\u043E <em>(nija)</em> \u0440\u0443\u043A\u0430\u0445 <em>(kara)</em>, \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u043E\u0433\u043E <em>(p\u016Br\u1E47am)</em> \u043D\u0435\u043A\u0442\u0430\u0440\u043E\u043C <em>(rasa-\u0101sava)</em> \u0412\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em>. \u0418\u043C\u0435\u043D\u043D\u043E \u044D\u0442\u043E <em>(tad etad)</em> \u0435\u0433\u043E <em>(asya)</em> \u043E\u0431\u0435\u0442 <em>(vratam)</em>, \u0438 <em>(ca)</em> \u043E\u0447\u0435\u043D\u044C \u0442\u0440\u0443\u0434\u043D\u044B\u0439 <em>(su-durlabham)</em> \u0438 <em>(ca)</em> \u043E\u0447\u0435\u043D\u044C \u043F\u0440\u043E\u0441\u0442\u043E\u0439 <em>(sulabham)</em>.</p><p class="eng">[The Knower of the Self] sees <em>(pa\u015Byati)</em> all of which <em>(sarvam\u2026 yad)</em> with equanimity and impartiality <em>(samay\u0101 d\u1E5B\u1E63\u1E6Dy\u0101)</em>, that is tosay <em>(yad ca)</em>, he considers <em>(manute)</em> Pure Consciousness <em>(sa\u1E41vidam)</em> to be resting and delighting in <em>(nirat\u0101m)</em> the cemetery <em>(\u015Bma\u015B\u0101na)</em> [called] the universe <em>(vi\u015Bva)</em> [and] being marked <em>(kalit\u0101m)</em> by the figure \u2013as an emblem\u2013 <em>(kalpan\u0101)</em> of the skeleton <em>(kha\u1E6Dv\u0101\u1E45ga)</em> in the form of [his own] physical body <em>(vigraha)</em>. And he tastes <em>(rasayati ca yad)</em> [the best drink] contained in the skull <em>(kap\u0101lam)</em> \u2014that [symbolizes] a fragment <em>(kha\u1E47\u1E0Daka)</em> of \u201Cvedya\u201D or the objective side of the universal manifestation <em>(vedya)</em>\u2014 lying <em>(gam)</em> in his <em>(nija)</em> hands <em>(kara)</em> \u2013in the goddesses of his senses\u2013, which is full of <em>(p\u016Br\u1E47am)</em> [that] Nectar \u2013the best drink\u2013 <em>(rasa-\u0101sava)</em> residing in the universe <em>(vi\u015Bva)</em>. That very thing <em>(tad etad)</em> [is] his <em>(asya)</em> vow <em>(vratam)</em>, [which is] both <em>(ca)</em> very difficult <em>(su-durlabham)</em> and <em>(ca)</em> easy <em>(sulabham)</em>[to observe].</p></div><div class="stanza"><a href="#s81" id="s81" class="num">81</a><p class="sans">\u0907\u0924\u093F \u091C\u0928\u094D\u092E\u0928\u093E\u0936\u0939\u0940\u0928\u0902 \u092A\u0930\u092E\u093E\u0930\u094D\u0925\u092E\u0939\u0947\u0936\u094D\u0935\u0930\u093E\u0916\u094D\u092F\u092E\u0941\u092A\u0932\u092D\u094D\u092F \u0964<br> \u0909\u092A\u0932\u092C\u094D\u0927\u0943\u0924\u093E\u092A\u094D\u0930\u0915\u093E\u0936\u093E\u0924\u094D\u0915\u0943\u0924\u0915\u0943\u0924\u094D\u092F\u0938\u094D\u0924\u093F\u0937\u094D\u0920\u0924\u093F \u092F\u0925\u0947\u0937\u094D\u091F\u092E\u094D \u0965\u096E\u0967\u0965</p><p class="trans">Iti janman\u0101\u015Bah\u012Bna\u1E41 param\u0101rthamahe\u015Bvar\u0101khyamupalabhya \u0964<br> Upalabdh\u1E5Bt\u0101prak\u0101\u015B\u0101tk\u1E5Btak\u1E5Btyasti\u1E63\u1E6Dhati yathe\u1E63\u1E6Dam \u096581\u0965</p><p>\u0420\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u0432 <em>(upalabhya)</em> \u0442\u0430\u043A <em>(iti)</em> \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0433\u043E \u043A\u0430\u043A <em>(\u0101khyam)</em> \u0412\u044B\u0441\u0448\u0430\u044F \u0438\u0441\u0442\u0438\u043D\u0430 <em>(param\u0101rtha)</em> \u0412\u0435\u043B\u0438\u043A\u043E\u0433\u043E <em>(mah\u0101)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(\u012B\u015Bvara)</em> \u043D\u0435 \u043F\u043E\u0434\u0432\u0435\u0440\u0436\u0435\u043D\u043D\u043E\u0433\u043E <em>(h\u012Bnam)</em> \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044E <em>(janma)</em> [\u0438] \u0441\u043C\u0435\u0440\u0442\u0438 <em>(n\u0101\u015Ba)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u0448\u0438\u0439 <em>(k\u1E5Bta-k\u1E5Btya\u1E25)</em> \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F <em>[\u0432 \u0442\u0435\u043B\u0435]</em> <em>(ti\u1E63\u1E6Dhati)</em> \u043F\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044E <em>(yath\u0101-i\u1E63\u1E6Dam)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044F \u0441\u0435\u0431\u044F <em>(prak\u0101\u015B\u0101t)</em> \u043A\u0430\u043A \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439 \u0441\u0443\u0431\u044A\u0435\u043A\u0442 <em>(upalabdh\u1E5Bt\u0101)</em>.</p><p class="eng">After realizing <em>(upalabhya)</em> in that way <em>(iti)</em> the One who is known as <em>(\u0101khyam)</em> the Real <em>(param\u0101rtha)</em> Great <em>(mah\u0101)</em> Lord <em>(\u012B\u015Bvara)</em> devoid of <em>(h\u012Bnam)</em> birth <em>(janma)</em> [and] death <em>(n\u0101\u015Ba)</em>, [the Yog\u012B \u2013the Knower of the Self\u2013] that has attained the Supreme Goal of existence <em>(k\u1E5Bta-k\u1E5Btya\u1E25)</em> remains [in a physical body] <em>(ti\u1E63\u1E6Dhati)</em> as he wishes <em>(yath\u0101-i\u1E63\u1E6Dam)</em>, because of the display or manifestation <em>(prak\u0101\u015B\u0101t)</em> [of this Great Lord] as the State of the Perceiver <em>(upalabdh\u1E5Bt\u0101)</em></p></div><div class="stanza"><a href="#s82" id="s82" class="num">82</a><p class="sans">\u0935\u094D\u092F\u093E\u092A\u093F\u0928\u092E\u092D\u093F\u0939\u093F\u0924\u092E\u093F\u0924\u094D\u0925\u0902 \u0938\u0930\u094D\u0935\u093E\u0924\u094D\u092E\u093E\u0928\u0902 \u0935\u093F\u0927\u0942\u0924\u0928\u093E\u0928\u093E\u0924\u094D\u0935\u092E\u094D \u0964<br> \u0928\u093F\u0930\u0941\u092A\u092E\u092A\u0930\u092E\u093E\u0928\u0928\u094D\u0926\u0902 \u092F\u094B \u0935\u0947\u0924\u094D\u0924\u093F \u0938 \u0924\u0928\u094D\u092E\u092F\u094B \u092D\u0935\u0924\u093F \u0965\u096E\u0968\u0965</p><p class="trans">Vy\u0101pinamabhihitamittha\u1E41 sarv\u0101tm\u0101na\u1E41 vidh\u016Btan\u0101n\u0101tvam \u0964<br> Nirupamaparam\u0101nanda\u1E41 yo vetti sa tanmayo bhavati \u096582\u0965</p><p>\u0422\u043E\u0442, \u043A\u0442\u043E <em>(ya\u1E25)</em> \u0437\u043D\u0430\u0435\u0442 <em>(vetti)</em> \u0415\u0433\u043E <em>(sa\u1E25)</em> \u043A\u0430\u043A <em>(ittham)</em> \u0418\u0441\u0442\u0438\u043D\u043D\u043E\u0435 \xAB\u042F\xBB <em>(\u0101tm\u0101nam)</em> \u0432\u0441\u0435\u0433\u043E <em>(sarva)</em>, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u043E\u0435 <em>(abhihitam)</em> \u0432\u0441\u0435\u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u043C <em>(vy\u0101pinam)</em>, \u0443\u043A\u0440\u043E\u0442\u0438\u0432\u0448\u0435\u0435 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u044C \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(vidh\u016Bta-n\u0101n\u0101tvam)</em>, \u0447\u044C\u0451 \u0412\u044B\u0441\u0448\u043B\u0435\u0435 <em>(parama)</em> \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E <em>(\u0101nandam)</em> \u043D\u0435 \u0438\u043C\u0435\u0435\u0442 \u0440\u0430\u0432\u043D\u044B\u0445 <em>(nirupama)</em>, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(bhavati)</em> \u0435\u0434\u0438\u043D\u044B\u043C <em>(maya\u1E25)</em> \u0441 \u041D\u0438\u043C <em>(tad)</em>.</p><p class="eng">He <em>(sa\u1E25)</em> who <em>(ya\u1E25)</em> knows <em>(vetti)</em> so <em>(ittham)</em> the Self <em>(\u0101tm\u0101nam)</em> of all <em>(sarva)</em>, called <em>(abhihitam)</em> the All-pervasive One <em>(vy\u0101pinam)</em> who has humbled infinity of dualism <em>(vidh\u016Bta-n\u0101n\u0101tvam)</em> [and] whose Supreme <em>(parama)</em> Bliss <em>(\u0101nandam)</em> is unequaled <em>(nirupama)</em>, is <em>(bhavati)</em> identical <em>(maya\u1E25)</em> with Him <em>(tad)</em>.</p></div><div class="stanza"><a href="#s83" id="s83" class="num">83</a><p class="sans">\u0924\u0940\u0930\u094D\u0925\u0947 \u0936\u094D\u0935\u092A\u091A\u0917\u0943\u0939\u0947 \u0935\u093E \u0928\u0937\u094D\u091F\u0938\u094D\u092E\u0943\u0924\u093F\u0930\u092A\u093F \u092A\u0930\u093F\u0924\u094D\u092F\u091C\u0928\u094D\u0926\u0947\u0939\u092E\u094D \u0964<br> \u091C\u094D\u091E\u093E\u0928\u0938\u092E\u0915\u093E\u0932\u092E\u0941\u0915\u094D\u0924\u0903 \u0915\u0948\u0935\u0932\u094D\u092F\u0902 \u092F\u093E\u0924\u093F \u0939\u0924\u0936\u094B\u0915\u0903 \u0965\u096E\u0969\u0965</p><p class="trans">T\u012Brthe \u015Bvapacag\u1E5Bhe v\u0101 na\u1E63\u1E6Dasm\u1E5Btirapi parityajandeham \u0964<br> J\xF1\u0101nasamak\u0101lamukta\u1E25 kaivalya\u1E41 y\u0101ti hata\u015Boka\u1E25 \u096583\u0965</p><p>\u041F\u043E\u043A\u0438\u0434\u0430\u0435\u0442 <em>(parityajan)</em> \u0441\u0436\u0451\u0433\u0448\u0438\u0439 \u0433\u043E\u0440\u0435\u0441\u0442\u0438 <em>(hata-\u015Boka\u1E25)</em> \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0442\u0435\u043B\u043E <em>(deham)</em> \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u043C \u043C\u0435\u0441\u0442\u0435 <em>(t\u012Brthe)</em> \u0438\u043B\u0438 <em>(v\u0101)</em> \u0432 \u0434\u043E\u043C\u0435 <em>(g\u1E5Bhe)</em> \u043F\u0430\u0440\u0438\u0438 <em>(\u015Bva-paca)</em>, \u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 <em>(api)</em> \u043F\u043E\u0442\u0435\u0440\u044F\u0435\u0442 \u043F\u0430\u043C\u044F\u0442\u044C <em>(na\u1E63\u1E6Da-sm\u1E5Bti\u1E25)</em>, \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0451\u043D\u043D\u044B\u0439 <em>(mukta\u1E25)</em> \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E <em>(sama-k\u0101la)</em> \u0441\u043E \u0437\u043D\u0430\u043D\u0438\u0435\u043C [\u043E \u0421\u0435\u0431\u0435] <em>(j\xF1\u0101na)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(y\u0101ti)</em> \u0430\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0433\u043E \u0415\u0434\u0438\u043D\u0441\u0442\u0432\u0430 <em>(kaivalyam)</em>.</p><p class="eng">[Whether] the one who has disregarded sorrow <em>(hata-\u015Boka\u1E25)</em> leaves <em>(parityajan)</em> [his] physical body <em>(deham)</em> in a place of pilgrimage \u2013i.e. in an extremely auspicious place\u2013 <em>(t\u012Brthe)</em> or <em>(v\u0101)</em> at the house <em>(g\u1E5Bhe)</em> of an outcast <em>(\u015Bva-paca)</em>, [or] even if <em>(api)</em> he loses the memory <em>(na\u1E63\u1E6Da-sm\u1E5Bti\u1E25)</em> [at that moment,] since he has achieved Liberation <em>(mukta\u1E25)</em> simultaneously <em>(sama-k\u0101la)</em> with [his obtaining] Knowledge [about the Self] <em>(j\xF1\u0101na)</em>, he attains <em>(y\u0101ti)</em> Complete Liberation \u2013lit. Isolation\u2013 <em>(kaivalyam)</em>[at the time of death].</p></div><div class="stanza"><a href="#s84" id="s84" class="num">84</a><p class="sans">\u092A\u0941\u0923\u094D\u092F\u093E\u092F \u0924\u0940\u0930\u094D\u0925\u0938\u0947\u0935\u093E \u0928\u093F\u0930\u092F\u093E\u092F \u0936\u094D\u0935\u092A\u091A\u0938\u0926\u0928\u0928\u093F\u0927\u0928\u0917\u0924\u093F\u0903 \u0964<br> \u092A\u0941\u0923\u094D\u092F\u093E\u092A\u0941\u0923\u094D\u092F\u0915\u0932\u0919\u094D\u0915\u0938\u094D\u092A\u0930\u094D\u0936\u093E\u092D\u093E\u0935\u0947 \u0924\u0941 \u0915\u093F\u0902 \u0924\u0947\u0928 \u0965\u096E\u096A\u0965</p><p class="trans">Pu\u1E47y\u0101ya t\u012Brthasev\u0101 niray\u0101ya \u015Bvapacasadananidhanagati\u1E25 \u0964<br> Pu\u1E47y\u0101pu\u1E47yakala\u1E45kaspar\u015B\u0101bh\u0101ve tu ki\u1E41 tena \u096584\u0965</p><p>\u041F\u0430\u043B\u043E\u043C\u043D\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u043F\u043E \u0441\u0432\u044F\u0442\u044B\u043C \u043C\u0435\u0441\u0442\u0430\u043C <em>(t\u012Brtha-sev\u0101)</em> \u043F\u0440\u0438\u043D\u043E\u0441\u0438\u0442 \u0437\u0430\u0441\u043B\u0443\u0433\u0438 <em>(pu\u1E47y\u0101ya)</em>, \u043D\u0430\u0441\u0442\u0443\u043F\u043B\u0435\u043D\u0438\u0435 <em>(gati\u1E25)</em> \u0441\u043C\u0435\u0440\u0442\u0438 <em>(nidhana)</em> \u0432 \u0434\u043E\u043C\u0435 <em>(sadana)</em> \u043E\u0442\u0432\u0435\u0440\u0436\u0435\u043D\u043D\u043E\u0433\u043E <em>(\u015Bvapaca)</em> \u0432\u0435\u0434\u0451\u0442 \u0432 \u0430\u0434 <em>(niray\u0101ya)</em>. \u041D\u043E <em>(tu)</em> \u0447\u0442\u043E <em>(kim)</em> \u0442\u043E\u043C\u0443 <em>(tena)</em>, \u0434\u043B\u044F \u043A\u043E\u0433\u043E \u043D\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 <em>(abh\u0101ve)</em> \u0441\u043E\u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u044F <em>(spar\u015Ba)</em> \u0441 \u0437\u0430\u0433\u0440\u044F\u0437\u043D\u0435\u043D\u0438\u0435\u043C <em>(kala\u1E45ka)</em> \u0437\u0430\u0441\u043B\u0443\u0433\u0430\u043C\u0438 <em>(pu\u1E47ya)</em> [\u0438] \u0433\u0440\u0435\u0445\u0430\u043C\u0438 <em>(apu\u1E47ya)</em>?</p><p class="eng">A visit to places of pilgrimage <em>(t\u012Brtha-sev\u0101)</em> [is] for getting merit <em>(pu\u1E47y\u0101ya)</em>, [while] arriving at <em>(gati\u1E25)</em> death <em>(nidhana)</em> in the residence <em>(sadana)</em> of an outcast <em>(\u015Bvapaca)</em> leads to hell <em>(niray\u0101ya)</em>. But <em>(tu)</em> in the absence of <em>(abh\u0101ve)</em> the touch <em>(spar\u015Ba)</em> by the stain <em>(kala\u1E45ka)</em> [called] merit <em>(pu\u1E47ya)</em> [and] demerit <em>(apu\u1E47ya)</em>, what <em>(kim)</em> of that <em>(tena)</em>? \u2013i.e. what is the relevance of visiting places of pilgrimage or of not dying at the house of an outcast in order to avoid a descent into hell, etc.?\u2013</p></div><div class="stanza"><a href="#s85-86" id="s85-86" class="num">85-86</a><p class="sans">\u0924\u0941\u0937\u0915\u092E\u094D\u092C\u0941\u0915\u0938\u0941\u092A\u0943\u0925\u0915\u094D\u0915\u0943\u0924\u0924\u0923\u094D\u0921\u0941\u0932\u0915\u0923\u0924\u0941\u0937\u0926\u0932\u093E\u0928\u094D\u0924\u0930\u0915\u094D\u0937\u0947\u092A\u0903 \u0964<br> \u0924\u0923\u094D\u0921\u0941\u0932\u0915\u0923\u0938\u094D\u092F \u0915\u0941\u0930\u0941\u0924\u0947 \u0928 \u092A\u0941\u0928\u0938\u094D\u0924\u0926\u094D\u0930\u0942\u092A\u0924\u093E\u0926\u093E\u0924\u094D\u092E\u094D\u092F\u092E\u094D \u0965\u096E\u096B\u0965</p><p class="sans">\u0924\u0926\u094D\u0935\u0924\u094D\u0915\u091E\u094D\u091A\u0941\u0915\u092A\u091F\u0932\u0940\u092A\u0943\u0925\u0915\u094D\u0915\u0943\u0924\u093E \u0938\u0902\u0935\u093F\u0926\u0924\u094D\u0930 \u0938\u0902\u0938\u094D\u0915\u093E\u0930\u093E\u0924\u094D \u0964<br> \u0924\u093F\u0937\u094D\u0920\u0928\u094D\u0924\u094D\u092F\u092A\u093F \u092E\u0941\u0915\u094D\u0924\u093E\u0924\u094D\u092E\u093E \u0924\u0924\u094D\u0938\u094D\u092A\u0930\u094D\u0936\u0935\u093F\u0935\u0930\u094D\u091C\u093F\u0924\u093E \u092D\u0935\u0924\u093F \u0965\u096E\u096C\u0965</p><p class="trans">Tu\u1E63akambukasup\u1E5Bthakk\u1E5Btata\u1E47\u1E0Dulaka\u1E47atu\u1E63adal\u0101ntarak\u1E63epa\u1E25 \u0964<br> Ta\u1E47\u1E0Dulaka\u1E47asya kurute na punastadr\u016Bpat\u0101d\u0101tmyam \u096585\u0965</p><p class="trans">Tadvatka\xF1cukapa\u1E6Dal\u012Bp\u1E5Bthakk\u1E5Bt\u0101 sa\u1E41vidatra sa\u1E41sk\u0101r\u0101t \u0964<br> Ti\u1E63\u1E6Dhantyapi mukt\u0101tm\u0101 tatspar\u015Bavivarjit\u0101 bhavati \u096586\u0965</p><p>[\u041A\u0430\u043A \u043D\u0435] \u0437\u0430\u0442\u0430\u043B\u043A\u0438\u0432\u0430\u0439 <em>(k\u1E63epa\u1E25)</em> \u0437\u0435\u0440\u043D\u043E \u0440\u0438\u0441\u0430 <em>(ta\u1E47\u1E0Dula-ka\u1E47asya)</em> \u0432 <em>(antara)</em> \u0444\u0440\u0430\u0433\u043C\u0435\u043D\u0442 <em>(dala)</em> \u043A\u043E\u0436\u0443\u0440\u044B <em>(tu\u1E63a)</em>, \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0442\u0434\u0435\u043B\u0435\u043D\u043D\u043E\u0435 <em>(su-p\u1E5Bthak-k\u1E5Bta)</em> \u043E\u0442 \u043A\u043E\u0436\u0443\u0440\u044B \u0438 \u043C\u044F\u043A\u0438\u043D\u044B <em>(tu\u1E63a-kambuka)</em> \u0440\u0438\u0441\u043E\u0432\u043E\u0435 \u0437\u0435\u0440\u043D\u043E <em>(ta\u1E47\u1E0Dula-ka\u1E47a)</em> \u043D\u0435 <em>(na)</em> \u043E\u0431\u0440\u0430\u0437\u0443\u0435\u0442 <em>(kurute)</em> \u0441\u043D\u043E\u0432\u0430 <em>(punar)</em> \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 <em>(t\u0101d\u0101tmyam)</em> \u0432 \u0442\u043E\u0439 \u0436\u0435 <em>(tad)</em> \u0444\u043E\u0440\u043C\u0435 <em>(r\u016Bpa)</em>. \u0422\u0430\u043A\u0438\u043C \u0436\u0435 \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(tadvat)</em>, \u0427\u0438\u0441\u0442\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(sa\u1E41vid)</em>, \u043E\u0442\u0434\u0435\u043B\u0451\u043D\u043D\u043E\u0435 <em>(p\u1E5Bthak-k\u1E5Bt\u0101)</em> \u043E\u0442 \u0433\u0440\u0443\u043F\u043F\u044B <em>(pa\u1E6Dal\u012B)</em> \u043E\u0431\u043E\u043B\u043E\u0447\u0435\u043A <em>(ka\xF1cuka)</em>, \u0434\u0430\u0436\u0435 <em>(api)</em> \u043E\u0441\u0442\u0430\u0432\u0430\u044F\u0441\u044C <em>(ti\u1E63\u1E6Dhant\u012B)</em> \u0432 \u043D\u0438\u0445 <em>(atra)</em> \u0441\u0438\u043B\u043E\u0439 \u043D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u043D\u044B\u0445 \u0441\u0430\u043C\u0441\u043A\u0430\u0440 <em>(sa\u1E41sk\u0101r\u0101t)</em>, \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043E <em>(mukta-\u0101tm\u0101)</em> [\u0438] \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(bhavati)</em> \u043D\u0435 \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u043C <em>(vivarjit\u0101)</em> \u0441\u043E\u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0435\u043C <em>(spar\u015Ba)</em> \u0441 \u043D\u0438\u043C\u0438 <em>(tad)</em>.</p><p class="eng">The insertion <em>(k\u1E63epa\u1E25)</em> of a rice-grain <em>(ta\u1E47\u1E0Dula-ka\u1E47asya)</em> into <em>(antara)</em> the [same] fragment <em>(dala)</em> of husk <em>(tu\u1E63a)</em> [after that very] grain of rice <em>(ta\u1E47\u1E0Dula-ka\u1E47a)</em> was totally separated <em>(su-p\u1E5Bthak-k\u1E5Bta)</em> from [its] husk and bran <em>(tu\u1E63a-kambuka)</em> does not <em>(na)</em> produce <em>(kurute)</em> identity [i.e. a very close and stable union of grain and husk even if they are tightly wrapped up with a thread] <em>(t\u0101d\u0101tmyam)</em> in the form of <em>(r\u016Bpa)</em> that <em>(tad)</em> [viz. in the form of the previous rice-grain] again <em>(punar)</em>. In the same way <em>(tadvat)</em>, Pure Consciousness [of the Knower of the Self] <em>(sa\u1E41vid)</em>, when separated <em>(p\u1E5Bthak-k\u1E5Bt\u0101)</em> from the group <em>(pa\u1E6Dal\u012B)</em> of sheaths [such as \u0100\u1E47avamala, etc.] <em>(ka\xF1cuka)</em>, although <em>(api)</em> She [Pure Consciousness] remains <em>(ti\u1E63\u1E6Dhant\u012B)</em> in this [group of sheaths] <em>(atra)</em> [which continues to assume the aspect of a body that stays like a residue for some time only] by force of the accumulated impression <em>(s)</em> <em>(sa\u1E41sk\u0101r\u0101t)</em>, being [totally] emancipated <em>(mukta-\u0101tm\u0101)</em>, becomes <em>(bhavati)</em> free from <em>(vivarjit\u0101)</em> the touch <em>(spar\u015Ba)</em> of that [group of sheaths] <em>(tad)</em>.</p></div><div class="stanza"><a href="#s87-88" id="s87-88" class="num">87-88</a><p class="sans">\u0915\u0941\u0936\u0932\u0924\u092E\u0936\u093F\u0932\u094D\u092A\u093F\u0915\u0932\u094D\u092A\u093F\u0924\u0935\u093F\u092E\u0932\u0940\u092D\u093E\u0935\u0903 \u0938\u092E\u0941\u0926\u094D\u0917\u0915\u094B\u092A\u093E\u0927\u0947\u0903 \u0964<br> \u092E\u0932\u093F\u0928\u094B\u093D\u092A\u093F \u092E\u0923\u093F\u0930\u0941\u092A\u093E\u0927\u0947\u0930\u094D\u0935\u093F\u091A\u094D\u091B\u0947\u0926\u0947 \u0938\u094D\u0935\u091A\u094D\u091B\u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0903 \u0965\u096E\u096D\u0965</p><p class="sans">\u090F\u0935\u0902 \u0938\u0926\u094D\u0917\u0941\u0930\u0941\u0936\u093E\u0938\u0928\u0935\u093F\u092E\u0932\u0938\u094D\u0925\u093F\u0924\u093F \u0935\u0947\u0926\u0928\u0902 \u0924\u0928\u0942\u092A\u093E\u0927\u0947\u0903 \u0964<br> \u092E\u0941\u0915\u094D\u0924\u092E\u092A\u094D\u092F\u0941\u092A\u093E\u0927\u094D\u092F\u0928\u094D\u0924\u0930\u0936\u0942\u0928\u094D\u092F\u092E\u093F\u0935\u093E\u092D\u093E\u0924\u093F \u0936\u093F\u0935\u0930\u0942\u092A\u092E\u094D \u0965\u096E\u096E\u0965</p><p class="trans">Ku\u015Balatama\u015Bilpikalpitavimal\u012Bbh\u0101va\u1E25 samudgakop\u0101dhe\u1E25 \u0964<br> Malino\u2019pi ma\u1E47irup\u0101dhervicchede svacchaparam\u0101rtha\u1E25 \u096587\u0965</p><p class="trans">Eva\u1E41 sadguru\u015B\u0101sanavimalasthiti vedana\u1E41 tan\u016Bp\u0101dhe\u1E25 \u0964<br> Muktamapyup\u0101dhyantara\u015B\u016Bnyamiv\u0101bh\u0101ti \u015Bivar\u016Bpam \u096588\u0965</p><p>\u0414\u0440\u0430\u0433\u043E\u0446\u0435\u043D\u043D\u044B\u0439 \u043A\u0430\u043C\u0435\u043D\u044C <em>(ma\u1E47i\u1E25)</em>, \u0447\u0435\u0439 \u0431\u0435\u0437\u0443\u043F\u0440\u0435\u0447\u043D\u044B\u0439 \u0432\u0438\u0434 <em>(vimal\u012B-bh\u0101va\u1E25)</em> \u0432\u044B\u0434\u0435\u043B\u0430\u043D <em>(kalpita)</em> \u0438\u0441\u043A\u0443\u0441\u043D\u044B\u043C <em>(ku\u015Balatama)</em> \u044E\u0432\u0435\u043B\u0438\u0440\u043E\u043C <em>(\u015Bilpi)</em>, \u0434\u0430\u0436\u0435 <em>(api)</em> \u0441\u043E\u043A\u0440\u044B\u0442\u044B\u0439 <em>(malina\u1E25)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F\u043C\u0438 <em>(up\u0101dhe\u1E25)</em> \u0448\u043A\u0430\u0442\u0443\u043B\u043A\u0438 <em>(samudgaka)</em>, \u0432 \u0434\u043E\u043B\u0436\u043D\u043E\u0435 \u0432\u0440\u0435\u043C\u044F <em>(parama-artha\u1E25)</em> \u0441\u0432\u0435\u0440\u043A\u0430\u0435\u0442 <em>(svaccha)</em> \u043F\u0440\u0438 \u0441\u043D\u044F\u0442\u0438\u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0439 <em>(up\u0101dhe\u1E25 vicchede)</em>. \u0422\u0430\u043A \u0436\u0435 <em>(evam)</em> \u0417\u043D\u0430\u043D\u0438\u0435 <em>(vedanam)</em>, \u0447\u044C\u044F \u0444\u043E\u0440\u043C\u0430 <em>(sthiti)</em> \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u0447\u0438\u0441\u0442\u0430 <em>(vimala)</em> \u0432 \u0443\u0447\u0435\u043D\u0438\u0438 <em>(\u015B\u0101sana)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0433\u043E <em>(sat)</em> \u0433\u0443\u0440\u0443 <em>(guru)</em>, \u0442\u043E\u0436\u0435 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0430\u044F\u0441\u044C \u043E\u0442 <em>(muktam api)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u0438\u0439 <em>(up\u0101dhe\u1E25)</em> \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0442\u0435\u043B\u0430 <em>(tanu)</em>, \u043B\u0438\u0448\u0451\u043D\u043D\u043E\u0435 \u043A\u0430\u043A\u0438\u0445-\u043B\u0438\u0431\u043E <em>(\u015B\u016Bnyam iva)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445 <em>(antara)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0439 <em>(up\u0101dhi)</em>, \u0441\u0438\u044F\u0435\u0442 <em>(\u0101bh\u0101ti)</em> \u043A\u0430\u043A \u0428\u0438\u0432\u0430 <em>(\u015Biva-r\u016Bpam)</em>.</p><p class="eng">Although <em>(api)</em> a gem <em>(ma\u1E47i\u1E25)</em>, whose completely pure state <em>(vimal\u012B-bh\u0101va\u1E25)</em> has been prepared <em>(kalpita)</em> by the most skillful <em>(ku\u015Balatama)</em> jeweler <em>(\u015Bilpi)</em>, [looks like] darkened <em>(malina\u1E25)</em> due to the limiting condition <em>(up\u0101dhe\u1E25)</em> [appearing as] the casket <em>(samudgaka)</em>, [it nevertheless becomes] duly <em>(parama-artha\u1E25)</em> spotless and very transparent <em>(svaccha)</em> when the limiting condition [called] casket is removed <em>(up\u0101dhe\u1E25 vicchede)</em>. So <em>(evam)</em> [is this] Knowledge <em>(vedanam)</em> whose state <em>(sthiti)</em> [is] totally pure <em>(vimala)</em> due to the teachings <em>(\u015B\u0101sana)</em> of a genuine <em>(sat)</em> Guru <em>(guru)</em>, [that] when It becomes liberated from <em>(muktam api)</em> the particularization <em>(up\u0101dhe\u1E25)</em> [known as] the physical body <em>(tanu)</em> [viz. when the body falls at the time of death], being devoid of <em>(\u015B\u016Bnyam iva)</em> another <em>(antara)</em> limiting condition <em>(up\u0101dhi)</em>, shines forth <em>(\u0101bh\u0101ti)</em> as \u015Aiva <em>(\u015Biva-r\u016Bpam)</em>[indeed].</p></div><div class="stanza"><a href="#s89" id="s89" class="num">89</a><p class="sans">\u0936\u093E\u0938\u094D\u0924\u094D\u0930\u093E\u0926\u093F\u092A\u094D\u0930\u093E\u092E\u093E\u0923\u094D\u092F\u093E\u0926\u0935\u093F\u091A\u0932\u093F\u0924\u0936\u094D\u0930\u0926\u094D\u0927\u092F\u093E\u092A\u093F \u0924\u0928\u094D\u092E\u092F\u0924\u093E\u092E\u094D \u0964<br> \u092A\u094D\u0930\u093E\u092A\u094D\u0924\u0903 \u0938 \u090F\u0935 \u092A\u0942\u0930\u094D\u0935\u0902 \u0938\u094D\u0935\u0930\u094D\u0917\u0902 \u0928\u0930\u0915\u0902 \u092E\u0928\u0941\u0937\u094D\u092F\u0924\u094D\u0935\u092E\u094D \u0965\u096E\u096F\u0965</p><p class="trans">\u015A\u0101str\u0101dipr\u0101m\u0101\u1E47y\u0101davicalita\u015Braddhay\u0101pi tanmayat\u0101m \u0964<br> Pr\u0101pta\u1E25 sa eva p\u016Brva\u1E41 svarga\u1E41 naraka\u1E41 manu\u1E63yatvam \u096589\u0965</p><p>\u0410\u0432\u0442\u043E\u0440\u0438\u0442\u0435\u0442\u043E\u043C <em>(pr\u0101m\u0101\u1E47y\u0101t)</em> \u043F\u0438\u0441\u0430\u043D\u0438\u0439 <em>(\u015B\u0101stra)</em> \u0438 \u0442\u043E\u043C\u0443 \u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0433\u043E <em>(\u0101di)</em>, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0442\u0432\u0451\u0440\u0434\u043E\u0439 \u0432\u0435\u0440\u043E\u0439 <em>(avicalita-\u015Braddhay\u0101 api)</em> \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u044F\u044F\u0441\u044C <em>(mayat\u0101m)</em> \u044D\u0442\u0438\u043C [\u0437\u043D\u0430\u043D\u0438\u0435\u043C] <em>(tad)</em>, \u043E\u043D <em>(sa\u1E25 eva)</em> \u0441\u043D\u0430\u0447\u0430\u043B\u0430 <em>(p\u016Brvam)</em> \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(pr\u0101pta\u1E25)</em> \u043D\u0435\u0431\u0435\u0441 <em>(svargam)</em>, \u0430\u0434\u0430 <em>(narakam)</em> \u0438\u043B\u0438 \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u043E\u0439 \u0444\u043E\u0440\u043C\u044B <em>(manu\u1E63yatvam)</em>.</p><p class="eng">Through the authority <em>(pr\u0101m\u0101\u1E47y\u0101t)</em> of the scriptures <em>(\u015B\u0101stra)</em> and so forth <em>(\u0101di)</em>, [and] by a unwavering faith <em>(avicalita-\u015Braddhay\u0101 api)</em>, he [a person] <em>(sa\u1E25 eva)</em> previously <em>(p\u016Brvam)</em> attains <em>(pr\u0101pta\u1E25)</em> identity <em>(mayat\u0101m)</em> with that <em>(tad)</em> [which he longs for. Subsequently, after the body falls, he goes either] to heaven <em>(svargam)</em> [or] to hell <em>(narakam)</em> [or] to the human condition <em>(manu\u1E63yatvam)</em>.</p></div><div class="stanza"><a href="#s90-91" id="s90-91" class="num">90-91</a><p class="sans">\u0905\u0928\u094D\u0924\u094D\u092F\u0903 \u0915\u094D\u0937\u0923\u0938\u094D\u0924\u0941 \u0924\u0938\u094D\u092E\u093F\u0928\u094D\u092A\u0941\u0923\u094D\u092F\u093E\u0902 \u092A\u093E\u092A\u093E\u0902 \u091A \u0935\u093E \u0938\u094D\u0925\u093F\u0924\u093F\u0902 \u092A\u0941\u0937\u094D\u092F\u0928\u094D \u0964<br> \u092E\u0942\u0922\u093E\u0928\u093E\u0902 \u0938\u0939\u0915\u093E\u0930\u0940\u092D\u093E\u0935\u0902 \u0917\u091A\u094D\u091B\u0924\u093F \u0917\u0924\u094C \u0924\u0941 \u0928 \u0938 \u0939\u0947\u0924\u0941\u0903 \u0965\u096F\u0966\u0965</p><p class="sans">\u092F\u0947\u093D\u092A\u093F \u0924\u0926\u093E\u0924\u094D\u092E\u0924\u094D\u0935\u0947\u0928 \u0935\u093F\u0926\u0941\u0903 \u092A\u0936\u0941\u092A\u0915\u094D\u0937\u093F\u0938\u0930\u0940\u0938\u0943\u092A\u093E\u0926\u092F\u0903 \u0938\u094D\u0935\u0917\u0924\u093F\u092E\u094D \u0964<br> \u0924\u0947\u093D\u092A\u093F \u092A\u0941\u0930\u093E\u0924\u0928\u0938\u092E\u094D\u092C\u094B\u0927\u0938\u0902\u0938\u094D\u0915\u0943\u0924\u093E\u0938\u094D\u0924\u093E\u0902 \u0917\u0924\u093F\u0902 \u092F\u093E\u0928\u094D\u0924\u093F \u0965\u096F\u0967\u0965</p><p class="trans">Antya\u1E25 k\u1E63a\u1E47astu tasminpu\u1E47y\u0101\u1E41 p\u0101p\u0101\u1E41 ca v\u0101 sthiti\u1E41 pu\u1E63yan \u0964<br> M\u016B\u1E0Dh\u0101n\u0101\u1E41 sahak\u0101r\u012Bbh\u0101va\u1E41 gacchati gatau tu na sa hetu\u1E25 \u096590\u0965</p><p class="trans">Ye\u2019pi tad\u0101tmatvena vidu\u1E25 pa\u015Bupak\u1E63isar\u012Bs\u1E5Bp\u0101daya\u1E25 svagatim \u0964<br> Te\u2019pi pur\u0101tanasambodhasa\u1E41sk\u1E5Bt\u0101st\u0101\u1E41 gati\u1E41 y\u0101nti \u096591\u0965</p><p>\u041F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u043C\u043E\u0435 <em>(pu\u1E63yan)</em> \u0432 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0439 <em>(antya\u1E25)</em> \u043C\u043E\u043C\u0435\u043D\u0442 <em>(k\u1E63a\u1E47a\u1E25 tu)</em> \u0431\u043B\u0430\u0433\u043E\u0435 <em>(pu\u1E47y\u0101m)</em> \u0438\u043B\u0438 <em>(ca v\u0101)</em> \u0433\u0440\u0435\u0448\u043D\u043E\u0435 <em>(p\u0101p\u0101m)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(sthitim)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u044E\u0449\u0435\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F <em>(sahak\u0101r\u012B-bh\u0101vam gacchati)</em> \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0430\u044E\u0449\u0438\u0445\u0441\u044F <em>(m\u016B\u1E0Dh\u0101n\u0101m)</em>, \u043D\u043E <em>(tu)</em> \u044D\u0442\u043E <em>(sa\u1E25)</em> \u043D\u0435 <em>(na)</em> \u043F\u0440\u0438\u0447\u0438\u043D\u0430 <em>(hetu\u1E25)</em> \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F <em>(gatau)</em> \u0434\u043B\u044F \u043D\u0435\u0433\u043E <em>(tasmin)</em>. \u0422\u0435 <em>(te)</em>, \u043A\u0442\u043E <em>(ye)</em> \u0431\u044B\u043B\u0438 \u0440\u0430\u043D\u0435\u0435 \u043F\u043E\u0441\u0432\u044F\u0449\u0435\u043D\u044B \u0432 \u0437\u043D\u0430\u043D\u0438\u0435 <em>(pur\u0101tana-sambodha-sa\u1E41sk\u1E5Bt\u0101\u1E25)</em>, \u0434\u0430\u0436\u0435 <em>(api\u2026 api)</em> \u0441\u0442\u0430\u0432 \u0434\u043E\u043C\u0430\u0448\u043D\u0438\u043C\u0438 \u0436\u0438\u0432\u043E\u0442\u043D\u044B\u043C\u0438, \u043F\u0442\u0438\u0446\u0430\u043C\u0438, \u0440\u0435\u043F\u0442\u0438\u043B\u0438\u044F\u043C\u0438 \u0438 \u0442.\u043F. <em>(pa\u015Bu-pak\u1E63i-sar\u012Bs\u1E5Bpa-\u0101daya\u1E25)</em>, \u0435\u0441\u043B\u0438 \u043E\u043D\u0438 \u0437\u043D\u0430\u044E\u0442 <em>(vidu\u1E25)</em> \u0441\u0432\u043E\u0451 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(sva-gatim)</em> \u043A\u0430\u043A \u042D\u0442\u043E \u0441\u0432\u043E\u0435\u0433\u043E \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0433\u043E \u042F <em>(tad-\u0101tmatvena)</em> [\u0432 \u043C\u043E\u043C\u0435\u043D\u0442 \u0441\u043C\u0435\u0440\u0442\u0438], \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0442 <em>(y\u0101nti)</em> \u0442\u043E\u0433\u043E <em>(t\u0101m)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(gatim)</em>.</p><p class="eng">The last <em>(antya\u1E25)</em> moment <em>(k\u1E63a\u1E47a\u1E25 tu)</em> nourishes or fosters <em>(pu\u1E63yan)</em> a virtuous <em>(pu\u1E47y\u0101m)</em> or <em>(ca v\u0101)</em> sinful <em>(p\u0101p\u0101m)</em> state <em>(sthitim)</em>, [and] becomes the cause <em>(sahak\u0101r\u012B-bh\u0101vam gacchati)</em> [of the course of destiny] in the case of the ones deluded by M\u0101y\u0101 <em>(m\u016B\u1E0Dh\u0101n\u0101m)</em>. But <em>(tu)</em> it \u2013i.e. the last moment\u2013 <em>(sa\u1E25)</em> is not <em>(na)</em> the cause <em>(hetu\u1E25)</em> of [such a] course of destiny <em>(gatau)</em> with respect to him \u2013viz. the Knower of the Self\u2013 <em>(tasmin)</em>. Even <em>(api\u2026 api)</em> those <em>(te)</em> who <em>(ye)</em> have been previously favored and sanctified by Knowledge <em>(pur\u0101tana-sambodha-sa\u1E41sk\u1E5Bt\u0101\u1E25)</em>, [even though] they are domestic animals, birds, reptiles, etc. <em>(pa\u015Bu-pak\u1E63i-sar\u012Bs\u1E5Bpa-\u0101daya\u1E25)</em>, if they know <em>(vidu\u1E25)</em> their state <em>(sva-gatim)</em> to be That of their own Self <em>(tad-\u0101tmatvena)</em> [at the time of death, then such beings] attain <em>(y\u0101nti)</em> that <em>(t\u0101m)</em> State <em>(gatim)</em>.</p></div><div class="stanza"><a href="#s92-93" id="s92-93" class="num">92-93</a><p class="sans">\u0938\u094D\u0935\u0930\u094D\u0917\u092E\u092F\u094B \u0928\u093F\u0930\u092F\u092E\u092F\u0938\u094D\u0924\u0926\u092F\u0902 \u0926\u0947\u0939\u093E\u0928\u094D\u0924\u0930\u093E\u0932\u0917\u0903 \u092A\u0941\u0930\u0941\u0937\u0903 \u0964<br> \u0924\u0926\u094D\u092D\u0919\u094D\u0917\u0947 \u0938\u094D\u0935\u094C\u091A\u093F\u0924\u094D\u092F\u093E\u0926\u094D\u0926\u0947\u0939\u093E\u0928\u094D\u0924\u0930\u092F\u094B\u0917\u092E\u092D\u094D\u092F\u0947\u0924\u093F \u0965\u096F\u0968\u0965</p><p class="sans">\u090F\u0935\u0902 \u091C\u094D\u091E\u093E\u0928\u093E\u0935\u0938\u0930\u0947 \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u093E \u0938\u0915\u0943\u0926\u0938\u094D\u092F \u092F\u093E\u0926\u0943\u0917\u0935\u092D\u093E\u0924\u0903 \u0964<br> \u0924\u093E\u0926\u0943\u0936 \u090F\u0935 \u0924\u0926\u093E\u0938\u094C \u0928 \u0926\u0947\u0939\u092A\u093E\u0924\u0947\u093D\u0928\u094D\u092F\u0925\u093E \u092D\u0935\u0924\u093F \u0965\u096F\u0969\u0965</p><p class="trans">Svargamayo nirayamayastadaya\u1E41 deh\u0101ntar\u0101laga\u1E25 puru\u1E63a\u1E25 \u0964<br> Tadbha\u1E45ge svaucity\u0101ddeh\u0101ntarayogamabhyeti \u096592\u0965</p><p class="trans">Eva\u1E41 j\xF1\u0101n\u0101vasare sv\u0101tm\u0101 sak\u1E5Bdasya y\u0101d\u1E5Bgavabh\u0101ta\u1E25 \u0964<br> T\u0101d\u1E5B\u015Ba eva tad\u0101sau na dehap\u0101te\u2019nyath\u0101 bhavati \u096593\u0965</p><p>\u0422\u0430\u043A <em>(tad)</em>, \u044D\u0442\u0430 <em>(ayam)</em> \u0438\u043D\u0434\u0438\u0432\u0438\u0434\u0443\u0430\u043B\u044C\u043D\u0430\u044F \u0434\u0443\u0448\u0430 <em>(puru\u1E63a\u1E25)</em> \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0430\u044F <em>(ga\u1E25)</em> \u0432\u043D\u0443\u0442\u0440\u0438 <em>(antar\u0101la)</em> \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0442\u0435\u043B\u0430 <em>(deha)</em> \u0435\u0441\u0442\u044C \u0440\u0430\u0439 <em>(svarga-maya\u1E25)</em> [\u0438\u043B\u0438] \u0430\u0434 <em>(niraya-maya\u1E25)</em>. \u041A\u043E\u0433\u0434\u0430 [\u044D\u0442\u043E \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0442\u0435\u043B\u043E] \u043E\u0442\u0431\u0440\u043E\u0448\u0435\u043D\u043E <em>(tad-bha\u1E45ge)</em>, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0435 \u0441 <em>(yogam abhyeti)</em> \u0434\u0440\u0443\u0433\u0438\u043C <em>(antara)</em> \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u0442\u0435\u043B\u043E\u043C <em>(deha)</em> \u043F\u043E\u0434\u0445\u043E\u0434\u044F\u0449\u0438\u043C <em>(aucity\u0101t)</em> \u0434\u043B\u044F \u043D\u0435\u0451 <em>(sva)</em>. \u0422\u0430\u043A\u0438\u043C \u0436\u0435 \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u0432 \u043C\u043E\u043C\u0435\u043D\u0442 <em>(avasare)</em> [\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u044F] \u0437\u043D\u0430\u043D\u0438\u044F <em>(j\xF1\u0101na)</em>, \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F <em>(sva)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C <em>(\u0101tm\u0101)</em> \u0432 \u0442\u043E\u0442 \u0436\u0435 \u043C\u043E\u043C\u0435\u043D\u0442 <em>(sak\u1E5Bt)</em> \u0441\u0430\u043C\u0430 \u0441\u043E\u0431\u043E\u0439 <em>(y\u0101d\u1E5Bk)</em> \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(avabh\u0101ta\u1E25)</em> \u043F\u0435\u0440\u0435\u0434 \u043D\u0435\u0439 <em>(asya)</em>. \u0412\u0441\u0435\u0433\u0434\u0430 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044F \u044D\u0442\u043E \u0442\u0430\u043A <em>(t\u0101d\u1E5B\u015Ba\u1E25 eva)</em> \u043E\u043D\u0430 <em>(asau)</em> \u0432\u043E\u043F\u0440\u0435\u043A\u0438 <em>(anyath\u0101)</em> \u043F\u0430\u0434\u0435\u043D\u0438\u044E \u0442\u0435\u043B\u0430 <em>(deha-p\u0101te)</em>, \u043D\u0435 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 [\u0441\u043D\u043E\u0432\u0430] <em>(na\u2026 bhavati)</em>.</p><p class="eng">Therefore <em>(tad)</em>, this <em>(ayam)</em> individual soul \u2013i.e. the limited being\u2013 <em>(puru\u1E63a\u1E25)</em> who is <em>(ga\u1E25)</em> inside <em>(antar\u0101la)</em> a physical body <em>(deha)</em> is heaven <em>(svarga-maya\u1E25)</em> [or] hell <em>(niraya-maya\u1E25)</em>. When that [physical body] is eliminated <em>(tad-bha\u1E45ge)</em>,[the individual soul] comes into contact with <em>(yogam abhyeti)</em> another <em>(antara)</em> physical body <em>(deha)</em> according to [the tendencies which are adequately] suitable <em>(aucity\u0101t)</em> for himself \u2013for such an individual soul\u2013 <em>(sva)</em>. Similarly <em>(evam)</em>, at the moment <em>(avasare)</em> Knowledge [is revealed] <em>(j\xF1\u0101na)</em>, his own <em>(sva)</em> Self <em>(\u0101tm\u0101)</em> appears <em>(avabh\u0101ta\u1E25)</em> at once <em>(sak\u1E5Bt)</em> as such <em>(y\u0101d\u1E5Bk)</em> before him \u2013before the limited being\u2013 <em>(asya)</em>. [After that,] He \u2013the Self\u2013 <em>(asau)</em> [is experienced] always \u2013Abhinavagupta wrote \u201Ctad\u0101\u201D or \u201Cthen\u201D, but it should preferably be \u201Csad\u0101\u201D or \u201Calways\u201D\u2013 <em>(tad\u0101)</em> like that <em>(t\u0101d\u1E5B\u015Ba\u1E25 eva)</em> \u2013as his essential nature\u2013, [and] when his physical body falls <em>(deha-p\u0101te)</em>, [He] is not <em>(na\u2026 bhavati)</em> otherwise <em>(anyath\u0101)</em>\u2013the Self remains revealed and never covered or veiled by anything\u2013</p></div><div class="stanza"><a href="#s94-95" id="s94-95" class="num">94-95</a><p class="sans">\u0915\u0930\u0923\u0917\u0923\u0938\u092E\u094D\u092A\u094D\u0930\u092E\u094B\u0937\u0903 \u0938\u094D\u092E\u0943\u0924\u093F\u0928\u093E\u0936\u0903 \u0936\u094D\u0935\u093E\u0938\u0915\u0932\u093F\u0932\u0924\u093E \u091A\u094D\u091B\u0947\u0926\u0903 \u0964<br> \u092E\u0930\u094D\u092E\u0938\u0941 \u0930\u0941\u091C\u093E\u0935\u093F\u0936\u0947\u0937\u093E\u0903 \u0936\u0930\u0940\u0930\u0938\u0902\u0938\u094D\u0915\u093E\u0930\u091C\u094B \u092D\u094B\u0917\u0903 \u0965\u096F\u096A\u0965</p><p class="sans">\u0938 \u0915\u0925\u0902 \u0935\u093F\u0917\u094D\u0930\u0939\u092F\u094B\u0917\u0947 \u0938\u0924\u093F \u0928 \u092D\u0935\u0947\u0924\u094D\u0924\u0947\u0928 \u092E\u094B\u0939\u092F\u094B\u0917\u0947\u093D\u092A\u093F \u0964<br> \u092E\u0930\u0923\u093E\u0935\u0938\u0930\u0947 \u091C\u094D\u091E\u093E\u0928\u0940 \u0928 \u091A\u094D\u092F\u0935\u0924\u0947 \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u092A\u0930\u092E\u093E\u0930\u094D\u0925\u093E\u0924\u094D \u0965\u096F\u096B\u0965</p><p class="trans">Kara\u1E47aga\u1E47asampramo\u1E63a\u1E25 sm\u1E5Btin\u0101\u015Ba\u1E25 \u015Bv\u0101sakalilat\u0101 ccheda\u1E25 \u0964<br> Marmasu ruj\u0101vi\u015Be\u1E63\u0101\u1E25 \u015Bar\u012Brasa\u1E41sk\u0101rajo bhoga\u1E25 \u096594\u0965</p><p class="trans">Sa katha\u1E41 vigrahayoge sati na bhavettena mohayoge\u2019pi \u0964<br> Mara\u1E47\u0101vasare j\xF1\u0101n\u012B na cyavate sv\u0101tmaparam\u0101rth\u0101t \u096595\u0965</p><p>\u041F\u043E\u043B\u043D\u043E\u0435 \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435 <em>(sampramo\u1E63a\u1E25)</em> \u0433\u0440\u0443\u043F\u043F\u044B <em>(ga\u1E47a)</em> \u043E\u0440\u0433\u0430\u043D\u043E\u0432 <em>(kara\u1E47a)</em>, \u043F\u043E\u0442\u0435\u0440\u044F <em>(n\u0101\u015Ba\u1E25)</em> \u043F\u0430\u043C\u044F\u0442\u0438 <em>(sm\u1E5Bti)</em>, \u0441\u043F\u0430\u0437\u043C\u044B <em>(kalilat\u0101)</em> \u0434\u044B\u0445\u0430\u043D\u0438\u044F <em>(\u015Bv\u0101sa)</em>, \u0440\u0430\u0437\u0440\u044B\u0432\u044B <em>(cheda\u1E25)</em> \u0442\u043A\u0430\u043D\u0435\u0439 <em>(marmasu)</em>, \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 <em>(vi\u015Be\u1E63\u0101\u1E25)</em> \u043B\u0438\u0445\u043E\u0440\u0430\u0434\u043A\u0438 <em>(ruj\u0101)</em> \u043F\u0440\u0438\u043D\u043E\u0441\u044F\u0442 \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u044F <em>(bhoga\u1E25)</em> \u0442\u0435\u043B\u0443 <em>(\u015Bar\u012Bra)</em> \u043F\u043E \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(ja\u1E25)</em> \u043D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u043D\u044B\u0445 \u0432\u043F\u0435\u0447\u0430\u0442\u043B\u0435\u043D\u0438\u0439 <em>(sa\u1E41sk\u0101ra)</em>. \u041A\u0430\u043A <em>(katham)</em> \u044D\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u043D\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442\u044C <em>(sa\u1E25\u2026 na\u2026 bhavet)</em> \u043A\u043E\u0433\u0434\u0430 \u0435\u0441\u0442\u044C \u043A\u043E\u043D\u0442\u0430\u043A\u0442 \u0441 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u0442\u0435\u043B\u043E\u043C <em>(vigraha-yoge sati)</em>? \u0412 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 <em>(tena)</em>, \u0437\u043D\u0430\u044E\u0449\u0438\u0439 <em>(j\xF1\u0101n\u012B)</em>, \u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 <em>(api)</em> \u0435\u0441\u0442\u044C \u0441\u0432\u044F\u0437\u044C \u0441 <em>(yoge)</em> \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u043E\u043C <em>(moha)</em> \u0432 \u043C\u043E\u043C\u0435\u043D\u0442 <em>(avasare)</em> \u0441\u043C\u0435\u0440\u0442\u0438 <em>(mara\u1E47a)</em>, \u043D\u0435 \u043E\u0442\u043A\u043B\u043E\u043D\u044F\u0435\u0442\u0441\u044F <em>(na cyavate)</em> \u043E\u0442 \u0412\u044B\u0441\u0448\u0435\u0439 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(parama-arth\u0101t)</em> \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(sva)</em> \u042F <em>(\u0101tma)</em>.</p><p class="eng">Complete destruction <em>(sampramo\u1E63a\u1E25)</em> of the group <em>(ga\u1E47a)</em> of [thirteen] organs <em>(kara\u1E47a)</em>, loss <em>(n\u0101\u015Ba\u1E25)</em> of memory <em>(sm\u1E5Bti)</em>, stammering <em>(kalilat\u0101)</em> of the air [in the region of the throat] <em>(\u015Bv\u0101sa)</em> \u2013i.e. spasmodic movement of the air in that area\u2013, separation <em>(cheda\u1E25)</em> in the joints <em>(marmasu)</em> [and] various <em>(vi\u015Be\u1E63\u0101\u1E25)</em> ailments [such as fever, dysentery, etc.] <em>(ruj\u0101)</em> [constitute] the experience of pain <em>(bhoga\u1E25)</em> that is caused by <em>(ja\u1E25)</em> the accumulated impressions <em>(sa\u1E41sk\u0101ra)</em> relating to the physical body <em>(\u015Bar\u012Bra)</em>. How <em>(katham)</em> could it \u2013the abovementioned experience of pain\u2014not happen <em>(sa\u1E25\u2026 na\u2026 bhavet)</em> when there is contact with the physical body <em>(vigraha-yoge sati)</em>? On that account <em>(tena)</em>, the Knower of the Self <em>(j\xF1\u0101n\u012B)</em>, even if <em>(api)</em> there is a relationship with <em>(yoge)</em> M\u0101y\u0101 \u2013viz. ignorance connected with the physical body\u2013 <em>(moha)</em> [being generated] at the time <em>(avasare)</em> of death <em>(mara\u1E47a)</em>, does not deviate <em>(na cyavate)</em> from the Highest Reality <em>(parama-arth\u0101t)</em> [called] his own <em>(sva)</em> Self <em>(\u0101tma)</em>.</p></div><div class="stanza"><a href="#s96" id="s96" class="num">96</a><p class="sans">\u092A\u0930\u092E\u093E\u0930\u094D\u0925\u092E\u093E\u0930\u094D\u0917\u092E\u0947\u0928\u0902 \u091D\u091F\u093F\u0924\u093F \u092F\u0926\u093E \u0917\u0941\u0930\u0941\u092E\u0941\u0916\u093E\u0924\u094D\u0938\u092E\u092D\u094D\u092F\u0947\u0924\u093F \u0964<br> \u0905\u0924\u093F\u0924\u0940\u0935\u094D\u0930\u0936\u0915\u094D\u0924\u093F\u092A\u093E\u0924\u093E\u0924\u094D\u0924\u0926\u0948\u0935 \u0928\u093F\u0930\u094D\u0935\u093F\u0918\u094D\u0928\u092E\u0947\u0935 \u0936\u093F\u0935\u0903 \u0965\u096F\u096C\u0965</p><p class="trans">Param\u0101rtham\u0101rgamena\u1E41 jha\u1E6Diti yad\u0101 gurumukh\u0101tsamabhyeti \u0964<br> Atit\u012Bvra\u015Baktip\u0101t\u0101ttadaiva nirvighnameva \u015Biva\u1E25 \u096596\u0965</p><p>\u041A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u044D\u0442\u043E\u0442 <em>(enam)</em> \u043F\u0443\u0442\u044C <em>(m\u0101rgam)</em> \u0412\u044B\u0441\u0448\u0435\u0439 \u0418\u0441\u0442\u0438\u043D\u044B <em>(parama-artha)</em> \u043F\u043E\u043B\u0443\u0447\u0435\u043D <em>(samabhyeti)</em> \u0438\u0437 \u0443\u0441\u0442 <em>(mukh\u0101t)</em> \u0413\u0443\u0440\u0443 <em>(guru)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101 eva)</em>, \u0447\u0435\u0440\u0435\u0437 \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0441\u0438\u043B\u044C\u043D\u043E\u0435 \u0441\u043D\u0438\u0441\u0445\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0421\u0438\u043B\u044B <em>(ati-t\u012Bvra-\u015Bakti-p\u0101t\u0101t)</em>, \u043E\u043D \u0431\u044B\u0441\u0442\u0440\u043E \u0438 \u0431\u0435\u0441\u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E [\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F] \u0428\u0438\u0432\u043E\u0439 <em>(jha\u1E6Diti\u2026 nirvighnam eva \u015Biva\u1E25)</em>.</p><p class="eng">When <em>(yad\u0101)</em> [a certain person who is in his last birth] receives <em>(samabhyeti)</em> this <em>(enam)</em> path <em>(m\u0101rgam)</em> of the Highest Reality <em>(parama-artha)</em> from the mouth <em>(mukh\u0101t)</em> of [his] Guru <em>(guru)</em>, then <em>(tad\u0101 eva)</em>, through an excessively strong descent of Power <em>(ati-t\u012Bvra-\u015Bakti-p\u0101t\u0101t)</em>, he instantly and unobstructedly [becomes] \u015Aiva <em>(jha\u1E6Diti\u2026 nirvighnam eva \u015Biva\u1E25)</em>.</p></div><div class="stanza"><a href="#s97" id="s97" class="num">97</a><p class="sans">\u0938\u0930\u094D\u0935\u094B\u0924\u094D\u0924\u0940\u0930\u094D\u0923\u0902 \u0930\u0942\u092A\u0902 \u0938\u094B\u092A\u093E\u0928\u092A\u0926\u0915\u094D\u0930\u092E\u0947\u0923 \u0938\u0902\u0936\u094D\u0930\u092F\u0924\u0903 \u0964<br> \u092A\u0930\u0924\u0924\u094D\u0924\u094D\u0935\u0930\u0942\u0922\u093F\u0932\u093E\u092D\u0947 \u092A\u0930\u094D\u092F\u0928\u094D\u0924\u0947 \u0936\u093F\u0935\u092E\u092F\u0940\u092D\u093E\u0935\u0903 \u0965\u096F\u096D\u0965</p><p class="trans">Sarvott\u012Br\u1E47a\u1E41 r\u016Bpa\u1E41 sop\u0101napadakrame\u1E47a sa\u1E41\u015Brayata\u1E25 \u0964<br> Paratattvar\u016B\u1E0Dhil\u0101bhe paryante \u015Bivamay\u012Bbh\u0101va\u1E25 \u096597\u0965</p><p>\u0420\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u0430\u0432\u0448\u0438\u0439 <em>(sa\u1E41\u015Brayata\u1E25)</em> \u0442\u0440\u0430\u043D\u0441\u0446\u0435\u043D\u0434\u0435\u043D\u0442\u043D\u0443\u044E <em>(utt\u012Br\u1E47am)</em> \u0432\u0441\u0435\u043C\u0443 <em>(sarva)</em> \u041F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(r\u016Bpam)</em> \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u044B\u043C \u043C\u0435\u0442\u043E\u0434\u043E\u043C <em>(krame\u1E47a)</em> \u043F\u043E\u0434\u044A\u0435\u043C\u0430 <em>(pada)</em> \u043F\u043E \u0441\u0442\u0443\u043F\u0435\u043D\u044F\u043C <em>(sop\u0101na)</em>, \u0432\u0437\u043E\u0439\u0434\u044F <em>(r\u016B\u1E0Dhi-l\u0101bhe)</em> \u043A \u0412\u044B\u0441\u0448\u0435\u043C\u0443 <em>(para)</em> \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0443 <em>(tattva)</em>, \u0432 \u043A\u043E\u043D\u0446\u0435 \u043A\u043E\u043D\u0446\u043E\u0432 <em>(paryante)</em> \u0441\u043B\u0438\u0432\u0430\u0435\u0442\u0441\u044F <em>(may\u012B-bh\u0101va\u1E25)</em> \u0441 \u0428\u0438\u0432\u043E\u0439 <em>(\u015Biva)</em>.</p><p class="eng">To him who, [not having attained the teaching about the perfect Knowledge due to a soft descent of Power,] realizes <em>(sa\u1E41\u015Brayata\u1E25)</em> the Nature <em>(r\u016Bpam)</em> which transcends <em>(utt\u012Br\u1E47am)</em> all <em>(sarva)</em> by the gradual method <em>(krame\u1E47a)</em> of climbing up <em>(pada)</em> the ladders \u2013viz. the successive stages to go up higher and higher\u2013 <em>(sop\u0101na)</em>, after ascending <em>(r\u016B\u1E0Dhi-l\u0101bhe)</em> into the Supreme <em>(para)</em> Principle <em>(tattva)</em> [as far as possible while living, a full] identification <em>(may\u012B-bh\u0101va\u1E25)</em> with \u015Aiva <em>(\u015Biva)</em> [takes place] at the end \u2013i.e. at the moment when his body falls\u2013 <em>(paryante)</em>.</p></div><div class="stanza"><a href="#s98-99" id="s98-99" class="num">98-99</a><p class="sans">\u0924\u0938\u094D\u092F \u0924\u0941 \u092A\u0930\u092E\u093E\u0930\u094D\u0925\u092E\u092F\u0940\u0902 \u0927\u093E\u0930\u093E\u092E\u0917\u0924\u0938\u094D\u092F \u092E\u0927\u094D\u092F\u0935\u093F\u0936\u094D\u0930\u093E\u0928\u094D\u0924\u0947\u0903 \u0964<br> \u0924\u0924\u094D\u092A\u0926\u0932\u093E\u092D\u094B\u0924\u094D\u0938\u0941\u0915\u091A\u0947\u0924\u0938\u094B\u093D\u092A\u093F \u092E\u0930\u0923\u0902 \u0915\u0926\u093E\u091A\u093F\u0924\u094D\u0938\u094D\u092F\u093E\u0924\u094D \u0965\u096F\u096E\u0965</p><p class="sans">\u092F\u094B\u0917\u092D\u094D\u0930\u0937\u094D\u091F\u0903 \u0936\u093E\u0938\u094D\u0924\u094D\u0930\u0947 \u0915\u0925\u093F\u0924\u094B\u093D\u0938\u094C \u091A\u093F\u0924\u094D\u0930\u092D\u094B\u0917\u092D\u0941\u0935\u0928\u092A\u0924\u093F\u0903 \u0964<br> \u0935\u093F\u0936\u094D\u0930\u093E\u0928\u094D\u0924\u093F\u0938\u094D\u0925\u093E\u0928\u0935\u0936\u093E\u0926\u094D\u092D\u0942\u0924\u094D\u0935\u093E \u091C\u0928\u094D\u092E\u093E\u0928\u094D\u0924\u0930\u0947 \u0936\u093F\u0935\u0940\u092D\u0935\u0924\u093F \u0965\u096F\u096F\u0965</p><p class="trans">Tasya tu param\u0101rthamay\u012B\u1E41 dh\u0101r\u0101magatasya madhyavi\u015Br\u0101nte\u1E25 \u0964<br> Tatpadal\u0101bhotsukacetaso\u2019pi mara\u1E47a\u1E41 kad\u0101citsy\u0101t \u096598\u0965</p><p class="trans">Yogabhra\u1E63\u1E6Da\u1E25 \u015B\u0101stre kathito\u2019sau citrabhogabhuvanapati\u1E25 \u0964<br> Vi\u015Br\u0101ntisth\u0101nava\u015B\u0101dbh\u016Btv\u0101 janm\u0101ntare \u015Biv\u012Bbhavati \u096599\u0965</p><p>\u041D\u043E <em>(tu)</em> \u043E\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u0439 <em>(vi\u015Br\u0101nte\u1E25)</em> \u043D\u0430 \u043F\u043E\u043B\u043F\u0443\u0442\u0438 <em>(madhya)</em> \u043F\u0440\u0438\u0445\u043E\u0434\u043E\u043C <em>(sy\u0101t)</em> \u0432 \u043A\u0430\u043A\u043E\u0439-\u0442\u043E \u043C\u043E\u043C\u0435\u043D\u0442 <em>(kad\u0101cid)</em> \u0441\u043C\u0435\u0440\u0442\u0438 <em>(mara\u1E47am)</em> \u043D\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(agatasya)</em> \u043F\u043E\u0442\u043E\u043A\u0430 <em>(dh\u0101r\u0101m)</em> \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u043E\u0433\u043E <em>(may\u012Bm)</em> \u0412\u044B\u0441\u0448\u0435\u0439 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E <em>(parama-artha)</em>, \u0445\u043E\u0442\u044C <em>(api)</em> \u0435\u0433\u043E \u0443\u043C <em>(cetasa\u1E25)</em> [\u0438] \u043D\u0430\u043C\u0435\u0440\u0435\u043D <em>(utsuka)</em> \u0434\u043E\u0441\u0442\u0438\u0447\u044C <em>(l\u0101bha)</em> \u044D\u0442\u043E\u0433\u043E <em>(tad)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(pada)</em>. \u0422\u0430\u043A\u043E\u0433\u043E <em>(asau)</em>, \u043F\u0438\u0441\u0430\u043D\u0438\u044F <em>(\u015B\u0101stre)</em> \u0438\u043C\u0435\u043D\u0443\u044E\u0442 <em>(kathita\u1E25)</em> \u043E\u0442\u043F\u0430\u0432\u0448\u0438\u043C <em>(bhra\u1E63\u1E6Da\u1E25)</em> \u043E\u0442 \u0439\u043E\u0433\u0438 <em>(yoga)</em>. \u041E\u043D \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0432\u043B\u0430\u0434\u044B\u043A\u043E\u0439 <em>(pati\u1E25)</em> \u043C\u0438\u0440\u043E\u0432 <em>(bhuvana)</em> \u0432\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u043D\u044B\u0445 <em>(citra)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0439 <em>(bhoga)</em>. \u0412 \u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u0435 <em>(va\u015B\u0101t)</em> [\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u044F \u0432] \u043C\u0435\u0441\u0442\u0430\u0445 \u043E\u0442\u0434\u044B\u0445\u0430 <em>(vi\u015Br\u0101nti-sth\u0101na)</em>, \u043F\u043E\u0441\u043B\u0435 \u043F\u0440\u0438\u043D\u044F\u0442\u0438\u044F <em>(bh\u016Btv\u0101)</em> \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u0447\u043D\u043E\u0433\u043E <em>(antare)</em> \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F <em>(janma)</em>, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0428\u0438\u0432\u043E\u0439 <em>(\u015Biv\u012B-bhavati)</em>.</p><p class="eng">But <em>(tu)</em> in the case of one who stops <em>(vi\u015Br\u0101nte\u1E25)</em> half-way <em>(madhya)</em> [due to some obstacle and] does not attain <em>(agatasya)</em> the Stream <em>(dh\u0101r\u0101m)</em> full of <em>(may\u012Bm)</em> the Highest Reality <em>(parama-artha)</em>; [or if,] though <em>(api)</em> his mind <em>(cetasa\u1E25)</em> is eager to <em>(utsuka)</em> acquire <em>(l\u0101bha)</em> that <em>(tad)</em> State <em>(pada)</em>, death <em>(mara\u1E47am)</em> occurs <em>(sy\u0101t)</em> at some moment <em>(kad\u0101cid)</em> [in the middle of his practice. Then,] he <em>(asau)</em>, [in both situations,] is said to be <em>(kathita\u1E25)</em> one who has fallen <em>(bhra\u1E63\u1E6Da\u1E25)</em> from Yoga <em>(yoga)</em> in the [revealed] scripture[s] <em>(\u015B\u0101stre)</em>. [When his physical body dies,] he becomes a lord <em>(pati\u1E25)</em> of the worlds <em>(bhuvana)</em> [replete with] wonderful <em>(citra)</em> enjoyments <em>(bhoga)</em>. [On the cessation of his right to those enjoyments, and] on account of <em>(va\u015B\u0101t)</em> [the awakening of the accumulated impressions belonging to that practice of focusing his attention on successive] resting places <em>(vi\u015Br\u0101nti-sth\u0101na)</em>, [such a person,] after taking <em>(bh\u016Btv\u0101)</em> another <em>(antare)</em> birth <em>(janma)</em>, [easily ascends into the State which had been perceived in his previous birth or life, and finally, once such a physical body falls,] he becomes<br> \u015Aiva <em>(\u015Biv\u012B-bhavati)</em>.</p></div><div class="stanza"><a href="#s100-101" id="s100-101" class="num">100-101</a><p class="sans">\u092A\u0930\u092E\u093E\u0930\u094D\u0925\u092E\u093E\u0930\u094D\u0917\u092E\u0947\u0928\u0902 \u0939\u094D\u092F\u092D\u094D\u092F\u0938\u094D\u092F\u093E\u092A\u094D\u0930\u093E\u092A\u094D\u092F \u092F\u094B\u0917\u092E\u092A\u093F \u0928\u093E\u092E \u0964<br> \u0938\u0941\u0930\u0932\u094B\u0915\u092D\u094B\u0917\u092D\u093E\u0917\u0940 \u092E\u0941\u0926\u093F\u0924\u092E\u0928\u093E \u092E\u094B\u0926\u0924\u0947 \u0938\u0941\u091A\u093F\u0930\u092E\u094D \u0965\u0967\u0966\u0966\u0965</p><p class="sans">\u0935\u093F\u0937\u092F\u0947\u0937\u0941 \u0938\u093E\u0930\u094D\u0935\u092D\u094C\u092E\u0903 \u0938\u0930\u094D\u0935\u091C\u0928\u0948\u0903 \u092A\u0942\u091C\u094D\u092F\u0924\u0947 \u092F\u0925\u093E \u0930\u093E\u091C\u093E \u0964<br> \u092D\u0941\u0935\u0928\u0947\u0937\u0941 \u0938\u0930\u094D\u0935\u0926\u0948\u0935\u0948\u0930\u094D\u092F\u094B\u0917\u092D\u094D\u0930\u0937\u094D\u091F\u0938\u094D\u0924\u0925\u093E \u092A\u0942\u091C\u094D\u092F\u0903 \u0965\u0967\u0966\u0967\u0965</p><p class="trans">Param\u0101rtham\u0101rgamena\u1E41 hyabhyasy\u0101pr\u0101pya yogamapi n\u0101ma \u0964<br> Suralokabhogabh\u0101g\u012B muditaman\u0101 modate suciram \u0965100\u0965</p><p class="trans">Vi\u1E63aye\u1E63u s\u0101rvabhauma\u1E25 sarvajanai\u1E25 p\u016Bjyate yath\u0101 r\u0101j\u0101 \u0964<br> Bhuvane\u1E63u sarvadaivairyogabhra\u1E63\u1E6Dastath\u0101 p\u016Bjya\u1E25 \u0965101\u0965</p><p>\u0414\u0430\u0436\u0435 <em>(api)</em> \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0432\u0448\u0438\u0439 <em>(abhyasya)</em> \u044D\u0442\u043E\u0442 <em>(enam)</em> \u043F\u0443\u0442\u044C <em>(m\u0101rgam)</em> \u0412\u044B\u0441\u0448\u0435\u0439 <em>(parama)</em> \u0446\u0435\u043B\u0438 <em>(artha)</em> \u0432\u0435\u0440\u043D\u043E <em>(hi)</em>, \u043D\u043E <em>(n\u0101ma)</em> \u043D\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0432\u0448\u0438\u0439 <em>(apr\u0101pya)</em> \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 <em>(yogam)</em>, \u0432\u043A\u0443\u0448\u0430\u0435\u0442 <em>(bh\u0101g\u012B)</em> \u0443\u0434\u043E\u0432\u043E\u043B\u044C\u0441\u0442\u0432\u0438\u044F <em>(bhoga)</em> \u043C\u0438\u0440\u0430 <em>(loka)</em> \u0431\u043E\u0433\u043E\u0432 <em>(sura)</em>, [\u0433\u0434\u0435] \u0441 \u0443\u043C\u043E\u043C \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u043C \u0440\u0430\u0434\u043E\u0441\u0442\u044C\u044E <em>(mudita-man\u0101)</em> \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u0435\u0442\u0441\u044F <em>(modate)</em> \u043E\u0447\u0435\u043D\u044C \u0434\u043E\u043B\u0433\u043E\u0435 \u0432\u0440\u0435\u043C\u044F <em>(suciram)</em>. \u041A\u0430\u043A <em>(yath\u0101)</em> \u0446\u0430\u0440\u044C <em>(r\u0101j\u0101)</em> \u0441\u0430\u043C\u043E\u0434\u0435\u0440\u0436\u0430\u0432\u0435\u0446 <em>(s\u0101rvabhauma\u1E25)</em> \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F <em>(p\u016Bjyate)</em> \u0432\u0441\u0435\u043C\u0438 \u043B\u044E\u0434\u044C\u043C\u0438 <em>(sarva-janai\u1E25)</em> \u0446\u0430\u0440\u0441\u0442\u0432\u0430 <em>(vi\u1E63aye\u1E63u)</em>, \u0442\u0430\u043A \u0436\u0435 <em>(tath\u0101)</em> \u043E\u0442\u043F\u0430\u0432\u0448\u0438\u0439 <em>(bhra\u1E63\u1E6Da\u1E25)</em> \u043E\u0442 \u0439\u043E\u0433\u0438 <em>(yoga)</em> \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F <em>(p\u016Bjya\u1E25)</em> \u0432\u0441\u0435\u043C\u0438 \u0431\u043E\u0433\u0430\u043C\u0438 <em>(sarva-daivai\u1E25)</em> \u0432 [\u0440\u0430\u0439\u0441\u043A\u0438\u0445] \u043C\u0438\u0440\u0430\u0445 <em>(bhuvane\u1E63u)</em>.</p><p class="eng">Even <em>(api)</em> after having practiced <em>(abhyasya)</em> this <em>(enam)</em> path <em>(m\u0101rgam)</em> of the Highest <em>(parama)</em> Reality <em>(artha)</em> indeed <em>(hi)</em>, but <em>(n\u0101ma)</em> not having attained <em>(apr\u0101pya)</em> a [repose characterized by a right] union [with his own Self] <em>(yogam)</em>,[he, the one who fell from Yoga,] partakes of <em>(bh\u0101g\u012B)</em> the enjoyments <em>(bhoga)</em> in the worlds <em>(loka)</em> of the gods <em>(sura)</em>,[and] with his mind full of cheerfulness <em>(mudita-man\u0101)</em>, he is happy <em>(modate)</em> [there] for a very long time <em>(suciram)</em>. Just as <em>(yath\u0101)</em> a sovereign <em>(r\u0101j\u0101)</em> [and] universal monarch <em>(s\u0101rvabhauma\u1E25)</em> is worshiped <em>(p\u016Bjyate)</em> by all the people <em>(sarva-janai\u1E25)</em> in [his] territories <em>(vi\u1E63aye\u1E63u)</em>, in the same way <em>(tath\u0101)</em>, one who has fallen <em>(bhra\u1E63\u1E6Da\u1E25)</em> from Yoga <em>(yoga)</em> [is]worshiped <em>(p\u016Bjya\u1E25)</em> by all the gods <em>(sarva-daivai\u1E25)</em> in [each of their heavenly] worlds <em>(bhuvane\u1E63u)</em>.</p></div><div class="stanza"><a href="#s102" id="s102" class="num">102</a><p class="sans">\u092E\u0939\u0924\u093E \u0915\u093E\u0932\u0947\u0928 \u092A\u0941\u0928\u0930\u094D\u092E\u093E\u0928\u0941\u0937\u094D\u092F\u0902 \u092A\u094D\u0930\u093E\u092A\u094D\u092F \u092F\u094B\u0917\u092E\u092D\u094D\u092F\u0938\u094D\u092F \u0964<br> \u092A\u094D\u0930\u093E\u092A\u094D\u0928\u094B\u0924\u093F \u0926\u093F\u0935\u094D\u092F\u092E\u092E\u0943\u0924\u0902 \u092F\u0938\u094D\u092E\u093E\u0926\u093E\u0935\u0930\u094D\u0924\u0924\u0947 \u0928 \u092A\u0941\u0928\u0903 \u0965\u0967\u0966\u0968\u0965</p><p class="trans">Mahat\u0101 k\u0101lena punarm\u0101nu\u1E63ya\u1E41 pr\u0101pya yogamabhyasya \u0964<br> Pr\u0101pnoti divyamam\u1E5Bta\u1E41 yasm\u0101d\u0101vartate na puna\u1E25 \u0965102\u0965</p><p>\u041F\u043E\u0441\u043B\u0435 \u0434\u043E\u043B\u0433\u043E\u0433\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438 <em>(mahat\u0101 k\u0101lena)</em> \u043E\u0431\u0440\u0435\u0442\u044F <em>(pr\u0101pya)</em> \u0441\u043D\u043E\u0432\u0430 <em>(punar)</em> \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u043A\u0443\u044E \u0444\u043E\u0440\u043C\u0443 <em>(m\u0101nu\u1E63yam)</em>, [\u043E\u043D] \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u0435\u0442 <em>(abhyasya)</em> \u0419\u043E\u0433\u0443 <em>(yogam)</em> [\u0438] \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(pr\u0101pnoti)</em> \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(divyam)</em> \u041D\u0435\u043A\u0442\u0430\u0440\u0430 \u0431\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u0438\u044F <em>(am\u1E5Btam)</em> \u043F\u043E\u0441\u043B\u0435 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E <em>(yasm\u0101t)</em> \u043D\u0435 \u0432\u043E\u0437\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044F <em>(\u0101vartate na)</em> \u0441\u043D\u043E\u0432\u0430 <em>(punar)</em>.</p><p class="eng">After a very long time <em>(mahat\u0101 k\u0101lena)</em> [living in those heavenly worlds, the one who fell from Yoga,] having obtained <em>(pr\u0101pya)</em> again <em>(punar)</em> the human condition <em>(m\u0101nu\u1E63yam)</em>, practices <em>(abhyasya)</em> Yoga <em>(yogam)</em> [and] acquires <em>(pr\u0101pnoti)</em> the divine <em>(divyam)</em> Nectar of Immortality <em>(am\u1E5Btam)</em> from which <em>(yasm\u0101t)</em> he does not return <em>(\u0101vartate na)</em> any more <em>(punar)</em>.</p></div><div class="stanza"><a href="#s103" id="s103" class="num">103</a><p class="sans">\u0924\u0938\u094D\u092E\u093E\u0924\u094D\u0938\u0928\u094D\u092E\u093E\u0930\u094D\u0917\u0947\u093D\u0938\u094D\u092E\u093F\u0928\u094D\u0928\u093F\u0930\u0924\u094B \u092F\u0903 \u0915\u0936\u094D\u091A\u093F\u0926\u0947\u0924\u093F \u0938 \u0936\u093F\u0935\u0924\u094D\u0935\u092E\u094D \u0964<br> \u0907\u0924\u093F \u092E\u0924\u094D\u0935\u093E \u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0947 \u092F\u0925\u093E\u0924\u0925\u093E\u092A\u093F \u092A\u094D\u0930\u092F\u0924\u0928\u0940\u092F\u092E\u094D \u0965\u0967\u0966\u0969\u0965</p><p class="trans">Tasm\u0101tsanm\u0101rge\u2019sminnirato ya\u1E25 ka\u015Bcideti sa \u015Bivatvam \u0964<br> Iti matv\u0101 param\u0101rthe yath\u0101tath\u0101pi prayatan\u012Byam \u0965103\u0965</p><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(tasm\u0101t)</em>, \u043A\u0430\u0436\u0434\u044B\u0439 <em>(ya\u1E25 ka\u015Bcid)</em> \u0438\u0441\u0442\u0438\u043D\u043D\u043E \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u044B\u0439 <em>(nirata\u1E25)</em> \u044D\u0442\u043E\u043C\u0443 <em>(asmin)</em> \u0432\u0435\u0447\u043D\u043E\u043C\u0443 \u043F\u0443\u0442\u0438 <em>(sat-m\u0101rge)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0428\u0438\u0432\u043E\u0439 <em>(eti sa\u1E25 \u015Bivatvam)</em>. \u0417\u043D\u0430\u044F \u044D\u0442\u043E <em>(iti matv\u0101)</em>, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0435\u0434\u043F\u0440\u0438\u043D\u044F\u0442\u044C \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u044B\u0435 \u0443\u0441\u0438\u043B\u0438\u044F <em>(prayatan\u012Byam)</em> \u043B\u044E\u0431\u044B\u043C [\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u043C] \u0441\u043F\u043E\u0441\u043E\u0431\u043E\u043C <em>(yath\u0101-tath\u0101 api)</em> [\u0434\u043E\u0441\u0442\u0438\u0447\u044C] \u0412\u044B\u0441\u0448\u0435\u0439 \u0446\u0435\u043B\u0438 <em>(parama-arthe)</em>.</p><p class="eng">Therefore <em>(tasm\u0101t)</em>, anyone whosoever <em>(ya\u1E25 ka\u015Bcid)</em> that is completely devoted to <em>(nirata\u1E25)</em> this <em>(asmin)</em> very beautiful path <em>(sat-m\u0101rge)</em> becomes \u015Aiva <em>(eti sa\u1E25 \u015Bivatvam)</em>. Reflecting in this manner <em>(iti matv\u0101)</em>, a great effort is to be intensely made <em>(prayatan\u012Byam)</em> in whatever [possible] way <em>(yath\u0101-tath\u0101 api)</em> in order to attain the Highest Reality or Supreme Goal <em>(parama-arthe)</em>.</p></div><div class="stanza"><a href="#s104" id="s104" class="num">104</a><p class="sans">\u0907\u0926\u092E\u092D\u093F\u0928\u0935\u0917\u0941\u092A\u094D\u0924\u094B\u0926\u093F\u0924\u0938\u0919\u094D\u0915\u094D\u0937\u0947\u092A\u0902 \u0927\u094D\u092F\u093E\u092F\u0924\u0903 \u092A\u0930\u0902 \u092C\u094D\u0930\u0939\u094D\u092E \u0964<br> \u0905\u091A\u093F\u0930\u093E\u0926\u0947\u0935 \u0936\u093F\u0935\u0924\u094D\u0935\u0902 \u0928\u093F\u091C\u0939\u0943\u0926\u092F\u093E\u0935\u0947\u0936\u092E\u092D\u094D\u092F\u0947\u0924\u093F \u0965\u0967\u0966\u096A\u0965</p><p class="trans">Idamabhinavaguptoditasa\u1E45k\u1E63epa\u1E41 dhy\u0101yata\u1E25 para\u1E41 brahma \u0964<br> Acir\u0101deva \u015Bivatva\u1E41 nijah\u1E5Bday\u0101ve\u015Bamabhyeti \u0965104\u0965</p><p>\u0422\u043E\u0442, \u043A\u0442\u043E \u043C\u0435\u0434\u0438\u0442\u0438\u0440\u0443\u0435\u0442 <em>(dhy\u0101yata\u1E25)</em> \u043D\u0430 \u044D\u0442\u043E\u0433\u043E <em>(idam)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E <em>(param)</em> \u0411\u0440\u0430\u0445\u043C\u0443 <em>(brahma)</em> \u043A\u0440\u0430\u0442\u043A\u043E\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E <em>(sa\u1E45k\u1E63epam)</em> \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043E <em>(udita)</em> \u0410\u0431\u0445\u0438\u043D\u0430\u0432\u0430\u0433\u0443\u043F\u0442\u043E\u0439 <em>(abhinavagupta)</em>, \u0432\u0441\u043A\u043E\u0440\u0435 <em>(acir\u0101t eva)</em> \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F <em>(\u0101ve\u015Bam abhyeti)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0428\u0438\u0432\u044B <em>(\u015Bivatvam)</em> \u0432 \u0435\u0433\u043E <em>(nija)</em> \u0441\u0435\u0440\u0434\u0446\u0435 <em>(h\u1E5Bdaya)</em>.</p><p class="eng">In the case of the one who meditates <em>(dhy\u0101yata\u1E25)</em> on this <em>(idam)</em> Supreme <em>(param)</em> Brahma <em>(brahma)</em> in whom a brief explanation [about His nature] <em>(sa\u1E45k\u1E63epam)</em> has been proclaimed <em>(udita)</em> by Abhinavagupta <em>(abhinavagupta)</em> [in the form of venerable Param\u0101rthas\u0101ra], the State of \u015Aiva <em>(\u015Bivatvam)</em> soon <em>(acir\u0101t eva)</em> penetrates into <em>(\u0101ve\u015Bam abhyeti)</em> his <em>(nija)</em> heart <em>(h\u1E5Bdaya)</em>.</p></div><div class="stanza"><a href="#s105" id="s105" class="num">105</a><p class="sans">\u0906\u0930\u094D\u092F\u093E\u0936\u0924\u0947\u0928 \u0924\u0926\u093F\u0926\u0902 \u0938\u0919\u094D\u0915\u094D\u0937\u093F\u092A\u094D\u0924\u0902 \u0936\u093E\u0938\u094D\u0924\u094D\u0930\u0938\u093E\u0930\u092E\u0924\u093F\u0917\u0942\u0922\u092E\u094D \u0964<br> \u0905\u092D\u093F\u0928\u0935\u0917\u0941\u092A\u094D\u0924\u0947\u0928 \u092E\u092F\u093E \u0936\u093F\u0935\u091A\u0930\u0923\u0938\u094D\u092E\u0930\u0923\u0926\u0940\u092A\u094D\u0924\u0947\u0928 \u0965\u0967\u0966\u096B\u0965</p><p class="trans">\u0100ry\u0101\u015Batena tadida\u1E41 sa\u1E45k\u1E63ipta\u1E41 \u015B\u0101stras\u0101ramatig\u016B\u1E0Dham \u0964<br> Abhinavaguptena may\u0101 \u015Bivacara\u1E47asmara\u1E47ad\u012Bptena \u0965105\u0965</p><p>\u0418\u043C\u0435\u043D\u043D\u043E \u044D\u0442\u0430 <em>(tad idam)</em> \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0442\u0430\u0439\u043D\u0430\u044F <em>(ati-g\u016B\u1E0Dham)</em> \u0441\u0443\u0442\u044C <em>(s\u0101ram)</em> \u0432\u0441\u0435\u0445 \u043F\u0438\u0441\u0430\u043D\u0438\u0439 <em>(\u015B\u0101stra)</em> \u043A\u0440\u0430\u0442\u043A\u043E \u0438\u0437\u043B\u043E\u0436\u0435\u043D\u0430 <em>(sa\u1E45k\u1E63iptam)</em> \u0432 \u0441\u043E\u0442\u043D\u0435 <em>(\u015Batena)</em> [\u0441\u0442\u0440\u043E\u043A \u0432 \u0440\u0430\u0437\u043C\u0435\u0440\u0435] \u0430\u0440\u044C\u044F <em>(\u0101ry\u0101)</em> \u043C\u043D\u043E\u0439 <em>(may\u0101)</em>, \u0410\u0431\u0445\u0438\u043D\u0430\u0432\u0430\u0433\u0443\u043F\u0442\u043E\u0439 <em>(abhinavaguptena)</em>, \u043E\u0437\u0430\u0440\u0451\u043D\u043D\u044B\u043C <em>(d\u012Bptena)</em> \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435\u043C <em>(smara\u1E47a)</em> \u0441\u0442\u043E\u043F \u0428\u0438\u0432\u044B <em>(\u015Biva-cara\u1E47a)</em>.</p><p class="eng">This very <em>(tad idam)</em> extremely secret <em>(ati-g\u016B\u1E0Dham)</em> essence <em>(s\u0101ram)</em> of [all] the scriptures <em>(\u015B\u0101stra)</em> has been summed up <em>(sa\u1E45k\u1E63iptam)</em> in one hundred <em>(\u015Batena)</em> [verses in] \u0100ry\u0101 meter <em>(\u0101ry\u0101)</em> by me <em>(may\u0101)</em>, Abhinavagupta <em>(abhinavaguptena)</em>, the one who shines <em>(d\u012Bptena)</em> by the remembrance <em>(smara\u1E47a)</em> of the \u015Aiva\u2019s feet <em>(\u015Biva-cara\u1E47a)</em>.</p></div><div class="stanza"><p class="sans">\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u092E\u0939\u093E\u092E\u093E\u0939\u0947\u0936\u094D\u0935\u0930\u093E\u091A\u093E\u0930\u094D\u092F\u093E\u092D\u093F\u0928\u0935\u0917\u0941\u092A\u094D\u0924\u0935\u093F\u0930\u091A\u093F\u0924\u0903 \u092A\u0930\u092E\u093E\u0930\u094D\u0925\u0938\u093E\u0930\u0903\u0965</p><p class="trans">Iti \u015Br\u012Bmah\u0101m\u0101he\u015Bvar\u0101c\u0101ry\u0101bhinavaguptaviracita\u1E25 param\u0101rthas\u0101ra\u1E25 \u0965</p><p>\u0422\u0430\u043A\u043E\u0432\u0430 <em>(iti)</em> \u0421\u0443\u0442\u044C \u0412\u044B\u0441\u0448\u0435\u0439 \u0418\u0441\u0442\u0438\u043D\u044B <em>(parama-artha-s\u0101ra\u1E25)</em>, \u0441\u043E\u0447\u0438\u043D\u0451\u043D\u043D\u0430\u044F <em>(viracita\u1E25)</em> \u0410\u0431\u0445\u0438\u043D\u0430\u0432\u0430\u0433\u0443\u043F\u0442\u043E\u0439 <em>(abhinavagupta)</em>, \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u044B\u043C <em>(\u015Br\u012B)</em> \u0443\u0447\u0438\u0442\u0435\u043B\u0435\u043C <em>(\u0101c\u0101rya)</em> [\u0438] \u0432\u0435\u043B\u0438\u043A\u0438\u043C \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u044B\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(mah\u0101-m\u0101h\u0101-\u012B\u015Bvara)</em>.</p><p class="eng">Here ends <em>(iti)</em> Param\u0101rthas\u0101ra \u2013The essence of the Highest Reality or Supreme Goal\u2013 <em>(parama-artha-s\u0101ra\u1E25)</em> composed <em>(viracita\u1E25)</em> byAbhinavagupta <em>(abhinavagupta)</em>, the venerable <em>(\u015Br\u012B)</em> Master <em>(\u0101c\u0101rya)</em> [and] Great Devotee of the Great Lord <em>(mah\u0101-m\u0101h\u0101-\u012B\u015Bvara)</em>.</p></div>',96),n=[i];function r(h,p,o,d,v,l){return m(),a("div",null,n)}var y=e(s,[["render",r]]);export{u as __pageData,y as default};
